UPDATE words SET example_en_2 = 'The summary should be no longer than one paragraph.', example_ko_2 = '요약은 한 문단을 넘지 않아야 해요.', example_en_3 = 'I wrote a summary of the news article.', example_ko_3 = '뉴스 기사의 요약을 작성했어요.', example_en_4 = 'Please read the summary before the class discussion.', example_ko_4 = '수업 토론 전에 요약을 읽어 주세요.', example_en_5 = 'Her summary captured all the important points.', example_ko_5 = '그녀의 요약은 모든 중요한 요점을 담았어요.' WHERE id = 'w_academic_A2_34';

UPDATE words SET example_en_2 = 'The main point of the article is easy to find.', example_ko_2 = '기사의 주요 요점은 찾기 쉬워요.', example_en_3 = 'Can you make your point more clearly?', example_ko_3 = '요점을 더 명확하게 말씀해 주실 수 있나요?', example_en_4 = 'She made three strong points in her essay.', example_ko_4 = '그녀는 에세이에서 세 가지 강력한 요점을 제시했어요.', example_en_5 = 'I missed the point of the question entirely.', example_ko_5 = '질문의 요점을 완전히 놓쳤어요.' WHERE id = 'w_academic_A2_35';

