UPDATE words SET example_en_2 = 'The paper articulates its ontology as social constructivist.', example_ko_2 = '논문은 자신의 존재론을 사회 구성주의적으로 표현해요.', example_en_3 = 'Researchers must make their ontology explicit.', example_ko_3 = '연구자들은 자신의 존재론을 명시적으로 밝혀야 해요.', example_en_4 = 'Her ontology assumes that reality is constructed through language.', example_ko_4 = '그녀의 존재론은 현실이 언어를 통해 구성된다고 가정해요.', example_en_5 = 'A realist ontology underpins most positivist research.', example_ko_5 = '실재론적 존재론이 대부분의 실증주의 연구의 기반이 돼요.' WHERE id = 'w_academic_C1_01';

UPDATE words SET example_en_2 = 'Axiology concerns what values guide the research process.', example_ko_2 = '가치론은 연구 과정을 안내하는 가치가 무엇인지와 관련해요.', example_en_3 = 'Her axiology reflected a commitment to social justice.', example_ko_3 = '그녀의 가치론은 사회 정의에 대한 헌신을 반영했어요.', example_en_4 = 'Axiology influences which research questions are considered worthwhile.', example_ko_4 = '가치론은 어떤 연구 질문이 가치 있다고 여겨지는지에 영향을 미쳐요.', example_en_5 = 'Without clarifying your axiology, your ethical stance remains implicit.', example_ko_5 = '가치론을 명확히 하지 않으면 윤리적 입장이 암묵적으로 남아요.' WHERE id = 'w_academic_C1_02';

UPDATE words SET example_en_2 = 'A deductive argument moves from the general to the specific.', example_ko_2 = '연역적 논증은 일반에서 특수로 이동해요.', example_en_3 = 'The researcher used a deductive approach to test the theory.', example_ko_3 = '연구자는 이론을 검증하기 위해 연역적 접근법을 사용했어요.', example_en_4 = 'Deductive reasoning is central to positivist research design.', example_ko_4 = '연역적 추론은 실증주의 연구 설계의 핵심이에요.', example_en_5 = 'She criticized the deductive framework for ignoring emergent findings.', example_ko_5 = '그녀는 출현하는 연구 결과를 무시하는 연역적 틀을 비판했어요.' WHERE id = 'w_academic_C1_03';

UPDATE words SET example_en_2 = 'Inductive reasoning draws broad conclusions from specific cases.', example_ko_2 = '귀납적 추론은 특정 사례에서 광범위한 결론을 이끌어내요.', example_en_3 = 'The grounded theory approach is inherently inductive.', example_ko_3 = '근거 이론 접근법은 본질적으로 귀납적이에요.', example_en_4 = 'She chose an inductive design because the field is underexplored.', example_ko_4 = '그녀는 분야가 충분히 탐구되지 않았기 때문에 귀납적 설계를 선택했어요.', example_en_5 = 'Inductive logic is fundamental to qualitative inquiry.', example_ko_5 = '귀납적 논리는 질적 탐구에 근본적이에요.' WHERE id = 'w_academic_C1_04';

UPDATE words SET example_en_2 = 'Abductive reasoning is often used in qualitative case studies.', example_ko_2 = '귀추적 추론은 질적 사례 연구에서 자주 사용돼요.', example_en_3 = 'He used abductive logic to identify the most plausible explanation.', example_ko_3 = '그는 가장 설득력 있는 설명을 파악하기 위해 귀추적 논리를 사용했어요.', example_en_4 = 'Abductive thinking moves between data and theory iteratively.', example_ko_4 = '귀추적 사고는 데이터와 이론 사이를 반복적으로 이동해요.', example_en_5 = 'Peirce argued that abductive reasoning is the source of all new ideas.', example_ko_5 = '퍼스는 귀추적 추론이 모든 새로운 아이디어의 원천이라고 주장했어요.' WHERE id = 'w_academic_C1_05';

UPDATE words SET example_en_2 = 'Hermeneutics guides how researchers interpret interview transcripts.', example_ko_2 = '해석학은 연구자들이 인터뷰 대본을 해석하는 방법을 안내해요.', example_en_3 = 'Gadamer''s hermeneutics emphasizes the fusion of horizons.', example_ko_3 = '가다머의 해석학은 지평의 융합을 강조해요.', example_en_4 = 'She applied hermeneutics to analyze historical policy documents.', example_ko_4 = '그녀는 역사적 정책 문서를 분석하기 위해 해석학을 적용했어요.', example_en_5 = 'Hermeneutics assumes that meaning is always context-dependent.', example_ko_5 = '해석학은 의미가 항상 맥락에 의존한다고 가정해요.' WHERE id = 'w_academic_C1_06';

UPDATE words SET example_en_2 = 'She used phenomenology to explore students'' lived experience of anxiety.', example_ko_2 = '그녀는 학생들의 불안에 대한 살아있는 경험을 탐구하기 위해 현상학을 사용했어요.', example_en_3 = 'Husserl founded the philosophical tradition of phenomenology.', example_ko_3 = '후설은 현상학의 철학적 전통을 창시했어요.', example_en_4 = 'Phenomenology requires the researcher to "bracket" prior assumptions.', example_ko_4 = '현상학은 연구자가 이전 가정들을 "괄호 치기"하도록 요구해요.', example_en_5 = 'The study took a phenomenological approach to understand grief.', example_ko_5 = '연구는 슬픔을 이해하기 위해 현상학적 접근법을 취했어요.' WHERE id = 'w_academic_C1_07';

UPDATE words SET example_en_2 = 'Positivism argues that only empirically verifiable claims are meaningful.', example_ko_2 = '실증주의는 경험적으로 검증 가능한 주장만이 의미 있다고 주장해요.', example_en_3 = 'She critiqued positivism for ignoring subjective experience.', example_ko_3 = '그녀는 주관적 경험을 무시한다는 이유로 실증주의를 비판했어요.', example_en_4 = 'Logical positivism was influential in the early twentieth century.', example_ko_4 = '논리 실증주의는 20세기 초에 영향력이 있었어요.', example_en_5 = 'He adopted a positivist stance to ensure objectivity in measurement.', example_ko_5 = '그는 측정의 객관성을 확보하기 위해 실증주의적 입장을 채택했어요.' WHERE id = 'w_academic_C1_08';

UPDATE words SET example_en_2 = 'Constructivism holds that learners build their own understanding.', example_ko_2 = '구성주의는 학습자들이 자신의 이해를 구축한다고 봐요.', example_en_3 = 'Social constructivism emphasizes the role of culture in learning.', example_ko_3 = '사회 구성주의는 학습에서 문화의 역할을 강조해요.', example_en_4 = 'She designed her curriculum based on constructivist principles.', example_ko_4 = '그녀는 구성주의 원칙을 바탕으로 교육과정을 설계했어요.', example_en_5 = 'Constructivism challenges the idea that knowledge is transmitted passively.', example_ko_5 = '구성주의는 지식이 수동적으로 전달된다는 생각에 도전해요.' WHERE id = 'w_academic_C1_09';

UPDATE words SET example_en_2 = 'Pragmatism in research selects methods based on what is most useful.', example_ko_2 = '연구에서 실용주의는 가장 유용한 방법을 기준으로 선택해요.', example_en_3 = 'William James developed pragmatism as a philosophical doctrine.', example_ko_3 = '윌리엄 제임스는 실용주의를 철학적 교의로 발전시켰어요.', example_en_4 = 'She adopted a pragmatic worldview to justify her mixed-methods design.', example_ko_4 = '그녀는 혼합 방법론을 정당화하기 위해 실용주의적 세계관을 채택했어요.', example_en_5 = 'Pragmatism focuses on what works in practice, not abstract ideals.', example_ko_5 = '실용주의는 추상적 이상이 아닌 실제로 효과 있는 것에 초점을 맞춰요.' WHERE id = 'w_academic_C1_10';

UPDATE words SET example_en_2 = 'The Hegelian dialectic proceeds through thesis, antithesis, and synthesis.', example_ko_2 = '헤겔의 변증법은 정·반·합을 통해 진행돼요.', example_en_3 = 'Dialectic thinking challenges us to consider opposing viewpoints.', example_ko_3 = '변증법적 사고는 상반되는 관점을 고려하도록 도전해요.', example_en_4 = 'She used dialectic reasoning to resolve the apparent contradiction.', example_ko_4 = '그녀는 명백한 모순을 해결하기 위해 변증법적 추론을 사용했어요.', example_en_5 = 'The dialectic between structure and agency runs through the entire study.', example_ko_5 = '구조와 행위성 사이의 변증법이 연구 전체를 관통해요.' WHERE id = 'w_academic_C1_11';

UPDATE words SET example_en_2 = 'Reflexivity requires constant critical self-examination.', example_ko_2 = '성찰성은 지속적인 비판적 자기 검토를 요구해요.', example_en_3 = 'She demonstrated reflexivity by keeping a research journal.', example_ko_3 = '그녀는 연구 일지를 작성하여 성찰성을 보여줬어요.', example_en_4 = 'Lack of reflexivity can lead to unexamined bias in qualitative work.', example_ko_4 = '성찰성의 부재는 질적 연구에서 검토되지 않은 편향으로 이어질 수 있어요.', example_en_5 = 'He discussed his reflexivity in the positionality statement.', example_ko_5 = '그는 위치성 진술에서 성찰성을 논의했어요.' WHERE id = 'w_academic_C1_12';

UPDATE words SET example_en_2 = 'Cultural hegemony shapes what counts as "normal" in society.', example_ko_2 = '문화적 헤게모니는 사회에서 무엇이 "정상"으로 여겨지는지를 형성해요.', example_en_3 = 'Gramsci developed the theory of hegemony to explain ideological control.', example_ko_3 = '그람시는 이데올로기적 통제를 설명하기 위해 헤게모니 이론을 발전시켰어요.', example_en_4 = 'The paper examines how media reinforces dominant hegemony.', example_ko_4 = '논문은 미디어가 어떻게 지배적 헤게모니를 강화하는지 살펴봐요.', example_en_5 = 'Hegemony is maintained through consent, not just coercion.', example_ko_5 = '헤게모니는 강압만이 아닌 동의를 통해 유지돼요.' WHERE id = 'w_academic_C1_13';

UPDATE words SET example_en_2 = 'Discourse analysis examines how language creates meaning and power.', example_ko_2 = '담론 분석은 언어가 어떻게 의미와 권력을 만드는지 살펴봐요.', example_en_3 = 'She applied discourse analysis to political campaign speeches.', example_ko_3 = '그녀는 정치 캠페인 연설에 담론 분석을 적용했어요.', example_en_4 = 'Critical discourse analysis reveals hidden ideological assumptions.', example_ko_4 = '비판적 담론 분석은 숨겨진 이데올로기적 가정을 드러내요.', example_en_5 = 'The study used discourse analysis to investigate textbook language.', example_ko_5 = '연구는 교과서 언어를 조사하기 위해 담론 분석을 사용했어요.' WHERE id = 'w_academic_C1_14';

UPDATE words SET example_en_2 = 'The meta-analysis pooled data from 30 randomized controlled trials.', example_ko_2 = '메타 분석은 30개의 무작위 대조 시험 데이터를 통합했어요.', example_en_3 = 'A meta-analysis provides more statistical power than a single study.', example_ko_3 = '메타 분석은 단일 연구보다 더 많은 통계적 검증력을 제공해요.', example_en_4 = 'She identified publication bias as a threat to the meta-analysis.', example_ko_4 = '그녀는 출판 편향을 메타 분석의 위협으로 파악했어요.', example_en_5 = 'The meta-analysis confirmed what individual studies had suggested.', example_ko_5 = '메타 분석은 개별 연구들이 시사한 것을 확인했어요.' WHERE id = 'w_academic_C1_15';

UPDATE words SET example_en_2 = 'Grounded theory is well-suited to exploratory research.', example_ko_2 = '근거 이론은 탐색적 연구에 잘 맞아요.', example_en_3 = 'She collected data and allowed categories to emerge through grounded theory.', example_ko_3 = '그녀는 데이터를 수집하고 근거 이론을 통해 범주가 출현하도록 했어요.', example_en_4 = 'In grounded theory, data collection and analysis occur simultaneously.', example_ko_4 = '근거 이론에서 데이터 수집과 분석은 동시에 이루어져요.', example_en_5 = 'Glaser and Strauss first articulated grounded theory in 1967.', example_ko_5 = '글레이저와 스트라우스는 1967년에 처음으로 근거 이론을 표현했어요.' WHERE id = 'w_academic_C1_16';

UPDATE words SET example_en_2 = 'She spent six months conducting ethnography in a rural community.', example_ko_2 = '그녀는 시골 공동체에서 민족지학을 수행하며 6개월을 보냈어요.', example_en_3 = 'Ethnography relies on participant observation and field notes.', example_ko_3 = '민족지학은 참여 관찰과 현장 노트에 의존해요.', example_en_4 = 'Virtual ethnography adapts traditional methods to online communities.', example_ko_4 = '가상 민족지학은 전통적 방법을 온라인 커뮤니티에 맞게 적용해요.', example_en_5 = 'The ethnography provided thick description of classroom practices.', example_ko_5 = '민족지학은 교실 실천에 대한 두꺼운 기술을 제공했어요.' WHERE id = 'w_academic_C1_17';

UPDATE words SET example_en_2 = 'Critical realism distinguishes between the real, actual, and empirical domains.', example_ko_2 = '비판적 실재론은 실재적·현실적·경험적 영역을 구분해요.', example_en_3 = 'She chose critical realism to bridge qualitative and quantitative approaches.', example_ko_3 = '그녀는 질적·양적 접근법을 잇기 위해 비판적 실재론을 선택했어요.', example_en_4 = 'Critical realism acknowledges that reality exists independently of our knowledge.', example_ko_4 = '비판적 실재론은 현실이 우리의 지식과 독립적으로 존재한다고 인정해요.', example_en_5 = 'Roy Bhaskar developed critical realism in the 1970s.', example_ko_5 = '로이 바스카르는 1970년대에 비판적 실재론을 발전시켰어요.' WHERE id = 'w_academic_C1_18';

UPDATE words SET example_en_2 = 'She examined how students exercise agency within institutional constraints.', example_ko_2 = '그녀는 학생들이 제도적 제약 안에서 어떻게 행위성을 발휘하는지 살펴봤어요.', example_en_3 = 'Human agency is often constrained by structural forces.', example_ko_3 = '인간의 행위성은 종종 구조적 힘에 의해 제한돼요.', example_en_4 = 'The paper explores the relationship between agency and identity.', example_ko_4 = '논문은 행위성과 정체성 사이의 관계를 탐구해요.', example_en_5 = 'Students who believe in their own agency tend to persevere longer.', example_ko_5 = '자신의 행위성을 믿는 학생들이 더 오래 끈기를 발휘하는 경향이 있어요.' WHERE id = 'w_academic_C1_19';

UPDATE words SET example_en_2 = 'Social structures shape individual behavior and opportunity.', example_ko_2 = '사회 구조는 개인의 행동과 기회를 형성해요.', example_en_3 = 'The structure of the essay should reflect your argument''s logic.', example_ko_3 = '에세이의 구조는 논증의 논리를 반영해야 해요.', example_en_4 = 'She analyzed the power structure within the educational institution.', example_ko_4 = '그녀는 교육 기관 내의 권력 구조를 분석했어요.', example_en_5 = 'Deep structures often remain invisible to those within the system.', example_ko_5 = '깊은 구조는 종종 시스템 내에 있는 사람들에게 보이지 않아요.' WHERE id = 'w_academic_C1_20';

UPDATE words SET example_en_2 = 'Language is inherently intersubjective — it requires shared understanding.', example_ko_2 = '언어는 본질적으로 상호주관적이에요. 공유된 이해를 필요로 해요.', example_en_3 = 'Knowledge in the social sciences is often intersubjective rather than objective.', example_ko_3 = '사회과학에서 지식은 종종 객관적이라기보다 상호주관적이에요.', example_en_4 = 'Intersubjective agreement among researchers strengthens qualitative findings.', example_ko_4 = '연구자들 사이의 상호주관적 합의는 질적 연구 결과를 강화해요.', example_en_5 = 'Intersubjective meaning-making is a central concept in phenomenology.', example_ko_5 = '상호주관적 의미 만들기는 현상학의 핵심 개념이에요.' WHERE id = 'w_academic_C1_21';

UPDATE words SET example_en_2 = 'Normative claims describe how things should be, not how they are.', example_ko_2 = '규범적 주장은 사물이 어떠해야 하는지를 설명해요. 어떠한지가 아니라요.', example_en_3 = 'The policy recommendation is normative in nature.', example_ko_3 = '정책 권고는 본질적으로 규범적이에요.', example_en_4 = 'She distinguished between normative and descriptive statements.', example_ko_4 = '그녀는 규범적 진술과 서술적 진술을 구분했어요.', example_en_5 = 'A normative framework identifies what counts as ethical behavior.', example_ko_5 = '규범적 틀은 무엇이 윤리적 행동으로 여겨지는지를 파악해요.' WHERE id = 'w_academic_C1_22';

UPDATE words SET example_en_2 = 'Aristotle''s teleology sees nature as directed toward an end.', example_ko_2 = '아리스토텔레스의 목적론은 자연이 목적을 향해 방향 지어져 있다고 봐요.', example_en_3 = 'Teleological explanations focus on purpose rather than cause.', example_ko_3 = '목적론적 설명은 원인보다 목적에 초점을 맞춰요.', example_en_4 = 'She critiqued teleology for imposing direction on historical events.', example_ko_4 = '그녀는 역사적 사건에 방향을 부여하는 이유로 목적론을 비판했어요.', example_en_5 = 'Teleological thinking is common in design and ethics.', example_ko_5 = '목적론적 사고는 디자인과 윤리에서 흔해요.' WHERE id = 'w_academic_C1_23';

UPDATE words SET example_en_2 = 'The study deconstructs the binary between theory and practice.', example_ko_2 = '연구는 이론과 실천 사이의 이분법을 해체해요.', example_en_3 = 'Thinking in binaries oversimplifies complex social realities.', example_ko_3 = '이분법적으로 생각하는 것은 복잡한 사회적 현실을 지나치게 단순화해요.', example_en_4 = 'The gender binary is increasingly questioned in contemporary research.', example_ko_4 = '젠더 이분법은 현대 연구에서 점점 더 의문시되고 있어요.', example_en_5 = 'She argued that binary categories fail to capture lived experience.', example_ko_5 = '그녀는 이분법적 범주가 살아있는 경험을 포착하지 못한다고 주장했어요.' WHERE id = 'w_academic_C1_24';

UPDATE words SET example_en_2 = 'Ideology operates most effectively when it is invisible.', example_ko_2 = '이데올로기는 보이지 않을 때 가장 효과적으로 작동해요.', example_en_3 = 'The dominant ideology shaped the textbook''s representation of history.', example_ko_3 = '지배적 이데올로기가 역사에 대한 교과서의 서술을 형성했어요.', example_en_4 = 'She analyzed how neoliberal ideology influences education policy.', example_ko_4 = '그녀는 신자유주의 이데올로기가 어떻게 교육 정책에 영향을 미치는지 분석했어요.', example_en_5 = 'Althusser argued that schools function as ideological state apparatuses.', example_ko_5 = '알튀세르는 학교가 이데올로기적 국가 기구로 기능한다고 주장했어요.' WHERE id = 'w_academic_C1_25';

UPDATE words SET example_en_2 = 'High levels of abstraction can make an argument harder to follow.', example_ko_2 = '높은 수준의 추상화는 논증을 따라가기 더 어렵게 만들 수 있어요.', example_en_3 = 'She moved from concrete observations to higher levels of abstraction.', example_ko_3 = '그녀는 구체적 관찰에서 더 높은 수준의 추상화로 이동했어요.', example_en_4 = 'The theory operates at a level of abstraction removed from everyday life.', example_ko_4 = '이론은 일상생활에서 분리된 추상화 수준에서 작동해요.', example_en_5 = 'Abstraction is necessary but must be grounded in evidence.', example_ko_5 = '추상화는 필요하지만 증거에 기반해야 해요.' WHERE id = 'w_academic_C1_26';

UPDATE words SET example_en_2 = 'She could articulate her theoretical position in plain language.', example_ko_2 = '그녀는 이론적 입장을 평이한 언어로 명확히 표현할 수 있었어요.', example_en_3 = 'The report articulates a clear vision for education reform.', example_ko_3 = '보고서는 교육 개혁에 대한 명확한 비전을 표현해요.', example_en_4 = 'He struggled to articulate the relationship between the two variables.', example_ko_4 = '그는 두 변수 사이의 관계를 명확히 표현하는 데 어려움을 겪었어요.', example_en_5 = 'Good academic writing articulates complex ideas with precision.', example_ko_5 = '좋은 학술 글쓰기는 복잡한 아이디어를 정확하게 표현해요.' WHERE id = 'w_academic_C1_27';

UPDATE words SET example_en_2 = 'The nuances of the data were lost in the simplified summary.', example_ko_2 = '단순화된 요약에서 데이터의 뉘앙스가 사라졌어요.', example_en_3 = 'She appreciated the nuance in the professor''s feedback.', example_ko_3 = '그녀는 교수님 피드백의 뉘앙스를 감사히 여겼어요.', example_en_4 = 'A good interpreter preserves the nuances of the original text.', example_ko_4 = '좋은 해석자는 원본 텍스트의 뉘앙스를 보존해요.', example_en_5 = 'His analysis captured nuances that a surface reading would miss.', example_ko_5 = '그의 분석은 표면적 읽기로는 놓칠 뉘앙스를 포착했어요.' WHERE id = 'w_academic_C1_28';

UPDATE words SET example_en_2 = 'The success of the intervention is contingent on funding.', example_ko_2 = '개입의 성공은 자금 조달에 달려 있어요.', example_en_3 = 'Her findings are contingent on the specific context studied.', example_ko_3 = '그녀의 연구 결과는 연구된 특정 맥락에 따라 달라져요.', example_en_4 = 'Social outcomes are contingent rather than fixed.', example_ko_4 = '사회적 결과는 고정된 것이 아닌 우연적이에요.', example_en_5 = 'He argued that identity is contingent and constantly shifting.', example_ko_5 = '그는 정체성이 우연적이고 끊임없이 변한다고 주장했어요.' WHERE id = 'w_academic_C1_29';

UPDATE words SET example_en_2 = 'The paper problematizes the taken-for-granted role of testing.', example_ko_2 = '논문은 당연시되는 시험의 역할을 문제화해요.', example_en_3 = 'She problematizes the assumption that reading is a neutral skill.', example_ko_3 = '그녀는 독서가 중립적인 기술이라는 가정을 문제화해요.', example_en_4 = 'To problematize is not to reject, but to question deeply.', example_ko_4 = '문제화하는 것은 거부하는 것이 아니라 깊이 의문을 제기하는 거예요.', example_en_5 = 'Critical pedagogy asks us to problematize everyday classroom practices.', example_ko_5 = '비판적 교육학은 일상적인 교실 실천을 문제화하도록 요청해요.' WHERE id = 'w_academic_C1_30';

UPDATE words SET example_en_2 = 'She contextualized the findings within the broader social debate.', example_ko_2 = '그녀는 더 넓은 사회적 논쟁 안에서 연구 결과를 맥락화했어요.', example_en_3 = 'It is important to contextualize data before drawing conclusions.', example_ko_3 = '결론을 내리기 전에 데이터를 맥락화하는 것이 중요해요.', example_en_4 = 'The teacher encouraged students to contextualize vocabulary in sentences.', example_ko_4 = '선생님은 학생들이 문장 안에서 어휘를 맥락화하도록 격려했어요.', example_en_5 = 'He contextualized the poem within its historical moment.', example_ko_5 = '그는 역사적 순간 안에서 시를 맥락화했어요.' WHERE id = 'w_academic_C1_31';

UPDATE words SET example_en_2 = 'You must operationalize abstract concepts to make them measurable.', example_ko_2 = '추상적 개념을 측정 가능하게 만들기 위해 조작화해야 해요.', example_en_3 = 'She operationalized "academic engagement" as hours of study per week.', example_ko_3 = '그녀는 "학업 참여도"를 주당 공부 시간으로 조작화했어요.', example_en_4 = 'Operationalizing a concept requires choosing specific indicators.', example_ko_4 = '개념을 조작화하는 것은 특정 지표를 선택하는 것을 필요로 해요.', example_en_5 = 'The decision to operationalize well-being as life satisfaction was debated.', example_ko_5 = '웰빙을 삶의 만족도로 조작화하는 결정은 논쟁이 됐어요.' WHERE id = 'w_academic_C1_32';

UPDATE words SET example_en_2 = 'She used a heuristic framework to guide her initial analysis.', example_ko_2 = '그녀는 초기 분석을 안내하기 위해 발견적 틀을 사용했어요.', example_en_3 = 'Heuristic methods help researchers make sense of complex data.', example_ko_3 = '발견적 방법은 연구자들이 복잡한 데이터를 이해하도록 도와요.', example_en_4 = 'The model is intended as a heuristic device, not a definitive theory.', example_ko_4 = '모델은 확정적 이론이 아닌 발견적 도구로 의도됐어요.', example_en_5 = 'Heuristic reasoning speeds up decision-making but can introduce bias.', example_ko_5 = '발견적 추론은 의사결정을 빠르게 하지만 편향을 도입할 수 있어요.' WHERE id = 'w_academic_C1_33';

UPDATE words SET example_en_2 = 'The definition "a bachelor is an unmarried man" is not a tautology.', example_ko_2 = '"총각은 미혼 남성이다"라는 정의는 동어반복이 아니에요.', example_en_3 = 'Saying "it is what it is" is a common tautology.', example_ko_3 = '"어쩔 수 없는 건 어쩔 수 없어요"는 흔한 동어반복이에요.', example_en_4 = 'She pointed out the tautology in the author''s reasoning.', example_ko_4 = '그녀는 저자의 추론에서 동어반복을 지적했어요.', example_en_5 = 'A tautological argument fails to add new information.', example_ko_5 = '동어반복적 논증은 새로운 정보를 추가하지 못해요.' WHERE id = 'w_academic_C1_34';

UPDATE words SET example_en_2 = 'She juxtaposed traditional and progressive approaches to grammar teaching.', example_ko_2 = '그녀는 전통적 접근법과 진보적 접근법을 나란히 놓아 문법 교육을 비교했어요.', example_en_3 = 'Juxtaposing two texts reveals interesting differences.', example_ko_3 = '두 텍스트를 나란히 놓으면 흥미로운 차이점이 드러나요.', example_en_4 = 'He juxtaposed qualitative and quantitative results for comparison.', example_ko_4 = '그는 비교를 위해 질적·양적 결과를 나란히 놓았어요.', example_en_5 = 'Juxtaposing the two perspectives highlights contradictions in the field.', example_ko_5 = '두 관점을 나란히 놓으면 분야의 모순이 부각돼요.' WHERE id = 'w_academic_C1_35';

-- ============================================================
-- C2 — 35 words
-- ============================================================

UPDATE words SET example_en_2 = 'Derrida applied deconstruction to expose the limits of Western metaphysics.', example_ko_2 = '데리다는 서양 형이상학의 한계를 드러내기 위해 해체를 적용했어요.', example_en_3 = 'Deconstruction does not destroy a text but reveals its instabilities.', example_ko_3 = '해체는 텍스트를 파괴하는 것이 아니라 불안정성을 드러내요.', example_en_4 = 'She used deconstruction to analyze the assumptions in the policy document.', example_ko_4 = '그녀는 정책 문서의 가정을 분석하기 위해 해체를 사용했어요.', example_en_5 = 'Deconstruction challenges the idea that any text has a fixed meaning.', example_ko_5 = '해체는 어떤 텍스트도 고정된 의미를 가진다는 생각에 도전해요.' WHERE id = 'w_academic_C2_01';

UPDATE words SET example_en_2 = 'Logocentrism privileges rational, spoken discourse over other forms.', example_ko_2 = '로고스중심주의는 다른 형태보다 이성적이고 말해진 담론을 우선시해요.', example_en_3 = 'She critiqued the logocentric assumptions embedded in Western education.', example_ko_3 = '그녀는 서양 교육에 내재된 로고스중심주의적 가정을 비판했어요.', example_en_4 = 'Derrida''s critique of logocentrism challenged the primacy of speech.', example_ko_4 = '데리다의 로고스중심주의 비판은 말의 우월성에 도전했어요.', example_en_5 = 'Logocentrism assumes that meaning originates in the mind before it is written.', example_ko_5 = '로고스중심주의는 의미가 쓰여지기 전에 마음에서 비롯된다고 가정해요.' WHERE id = 'w_academic_C2_02';

UPDATE words SET example_en_2 = 'Différance reveals that signs only gain meaning through difference.', example_ko_2 = '차연은 기호가 차이를 통해서만 의미를 얻는다는 것을 드러내요.', example_en_3 = 'She applied the concept of différance to challenge fixed interpretations.', example_ko_3 = '그녀는 고정된 해석에 도전하기 위해 차연 개념을 적용했어요.', example_en_4 = 'Différance operates through both difference and deferral simultaneously.', example_ko_4 = '차연은 차이와 유예를 동시에 통해 작동해요.', example_en_5 = 'Understanding différance is essential for reading Derrida''s philosophy.', example_ko_5 = '차연을 이해하는 것은 데리다의 철학을 읽기 위해 필수적이에요.' WHERE id = 'w_academic_C2_03';

UPDATE words SET example_en_2 = 'Freire emphasized praxis as the union of reflection and action.', example_ko_2 = '프레이리는 프락시스를 성찰과 행동의 결합으로 강조했어요.', example_en_3 = 'Critical pedagogy calls for praxis that transforms oppressive conditions.', example_ko_3 = '비판적 교육학은 억압적 조건을 변혁하는 프락시스를 요구해요.', example_en_4 = 'She argued that research without praxis is merely academic.', example_ko_4 = '그녀는 프락시스 없는 연구는 단순히 학문적일 뿐이라고 주장했어요.', example_en_5 = 'Praxis bridges the gap between theoretical knowledge and lived reality.', example_ko_5 = '프락시스는 이론적 지식과 살아있는 현실 사이의 간격을 잇는 다리가 돼요.' WHERE id = 'w_academic_C2_04';

UPDATE words SET example_en_2 = 'Intersubjectivity makes shared scientific knowledge possible.', example_ko_2 = '상호주관성은 공유된 과학적 지식을 가능하게 해요.', example_en_3 = 'Habermas grounded his theory of communicative action in intersubjectivity.', example_ko_3 = '하버마스는 의사소통적 행위 이론을 상호주관성에 기반했어요.', example_en_4 = 'She examined how intersubjectivity is negotiated in classroom dialogue.', example_ko_4 = '그녀는 상호주관성이 교실 대화에서 어떻게 협상되는지 살펴봤어요.', example_en_5 = 'Without intersubjectivity, social coordination would be impossible.', example_ko_5 = '상호주관성 없이는 사회적 조율이 불가능할 거예요.' WHERE id = 'w_academic_C2_05';

UPDATE words SET example_en_2 = 'Deleuze and Guattari used the rhizome to challenge tree-like models of thought.', example_ko_2 = '들뢰즈와 과타리는 나무 같은 사고 모델에 도전하기 위해 리좀을 사용했어요.', example_en_3 = 'The rhizome has no beginning or end — it is always in the middle.', example_ko_3 = '리좀에는 시작도 끝도 없어요. 항상 중간에 있어요.', example_en_4 = 'She described the internet as a rhizomatic knowledge structure.', example_ko_4 = '그녀는 인터넷을 리좀적 지식 구조로 설명했어요.', example_en_5 = 'The rhizome metaphor disrupts linear narratives of academic progress.', example_ko_5 = '리좀 은유는 학문적 진보의 선형적 서사를 혼란시켜요.' WHERE id = 'w_academic_C2_06';

UPDATE words SET example_en_2 = 'Lévi-Strauss introduced bricolage as a metaphor for mythical thinking.', example_ko_2 = '레비-스트로스는 신화적 사고의 은유로 브리콜라주를 도입했어요.', example_en_3 = 'She used bricolage to combine ethnography, narrative, and autobiography.', example_ko_3 = '그녀는 민족지학·서사·자서전을 결합하기 위해 브리콜라주를 사용했어요.', example_en_4 = 'Bricolage in qualitative research embraces methodological flexibility.', example_ko_4 = '질적 연구에서의 브리콜라주는 방법론적 유연성을 수용해요.', example_en_5 = 'He described his interdisciplinary approach as a form of academic bricolage.', example_ko_5 = '그는 자신의 학제적 접근법을 학술적 브리콜라주의 형태로 설명했어요.' WHERE id = 'w_academic_C2_07';

UPDATE words SET example_en_2 = 'Heteroglossia captures the way social voices compete within a single text.', example_ko_2 = '이언론은 사회적 목소리들이 단일 텍스트 안에서 경쟁하는 방식을 포착해요.', example_en_3 = 'She analyzed the heteroglossia in contemporary academic writing.', example_ko_3 = '그녀는 현대 학술 글쓰기의 이언론을 분석했어요.', example_en_4 = 'Bakhtin''s heteroglossia challenges the idea of a unified language.', example_ko_4 = '바흐친의 이언론은 통일된 언어의 개념에 도전해요.', example_en_5 = 'The novel''s heteroglossia made it impossible to identify a single authorial voice.', example_ko_5 = '소설의 이언론은 단일한 작가 목소리를 파악하는 것을 불가능하게 했어요.' WHERE id = 'w_academic_C2_08';

UPDATE words SET example_en_2 = 'The philosopher concluded his lecture with an unresolved aporia.', example_ko_2 = '철학자는 해결되지 않은 아포리아로 강의를 마무리했어요.', example_en_3 = 'Deconstruction often leads to aporia rather than clear conclusions.', example_ko_3 = '해체는 종종 명확한 결론보다 아포리아로 이어져요.', example_en_4 = 'She welcomed the aporia as a space for genuine inquiry.', example_ko_4 = '그녀는 아포리아를 진정한 탐구를 위한 공간으로 환영했어요.', example_en_5 = 'The aporia at the heart of the text resists any final interpretation.', example_ko_5 = '텍스트의 핵심에 있는 아포리아는 어떤 최종 해석에도 저항해요.' WHERE id = 'w_academic_C2_09';

UPDATE words SET example_en_2 = 'Foucault used the episteme to map ruptures between historical periods.', example_ko_2 = '푸코는 역사적 시기들 사이의 단절을 지도화하기 위해 에피스테메를 사용했어요.', example_en_3 = 'The modern episteme differs radically from its Renaissance predecessor.', example_ko_3 = '근대적 에피스테메는 르네상스 시대의 전임자와 근본적으로 달라요.', example_en_4 = 'She argued that digital culture is reshaping the contemporary episteme.', example_ko_4 = '그녀는 디지털 문화가 현대의 에피스테메를 재형성하고 있다고 주장했어요.', example_en_5 = 'The episteme is not a theory but a ground from which theories emerge.', example_ko_5 = '에피스테메는 이론이 아니라 이론이 출현하는 토대예요.' WHERE id = 'w_academic_C2_10';

UPDATE words SET example_en_2 = 'Biopower operates through statistics, norms, and medical institutions.', example_ko_2 = '생체권력은 통계·규범·의료 기관을 통해 작동해요.', example_en_3 = 'She analyzed biopower in the context of public health campaigns.', example_ko_3 = '그녀는 공공 보건 캠페인 맥락에서 생체권력을 분석했어요.', example_en_4 = 'Foucault showed how biopower turns the body into a site of control.', example_ko_4 = '푸코는 생체권력이 어떻게 몸을 통제의 장소로 만드는지 보여줬어요.', example_en_5 = 'Biopower is exercised through systems of surveillance and classification.', example_ko_5 = '생체권력은 감시와 분류 시스템을 통해 행사돼요.' WHERE id = 'w_academic_C2_11';

UPDATE words SET example_en_2 = 'In contemporary media, the simulacrum has replaced authentic experience.', example_ko_2 = '현대 미디어에서 시뮬라크르는 진정한 경험을 대체했어요.', example_en_3 = 'She analyzed the theme park as a simulacrum of historical reality.', example_ko_3 = '그녀는 테마파크를 역사적 현실의 시뮬라크르로 분석했어요.', example_en_4 = 'Baudrillard argued that the simulacrum precedes and produces reality.', example_ko_4 = '보드리야르는 시뮬라크르가 현실에 선행하고 현실을 만들어낸다고 주장했어요.', example_en_5 = 'A simulacrum is a copy for which no original exists.', example_ko_5 = '시뮬라크르는 원본이 존재하지 않는 복사본이에요.' WHERE id = 'w_academic_C2_12';

UPDATE words SET example_en_2 = 'Spivak asked whether the subaltern can represent itself within dominant discourse.', example_ko_2 = '스피박은 서발턴이 지배적 담론 안에서 자신을 표현할 수 있는지 물었어요.', example_en_3 = 'Postcolonial studies center the voices of the subaltern.', example_ko_3 = '포스트식민 연구는 서발턴의 목소리를 중심에 놓아요.', example_en_4 = 'The subaltern is not simply the oppressed but those denied a voice in history.', example_ko_4 = '서발턴은 단순히 억압받은 자가 아니라 역사에서 목소리를 박탈당한 사람들이에요.', example_en_5 = 'She examined how colonial archives silenced the subaltern perspective.', example_ko_5 = '그녀는 식민지 기록 보관소가 어떻게 서발턴의 관점을 침묵시켰는지 살펴봤어요.' WHERE id = 'w_academic_C2_13';

UPDATE words SET example_en_2 = 'Hybridity produces new cultural forms that belong to neither origin.', example_ko_2 = '혼종성은 어느 기원에도 속하지 않는 새로운 문화 형태를 만들어내요.', example_en_3 = 'She explored hybridity in second-generation immigrant identity.', example_ko_3 = '그녀는 2세대 이민자 정체성에서 혼종성을 탐구했어요.', example_en_4 = 'Bhabha''s concept of hybridity resists the idea of pure cultural identity.', example_ko_4 = '바바의 혼종성 개념은 순수한 문화적 정체성의 개념에 저항해요.', example_en_5 = 'The hybrid "third space" is where cultural negotiation occurs.', example_ko_5 = '혼종적 "제3의 공간"은 문화적 협상이 이루어지는 곳이에요.' WHERE id = 'w_academic_C2_14';

UPDATE words SET example_en_2 = 'Genealogy traces how present-day truths emerged from historical contingency.', example_ko_2 = '계보학은 현재의 진리가 역사적 우연성에서 어떻게 출현했는지 추적해요.', example_en_3 = 'She applied Foucauldian genealogy to the history of educational testing.', example_ko_3 = '그녀는 교육 평가의 역사에 푸코적 계보학을 적용했어요.', example_en_4 = 'Genealogy does not seek origins but traces the accidents of history.', example_ko_4 = '계보학은 기원을 찾는 것이 아니라 역사의 우연들을 추적해요.', example_en_5 = 'His genealogy of the curriculum revealed its ideological underpinnings.', example_ko_5 = '그의 교육과정 계보학은 이데올로기적 기반을 드러냈어요.' WHERE id = 'w_academic_C2_15';

UPDATE words SET example_en_2 = 'Alterity demands ethical openness to what is fundamentally different.', example_ko_2 = '타자성은 근본적으로 다른 것에 대한 윤리적 개방성을 요구해요.', example_en_3 = 'She used Levinas''s concept of alterity to critique assimilationist education.', example_ko_3 = '그녀는 레비나스의 타자성 개념을 동화주의 교육 비판에 사용했어요.', example_en_4 = 'Alterity challenges us to encounter the other without reducing them to sameness.', example_ko_4 = '타자성은 우리가 타자를 동질성으로 환원하지 않고 만나도록 도전해요.', example_en_5 = 'Intercultural education must grapple with the problem of alterity.', example_ko_5 = '상호문화 교육은 타자성의 문제와 씨름해야 해요.' WHERE id = 'w_academic_C2_16';

UPDATE words SET example_en_2 = 'Spinoza''s philosophy is one of radical immanence.', example_ko_2 = '스피노자의 철학은 급진적 내재성의 철학이에요.', example_en_3 = 'Immanence rejects the idea that meaning comes from outside experience.', example_ko_3 = '내재성은 의미가 경험 밖에서 온다는 생각을 거부해요.', example_en_4 = 'Deleuze''s philosophy of immanence locates creativity within the world itself.', example_ko_4 = '들뢰즈의 내재성 철학은 창의성을 세계 자체 안에 위치시켜요.', example_en_5 = 'The tension between immanence and transcendence runs throughout Western theology.', example_ko_5 = '내재성과 초월성 사이의 긴장이 서양 신학 전체를 관통해요.' WHERE id = 'w_academic_C2_17';

UPDATE words SET example_en_2 = 'Mystical traditions often speak of transcendence through contemplative practice.', example_ko_2 = '신비주의 전통은 종종 명상적 실천을 통한 초월성을 이야기해요.', example_en_3 = 'Kant argued that transcendence lies beyond the limits of human knowledge.', example_ko_3 = '칸트는 초월성이 인간 지식의 한계 너머에 있다고 주장했어요.', example_en_4 = 'She examined how art can provide an experience of transcendence.', example_ko_4 = '그녀는 예술이 어떻게 초월성의 경험을 제공할 수 있는지 살펴봤어요.', example_en_5 = 'The sacred is often defined in terms of transcendence and awe.', example_ko_5 = '신성한 것은 종종 초월성과 경외감의 관점에서 정의돼요.' WHERE id = 'w_academic_C2_18';

UPDATE words SET example_en_2 = 'Maturana and Varela developed autopoiesis as a theory of cognition.', example_ko_2 = '마투라나와 바렐라는 인지 이론으로서 자기생산을 발전시켰어요.', example_en_3 = 'Autopoiesis explains how living systems maintain themselves over time.', example_ko_3 = '자기생산은 생물학적 시스템이 시간이 지나도 어떻게 스스로를 유지하는지 설명해요.', example_en_4 = 'She applied the concept of autopoiesis to educational institutions.', example_ko_4 = '그녀는 교육 기관에 자기생산 개념을 적용했어요.', example_en_5 = 'In autopoietic systems, the organization is self-referential and self-regulating.', example_ko_5 = '자기생산 시스템에서 조직은 자기 지시적이고 자기 조절적이에요.' WHERE id = 'w_academic_C2_19';

UPDATE words SET example_en_2 = 'Onto-epistemology refuses to separate questions of being from questions of knowing.', example_ko_2 = '존재-인식론은 존재의 문제와 앎의 문제를 분리하기를 거부해요.', example_en_3 = 'Karen Barad developed onto-epistemology through her concept of agential realism.', example_ko_3 = '카렌 바라드는 행위적 실재론 개념을 통해 존재-인식론을 발전시켰어요.', example_en_4 = 'An onto-epistemological approach challenges the observer/observed distinction.', example_ko_4 = '존재-인식론적 접근법은 관찰자/관찰 대상의 구분에 도전해요.', example_en_5 = 'Her onto-epistemological framework shaped both research design and interpretation.', example_ko_5 = '그녀의 존재-인식론적 틀은 연구 설계와 해석 모두를 형성했어요.' WHERE id = 'w_academic_C2_20';

UPDATE words SET example_en_2 = 'Intertextuality shows that every text echoes earlier texts.', example_ko_2 = '상호텍스트성은 모든 텍스트가 이전 텍스트들을 반향한다는 것을 보여줘요.', example_en_3 = 'Kristeva coined the term intertextuality drawing on Bakhtin''s dialogism.', example_ko_3 = '크리스테바는 바흐친의 대화주의를 바탕으로 상호텍스트성이라는 용어를 만들었어요.', example_en_4 = 'She traced the intertextuality between two apparently unrelated novels.', example_ko_4 = '그녀는 겉보기에 관련 없어 보이는 두 소설 사이의 상호텍스트성을 추적했어요.', example_en_5 = 'Academic writing is inherently intertextual — it builds on prior scholarship.', example_ko_5 = '학술 글쓰기는 본질적으로 상호텍스트적이에요. 이전 학문을 기반으로 해요.' WHERE id = 'w_academic_C2_21';

UPDATE words SET example_en_2 = 'The novel''s polyphony means no single character''s truth dominates.', example_ko_2 = '소설의 다성성은 어떤 한 인물의 진리도 지배하지 않는다는 것을 의미해요.', example_en_3 = 'She valued the polyphony of voices in participatory action research.', example_ko_3 = '그녀는 참여 실행 연구에서 목소리들의 다성성을 소중히 여겼어요.', example_en_4 = 'Polyphony in academic discourse means acknowledging competing perspectives.', example_ko_4 = '학술 담론에서 다성성은 경쟁하는 관점들을 인정하는 것을 의미해요.', example_en_5 = 'Bakhtin contrasted the polyphonic novel with the monological epic.', example_ko_5 = '바흐친은 다성적 소설과 단성적 서사시를 대조했어요.' WHERE id = 'w_academic_C2_22';

UPDATE words SET example_en_2 = 'Deterritorialization can generate new possibilities but also anxiety.', example_ko_2 = '탈영토화는 새로운 가능성을 만들어낼 수 있지만 불안감도 유발해요.', example_en_3 = 'Globalization involves the deterritorialization of economic relations.', example_ko_3 = '세계화는 경제적 관계의 탈영토화를 수반해요.', example_en_4 = 'She used deterritorialization to describe the collapse of national curriculum boundaries.', example_ko_4 = '그녀는 국가 교육과정 경계의 붕괴를 설명하기 위해 탈영토화를 사용했어요.', example_en_5 = 'Deterritorialization is always followed by reterritorialization in Deleuzian thought.', example_ko_5 = '들뢰즈적 사고에서 탈영토화는 항상 재영토화가 뒤따라요.' WHERE id = 'w_academic_C2_23';

UPDATE words SET example_en_2 = 'Nomadology refuses stable identity in favor of becoming.', example_ko_2 = '유목론은 되어감을 위해 안정적 정체성을 거부해요.', example_en_3 = 'She applied nomadology to theorize transnational academic identities.', example_ko_3 = '그녀는 초국가적 학술 정체성을 이론화하기 위해 유목론을 적용했어요.', example_en_4 = 'Nomadology challenges hierarchical and territorial thinking.', example_ko_4 = '유목론은 위계적이고 영토적인 사고에 도전해요.', example_en_5 = 'In nomadology, the nomad creates new paths rather than following established ones.', example_ko_5 = '유목론에서 유목민은 기존 길을 따르는 것이 아니라 새로운 길을 만들어요.' WHERE id = 'w_academic_C2_24';

UPDATE words SET example_en_2 = 'Plato''s pharmakon recurs throughout Derrida''s analysis of writing.', example_ko_2 = '플라톤의 파르마콘은 글쓰기에 대한 데리다의 분석 전체에 걸쳐 반복돼요.', example_en_3 = 'Technology functions as a pharmakon — both enabling and disabling attention.', example_ko_3 = '기술은 파르마콘으로 기능해요. 주의를 가능하게도, 불가능하게도 해요.', example_en_4 = 'She described social media as a pharmakon for contemporary communication.', example_ko_4 = '그녀는 소셜 미디어를 현대 소통의 파르마콘으로 설명했어요.', example_en_5 = 'The pharmakon reveals the instability of any attempt to separate good from harm.', example_ko_5 = '파르마콘은 선과 해악을 분리하려는 어떤 시도의 불안정성을 드러내요.' WHERE id = 'w_academic_C2_25';

UPDATE words SET example_en_2 = 'Postmodernism is characterized by skepticism toward metanarratives.', example_ko_2 = '포스트모더니즘은 거대서사에 대한 회의주의로 특징지어져요.', example_en_3 = 'She questioned whether science itself is a metanarrative.', example_ko_3 = '그녀는 과학 자체가 거대서사인지 의문을 제기했어요.', example_en_4 = 'Lyotard argued that the metanarrative of progress has lost its credibility.', example_ko_4 = '리오타르는 진보의 거대서사가 신뢰성을 잃었다고 주장했어요.', example_en_5 = 'Religious fundamentalism can be seen as a return to metanarrative certainty.', example_ko_5 = '종교적 근본주의는 거대서사적 확실성으로의 회귀로 볼 수 있어요.' WHERE id = 'w_academic_C2_26';

UPDATE words SET example_en_2 = 'Semiosis connects a sign vehicle, a meaning, and an interpretant.', example_ko_2 = '기호작용은 기호 매개체·의미·해석체를 연결해요.', example_en_3 = 'She studied the semiosis of scientific diagrams in textbooks.', example_ko_3 = '그녀는 교과서에서 과학적 다이어그램의 기호작용을 연구했어요.', example_en_4 = 'Peirce''s triadic model describes semiosis as an ongoing process.', example_ko_4 = '퍼스의 삼항 모델은 기호작용을 지속적인 과정으로 설명해요.', example_en_5 = 'Cultural semiosis shapes how communities assign meaning to events.', example_ko_5 = '문화적 기호작용은 공동체가 사건에 의미를 부여하는 방식을 형성해요.' WHERE id = 'w_academic_C2_27';

UPDATE words SET example_en_2 = 'Dialectical materialism links historical change to material conditions.', example_ko_2 = '변증법적 유물론은 역사적 변화를 물질적 조건과 연결해요.', example_en_3 = 'She used dialectical materialism to analyze educational inequality.', example_ko_3 = '그녀는 교육적 불평등을 분석하기 위해 변증법적 유물론을 사용했어요.', example_en_4 = 'Engels systematized dialectical materialism after Marx''s death.', example_ko_4 = '엥겔스는 마르크스 사후에 변증법적 유물론을 체계화했어요.', example_en_5 = 'Dialectical materialism sees contradiction as the engine of historical progress.', example_ko_5 = '변증법적 유물론은 모순을 역사적 진보의 엔진으로 봐요.' WHERE id = 'w_academic_C2_28';

UPDATE words SET example_en_2 = 'Schools have been compared to the panopticon because they monitor behavior.', example_ko_2 = '학교는 행동을 감시하기 때문에 판옵티콘에 비교되어 왔어요.', example_en_3 = 'Foucault extended the panopticon metaphor to hospitals, clinics, and prisons.', example_ko_3 = '푸코는 판옵티콘 은유를 병원·클리닉·감옥으로 확장했어요.', example_en_4 = 'Digital surveillance creates a virtual panopticon that operates globally.', example_ko_4 = '디지털 감시는 전 세계적으로 작동하는 가상 판옵티콘을 만들어요.', example_en_5 = 'In the panopticon, the mere possibility of being watched is enough to control behavior.', example_ko_5 = '판옵티콘에서는 관찰될 가능성만으로도 행동을 통제하기에 충분해요.' WHERE id = 'w_academic_C2_29';

UPDATE words SET example_en_2 = 'Habitus is acquired through socialization and becomes second nature.', example_ko_2 = '아비투스는 사회화를 통해 획득되고 제2의 본성이 돼요.', example_en_3 = 'She argued that academic habitus advantages middle-class students.', example_ko_3 = '그녀는 학업적 아비투스가 중산층 학생에게 유리하다고 주장했어요.', example_en_4 = 'Habitus generates practices that reproduce the social field.', example_ko_4 = '아비투스는 사회적 장을 재생산하는 실천을 만들어내요.', example_en_5 = 'The habitus of a researcher influences how they conduct and present their work.', example_ko_5 = '연구자의 아비투스는 연구를 수행하고 발표하는 방식에 영향을 미쳐요.' WHERE id = 'w_academic_C2_30';

UPDATE words SET example_en_2 = 'Publications and citations are forms of symbolic capital in academia.', example_ko_2 = '출판물과 인용은 학계에서 상징 자본의 형태예요.', example_en_3 = 'She analyzed how symbolic capital is distributed unequally across institutions.', example_ko_3 = '그녀는 상징 자본이 기관들 사이에서 불평등하게 분배되는 방식을 분석했어요.', example_en_4 = 'Symbolic capital can be converted into economic capital under the right conditions.', example_ko_4 = '상징 자본은 올바른 조건 하에서 경제적 자본으로 전환될 수 있어요.', example_en_5 = 'He used his symbolic capital as a renowned professor to influence policy.', example_ko_5 = '그는 저명한 교수로서 자신의 상징 자본을 사용해 정책에 영향을 미쳤어요.' WHERE id = 'w_academic_C2_31';

UPDATE words SET example_en_2 = 'Doxa naturalizes the social order so that it appears inevitable.', example_ko_2 = '독사는 사회적 질서를 자연화하여 불가피한 것처럼 보이게 해요.', example_en_3 = 'She examined how doxa in higher education marginalizes non-traditional students.', example_ko_3 = '그녀는 고등 교육의 독사가 비전통적 학생들을 어떻게 소외시키는지 살펴봤어요.', example_en_4 = 'Doxa operates below the level of explicit belief or deliberate choice.', example_ko_4 = '독사는 명시적 믿음이나 의도적 선택의 수준 아래에서 작동해요.', example_en_5 = 'When doxa is challenged, it can become explicit orthodoxy or heterodoxy.', example_ko_5 = '독사가 도전받으면 명시적 정통성이나 이단이 될 수 있어요.' WHERE id = 'w_academic_C2_32';

UPDATE words SET example_en_2 = 'Adolescence is often described as a period of liminality.', example_ko_2 = '청소년기는 종종 경계성의 시기로 설명돼요.', example_en_3 = 'Van Gennep described liminality as the middle phase of a rite of passage.', example_ko_3 = '반 헤넵은 경계성을 통과의례의 중간 단계로 설명했어요.', example_en_4 = 'She applied the concept of liminality to explore immigrant identity formation.', example_ko_4 = '그녀는 이민자 정체성 형성을 탐구하기 위해 경계성 개념을 적용했어요.', example_en_5 = 'Academic transitions often involve profound experiences of liminality.', example_ko_5 = '학업적 전환은 종종 깊은 경계성의 경험을 수반해요.' WHERE id = 'w_academic_C2_33';

UPDATE words SET example_en_2 = 'Mystical theology often employs an apophatic approach to describe God.', example_ko_2 = '신비주의 신학은 종종 신을 묘사하기 위해 부정적 접근법을 사용해요.', example_en_3 = 'An apophatic strategy defines something by systematically excluding what it is not.', example_ko_3 = '부정적 전략은 무엇이 아닌지를 체계적으로 배제함으로써 무언가를 정의해요.', example_en_4 = 'She used an apophatic method to discuss what consciousness is not.', example_ko_4 = '그녀는 의식이 아닌 것을 논의하기 위해 부정적 방법을 사용했어요.', example_en_5 = 'The apophatic tradition acknowledges the limits of human language.', example_ko_5 = '부정 신학적 전통은 인간 언어의 한계를 인정해요.' WHERE id = 'w_academic_C2_34';

UPDATE words SET example_en_2 = 'The exegesis of canonical texts is central to theological study.', example_ko_2 = '정경 텍스트의 주석은 신학 연구의 핵심이에요.', example_en_3 = 'She offered a rigorous exegesis of Foucault''s Discipline and Punish.', example_ko_3 = '그녀는 푸코의 『규율과 처벌』에 대한 엄격한 주석을 제공했어요.', example_en_4 = 'Exegesis requires close reading and historical contextual knowledge.', example_ko_4 = '주석은 세밀한 읽기와 역사적 맥락 지식을 필요로 해요.', example_en_5 = 'The exegesis revealed layers of meaning not visible at the surface level.', example_ko_5 = '주석은 표면적으로는 보이지 않는 의미의 층위들을 드러냈어요.' WHERE id = 'w_academic_C2_35';

