UPDATE words SET example_en_2 = 'She plays music every morning.', example_ko_2 = '그녀는 매일 아침 음악을 틀어요.', example_en_3 = 'What kind of music do you like?', example_ko_3 = '어떤 종류의 음악을 좋아해요?', example_en_4 = 'Music makes me feel relaxed.', example_ko_4 = '음악을 들으면 마음이 편안해져요.', example_en_5 = 'We danced to the music at the party.', example_ko_5 = '파티에서 음악에 맞춰 춤을 췄어요.' WHERE id = 'w_culture_A1_01';

UPDATE words SET example_en_2 = 'He makes art from recycled materials.', example_ko_2 = '그는 재활용 재료로 예술 작품을 만들어요.', example_en_3 = 'Art is a great way to express feelings.', example_ko_3 = '예술은 감정을 표현하는 훌륭한 방법이에요.', example_en_4 = 'My daughter loves art class at school.', example_ko_4 = '제 딸은 학교에서 미술 수업을 정말 좋아해요.', example_en_5 = 'The art on the wall is very colourful.', example_ko_5 = '벽에 있는 그림이 매우 화려해요.' WHERE id = 'w_culture_A1_02';

UPDATE words SET example_en_2 = 'Which movie do you want to see?', example_ko_2 = '어떤 영화를 보고 싶어요?', example_en_3 = 'The movie was two hours long.', example_ko_3 = '영화는 두 시간 길이였어요.', example_en_4 = 'I fell asleep during the movie.', example_ko_4 = '영화 중에 잠이 들었어요.', example_en_5 = 'That movie is based on a true story.', example_ko_5 = '그 영화는 실화를 바탕으로 해요.' WHERE id = 'w_culture_A1_03';

