UPDATE words SET example_en_2 = 'The interval gave us time to discuss the first act.', example_ko_2 = '인터미션 덕분에 1막에 대해 이야기할 시간이 생겼어요.', example_en_3 = 'Many people buy programmes during the interval.', example_ko_3 = '많은 사람들이 인터미션 동안 프로그램을 구매해요.', example_en_4 = 'The interval between the two acts was fifteen minutes.', example_ko_4 = '두 막 사이의 인터미션은 15분이었어요.', example_en_5 = 'She stretched her legs during the interval.', example_ko_5 = '그녀는 인터미션 동안 다리를 펴고 쉬었어요.' WHERE id = 'w_culture_A2_34';

