UPDATE words SET example_en_2 = 'The country''s cultural heritage attracts millions of tourists each year.', example_ko_2 = '그 나라의 문화유산은 매년 수백만 명의 관광객을 끌어들여요.', example_en_3 = 'We have a responsibility to pass on our cultural heritage to future generations.', example_ko_3 = '우리는 문화유산을 미래 세대에 전달할 책임이 있어요.', example_en_4 = 'The old building was preserved as a heritage site.', example_ko_4 = '그 오래된 건물은 유산 지역으로 보존됐어요.', example_en_5 = 'UNESCO helps protect world heritage around the globe.', example_ko_5 = 'UNESCO는 전 세계의 세계 유산 보호를 돕고 있어요.' WHERE id = 'w_culture_B1_01';

UPDATE words SET example_en_2 = 'The museum features both classical and contemporary works.', example_ko_2 = '그 박물관은 고전 작품과 현대 작품을 모두 선보여요.', example_en_3 = 'She is fascinated by contemporary dance forms.', example_ko_3 = '그녀는 현대 무용 형식에 매혹되어 있어요.', example_en_4 = 'Contemporary artists often challenge social norms through their work.', example_ko_4 = '현대 예술가들은 종종 작품을 통해 사회적 규범에 도전해요.', example_en_5 = 'The gallery focuses exclusively on contemporary Korean art.', example_ko_5 = '그 갤러리는 현대 한국 미술만을 전문으로 다뤄요.' WHERE id = 'w_culture_B1_02';

