UPDATE words SET example_en_2 = 'Her avant-garde approach to filmmaking divides opinion.', example_ko_2 = '영화 제작에 대한 그녀의 전위적인 접근 방식은 의견을 분분하게 해요.', example_en_3 = 'The avant-garde movement reshaped the art world in the early twentieth century.', example_ko_3 = '전위 예술 운동은 20세기 초에 예술계를 재편했어요.', example_en_4 = 'Critics were unsure what to make of his avant-garde sculpture.', example_ko_4 = '비평가들은 그의 전위적인 조각을 어떻게 받아들여야 할지 몰랐어요.', example_en_5 = 'An avant-garde score accompanies the experimental dance piece.', example_ko_5 = '실험적인 댄스 작품에 전위적인 음악이 함께해요.' WHERE id = 'w_culture_B2_01';

UPDATE words SET example_en_2 = 'She was initially confused by the abstract forms in the sculpture.', example_ko_2 = '그녀는 처음에 조각의 추상적인 형태에 혼란스러워했어요.', example_en_3 = 'The film deals with abstract themes such as identity and memory.', example_ko_3 = '그 영화는 정체성과 기억 같은 추상적인 주제를 다뤄요.', example_en_4 = 'He made the concept more concrete by using an abstract metaphor.', example_ko_4 = '그는 추상적인 은유를 사용해 개념을 더 구체적으로 만들었어요.', example_en_5 = 'Abstract art invites viewers to project their own meaning onto the work.', example_ko_5 = '추상 미술은 관람객이 작품에 자신만의 의미를 투영하도록 유도해요.' WHERE id = 'w_culture_B2_02';

UPDATE words SET example_en_2 = 'The exhibition traced the history of surrealism from its origins.', example_ko_2 = '그 전시회는 초현실주의의 기원부터 역사를 추적했어요.', example_en_3 = 'Her photography is deeply influenced by surrealism.', example_ko_3 = '그녀의 사진 작업은 초현실주의의 깊은 영향을 받았어요.', example_en_4 = 'Surrealism blended the rational and the dreamlike in unprecedented ways.', example_ko_4 = '초현실주의는 이성적인 것과 몽환적인 것을 전례 없는 방식으로 혼합했어요.', example_en_5 = 'Many artists drew on surrealism without fully embracing the movement.', example_ko_5 = '많은 예술가들이 운동을 완전히 받아들이지 않고도 초현실주의를 활용했어요.' WHERE id = 'w_culture_B2_03';

UPDATE words SET example_en_2 = 'The building was constructed with patronage from a wealthy family.', example_ko_2 = '그 건물은 부유한 가족의 후원으로 건립됐어요.', example_en_3 = 'Without patronage, many Renaissance artists could not have survived.', example_ko_3 = '후원 없이는 많은 르네상스 예술가들이 살아남을 수 없었을 거예요.', example_en_4 = 'She criticised the model of arts patronage as exclusionary.', example_ko_4 = '그녀는 예술 후원 모델이 배타적이라고 비판했어요.', example_en_5 = 'Government patronage of the arts has declined in recent years.', example_ko_5 = '최근 몇 년 동안 정부의 예술 후원이 감소했어요.' WHERE id = 'w_culture_B2_04';

UPDATE words SET example_en_2 = 'The lecture covered the iconography of Byzantine religious art.', example_ko_2 = '강의는 비잔틴 종교 미술의 도상학을 다뤘어요.', example_en_3 = 'The iconography of the painting reflects medieval Christian beliefs.', example_ko_3 = '그 그림의 도상학은 중세 기독교 신념을 반영해요.', example_en_4 = 'She specialises in the iconography of East Asian Buddhist art.', example_ko_4 = '그녀는 동아시아 불교 미술의 도상학을 전문으로 해요.', example_en_5 = 'Understanding the iconography is key to reading this altarpiece.', example_ko_5 = '도상학을 이해하는 것이 이 제단화를 읽는 데 핵심이에요.' WHERE id = 'w_culture_B2_05';

UPDATE words SET example_en_2 = 'Postmodern literature often plays with narrative structure.', example_ko_2 = '포스트모던 문학은 종종 서사 구조를 가지고 놀아요.', example_en_3 = 'She wrote her dissertation on postmodern approaches to theatre.', example_ko_3 = '그녀는 연극에 대한 포스트모던 접근 방식에 관한 논문을 썼어요.', example_en_4 = 'Postmodern art frequently borrows and remixes earlier styles.', example_ko_4 = '포스트모던 예술은 자주 이전 스타일을 차용하고 혼합해요.', example_en_5 = 'The gallery''s postmodern interior contrasts sharply with the classical works inside.', example_ko_5 = '갤러리의 포스트모던 인테리어는 내부의 고전 작품과 뚜렷한 대조를 이루어요.' WHERE id = 'w_culture_B2_06';

UPDATE words SET example_en_2 = 'The film received a devastating critique in the national press.', example_ko_2 = '그 영화는 전국 언론에서 혹독한 비평을 받았어요.', example_en_3 = 'Her critique of the exhibition raised important questions.', example_ko_3 = '전시회에 대한 그녀의 비평은 중요한 질문들을 제기했어요.', example_en_4 = 'Writing a good critique requires close observation.', example_ko_4 = '좋은 비평을 쓰려면 면밀한 관찰이 필요해요.', example_en_5 = 'The critique focused on the artist''s use of space and colour.', example_ko_5 = '그 비평은 예술가의 공간과 색채 사용에 집중했어요.' WHERE id = 'w_culture_B2_07';

UPDATE words SET example_en_2 = 'Her interpretation of the piece was deeply personal and moving.', example_ko_2 = '작품에 대한 그녀의 해석은 매우 개인적이고 감동적이었어요.', example_en_3 = 'The director''s interpretation of the play was controversial.', example_ko_3 = '연극에 대한 감독의 해석은 논란이 됐어요.', example_en_4 = 'Multiple interpretations can coexist without any one being definitive.', example_ko_4 = '어느 하나가 결정적이지 않아도 여러 해석이 공존할 수 있어요.', example_en_5 = 'The curator''s interpretation of the collection is reflected in how works are arranged.', example_ko_5 = '컬렉션에 대한 큐레이터의 해석은 작품이 배치된 방식에 반영돼 있어요.' WHERE id = 'w_culture_B2_08';

UPDATE words SET example_en_2 = 'The aesthetic movement is associated with the slogan "art for art''s sake".', example_ko_2 = '미학 운동은 "예술을 위한 예술"이라는 슬로건과 연관돼 있어요.', example_en_3 = 'Scholars debate the lasting impact of the aesthetic movement on modern design.', example_ko_3 = '학자들은 미학 운동이 현대 디자인에 미친 지속적인 영향을 논쟁해요.', example_en_4 = 'The aesthetic movement rejected the idea that art must serve a moral purpose.', example_ko_4 = '미학 운동은 예술이 도덕적 목적을 가져야 한다는 생각을 거부했어요.', example_en_5 = 'Figures of the aesthetic movement valued beauty above all else.', example_ko_5 = '미학 운동의 인물들은 무엇보다 아름다움을 중시했어요.' WHERE id = 'w_culture_B2_09';

UPDATE words SET example_en_2 = 'The programme promotes cross-cultural dialogue through music.', example_ko_2 = '그 프로그램은 음악을 통해 다문화적 대화를 촉진해요.', example_en_3 = 'Her research explores cross-cultural approaches to storytelling.', example_ko_3 = '그녀의 연구는 스토리텔링에 대한 다문화적 접근 방식을 탐구해요.', example_en_4 = 'Cross-cultural misunderstandings can arise even in art contexts.', example_ko_4 = '다문화적 오해는 예술적 맥락에서도 생길 수 있어요.', example_en_5 = 'The festival fosters cross-cultural understanding through shared experiences.', example_ko_5 = '그 축제는 공유된 경험을 통해 다문화적 이해를 증진해요.' WHERE id = 'w_culture_B2_10';

UPDATE words SET example_en_2 = 'She read the curator''s note carefully before entering the gallery.', example_ko_2 = '그녀는 갤러리에 들어가기 전에 큐레이터 노트를 주의 깊게 읽었어요.', example_en_3 = 'The curator''s note provided helpful context for understanding the installation.', example_ko_3 = '큐레이터 노트는 설치 미술을 이해하는 데 유용한 맥락을 제공했어요.', example_en_4 = 'A well-written curator''s note can transform the visitor''s experience.', example_ko_4 = '잘 쓰인 큐레이터 노트는 방문객의 경험을 변화시킬 수 있어요.', example_en_5 = 'The curator''s note was translated into six languages.', example_ko_5 = '큐레이터 노트는 여섯 개 언어로 번역됐어요.' WHERE id = 'w_culture_B2_11';

UPDATE words SET example_en_2 = 'The novel sparked controversy for its portrayal of historical events.', example_ko_2 = '그 소설은 역사적 사건을 묘사하는 방식으로 논란을 불러일으켰어요.', example_en_3 = 'Controversy often increases public interest in an artwork.', example_ko_3 = '논란은 종종 예술 작품에 대한 대중의 관심을 높여요.', example_en_4 = 'She entered the controversy deliberately to provoke debate.', example_ko_4 = '그녀는 의도적으로 논쟁을 불러일으키기 위해 논란에 뛰어들었어요.', example_en_5 = 'The controversy around the film lasted for several months.', example_ko_5 = '그 영화를 둘러싼 논란은 몇 달 동안 지속됐어요.' WHERE id = 'w_culture_B2_12';

UPDATE words SET example_en_2 = 'The artist turned down the commission because of the conditions attached.', example_ko_2 = '그 예술가는 붙어 있는 조건 때문에 의뢰를 거절했어요.', example_en_3 = 'She received a commission to paint a mural for the new library.', example_ko_3 = '그녀는 새 도서관을 위한 벽화를 그려달라는 의뢰를 받았어요.', example_en_4 = 'The commission required the work to be completed within six months.', example_ko_4 = '그 의뢰는 6개월 안에 완성해야 했어요.', example_en_5 = 'Public commissions can give artists unprecedented visibility.', example_ko_5 = '공공 의뢰는 예술가에게 전례 없는 가시성을 줄 수 있어요.' WHERE id = 'w_culture_B2_13';

UPDATE words SET example_en_2 = 'The installation used mirrors to create an infinite effect.', example_ko_2 = '그 설치 미술은 거울을 사용해 무한한 효과를 만들었어요.', example_en_3 = 'Visitors were invited to walk through the installation.', example_ko_3 = '방문객들은 설치 미술 안을 걸어서 통과하도록 초대됐어요.', example_en_4 = 'Her installation took three weeks to construct.', example_ko_4 = '그녀의 설치 미술은 3주에 걸쳐 제작됐어요.', example_en_5 = 'The installation explores our relationship with digital technology.', example_ko_5 = '그 설치 미술은 디지털 기술과의 관계를 탐구해요.' WHERE id = 'w_culture_B2_14';

UPDATE words SET example_en_2 = 'The auction house was asked to investigate the provenance of the drawing.', example_ko_2 = '경매 회사는 그 그림의 출처를 조사하도록 요청받았어요.', example_en_3 = 'Museums are increasingly required to verify the provenance of their collections.', example_ko_3 = '박물관들은 점점 더 컬렉션의 출처를 확인해야 해요.', example_en_4 = 'Unclear provenance can significantly reduce a work''s value.', example_ko_4 = '불분명한 출처는 작품의 가치를 크게 떨어뜨릴 수 있어요.', example_en_5 = 'She spent years researching the provenance of the family portrait.', example_ko_5 = '그녀는 가족 초상화의 출처를 연구하는 데 몇 년을 보냈어요.' WHERE id = 'w_culture_B2_15';

UPDATE words SET example_en_2 = 'The retrospective covered forty years of the artist''s career.', example_ko_2 = '그 회고전은 예술가의 40년 경력을 다뤘어요.', example_en_3 = 'A retrospective of her films will tour six cities this year.', example_ko_3 = '그녀의 영화 회고전이 올해 여섯 개 도시를 순회해요.', example_en_4 = 'The retrospective allowed visitors to see how her style evolved.', example_ko_4 = '회고전은 방문객들이 그녀의 스타일이 어떻게 발전했는지 볼 수 있게 했어요.', example_en_5 = 'He felt humbled to attend a retrospective of his own work.', example_ko_5 = '그는 자신의 작품 회고전에 참석하면서 겸손함을 느꼈어요.' WHERE id = 'w_culture_B2_16';

UPDATE words SET example_en_2 = 'The multimedia performance blended dance, music, and live coding.', example_ko_2 = '멀티미디어 공연은 춤, 음악, 라이브 코딩을 혼합했어요.', example_en_3 = 'She designed a multimedia installation for the science museum.', example_ko_3 = '그녀는 과학 박물관을 위한 멀티미디어 설치물을 디자인했어요.', example_en_4 = 'Multimedia art challenges traditional distinctions between disciplines.', example_ko_4 = '멀티미디어 예술은 학문 간의 전통적인 구분에 도전해요.', example_en_5 = 'The multimedia approach made the history exhibition more engaging.', example_ko_5 = '멀티미디어 접근 방식은 역사 전시회를 더 흥미롭게 만들었어요.' WHERE id = 'w_culture_B2_17';

UPDATE words SET example_en_2 = 'Her cartoons use satire to comment on political hypocrisy.', example_ko_2 = '그녀의 만화는 풍자를 사용해 정치적 위선을 비평해요.', example_en_3 = 'The show uses satire to expose the absurdity of modern life.', example_ko_3 = '그 쇼는 풍자를 사용해 현대 생활의 불합리함을 드러내요.', example_en_4 = 'Satire can be more powerful than a direct political statement.', example_ko_4 = '풍자는 직접적인 정치적 발언보다 더 강력할 수 있어요.', example_en_5 = 'His satire of the art world made many collectors uncomfortable.', example_ko_5 = '예술계에 대한 그의 풍자는 많은 컬렉터들을 불편하게 만들었어요.' WHERE id = 'w_culture_B2_18';

UPDATE words SET example_en_2 = 'Censorship of the arts has often been used as a political tool.', example_ko_2 = '예술의 검열은 종종 정치적 도구로 사용되어 왔어요.', example_en_3 = 'She campaigns against censorship in all forms.', example_ko_3 = '그녀는 모든 형태의 검열에 반대하는 캠페인을 벌여요.', example_en_4 = 'The novelist fled to avoid censorship of her controversial work.', example_ko_4 = '소설가는 논란이 되는 작품의 검열을 피하기 위해 도망쳤어요.', example_en_5 = 'Censorship often drives creativity underground rather than suppressing it.', example_ko_5 = '검열은 종종 창의성을 억압하기보다 지하로 몰아넣어요.' WHERE id = 'w_culture_B2_19';

UPDATE words SET example_en_2 = 'The film is a fusion of documentary and fiction.', example_ko_2 = '그 영화는 다큐멘터리와 허구의 융합이에요.', example_en_3 = 'Her music is a fusion of K-pop and classical orchestration.', example_ko_3 = '그녀의 음악은 K팝과 클래식 편곡의 융합이에요.', example_en_4 = 'Cultural fusion has always driven artistic innovation forward.', example_ko_4 = '문화 융합은 항상 예술적 혁신을 앞으로 이끌어왔어요.', example_en_5 = 'The restaurant''s fusion menu inspired her painting series.', example_ko_5 = '레스토랑의 퓨전 메뉴가 그녀의 회화 시리즈에 영감을 줬어요.' WHERE id = 'w_culture_B2_20';

UPDATE words SET example_en_2 = 'The immersive installation made visitors feel they were inside the painting.', example_ko_2 = '몰입형 설치물은 방문객들이 그림 안에 있는 것처럼 느끼게 했어요.', example_en_3 = 'Immersive storytelling is changing how audiences engage with fiction.', example_ko_3 = '몰입형 스토리텔링은 관객이 허구와 교감하는 방식을 바꾸고 있어요.', example_en_4 = 'The immersive concert put speakers all around the audience.', example_ko_4 = '몰입형 콘서트는 관객 주변에 스피커를 배치했어요.', example_en_5 = 'She prefers immersive art experiences to traditional gallery visits.', example_ko_5 = '그녀는 전통적인 갤러리 방문보다 몰입형 예술 경험을 선호해요.' WHERE id = 'w_culture_B2_21';

UPDATE words SET example_en_2 = 'The groundbreaking film used techniques that had never been seen before.', example_ko_2 = '그 획기적인 영화는 이전에 본 적 없는 기법을 사용했어요.', example_en_3 = 'Her groundbreaking research into music therapy changed the field.', example_ko_3 = '음악 치료에 대한 그녀의 획기적인 연구가 분야를 바꿨어요.', example_en_4 = 'The groundbreaking album sold a million copies in its first week.', example_ko_4 = '그 획기적인 앨범은 첫 주에 백만 장이 팔렸어요.', example_en_5 = 'Critics called the installation groundbreaking and long overdue.', example_ko_5 = '비평가들은 그 설치 미술을 획기적이며 오랫동안 기다려왔던 것이라고 불렀어요.' WHERE id = 'w_culture_B2_22';

UPDATE words SET example_en_2 = 'The transcript of the lecture was posted on the museum website.', example_ko_2 = '강의 대본이 박물관 웹사이트에 게시됐어요.', example_en_3 = 'She used the transcript to prepare for the interview.', example_ko_3 = '그녀는 인터뷰 준비를 위해 대본을 활용했어요.', example_en_4 = 'The transcript revealed that the director had very specific intentions.', example_ko_4 = '대본은 감독이 매우 구체적인 의도를 갖고 있었음을 드러냈어요.', example_en_5 = 'A transcript of the panel discussion is available on request.', example_ko_5 = '패널 토의의 대본은 요청 시 받아볼 수 있어요.' WHERE id = 'w_culture_B2_23';

UPDATE words SET example_en_2 = 'The album received widespread acclaim on its release.', example_ko_2 = '그 앨범은 발매 당시 광범위한 찬사를 받았어요.', example_en_3 = 'She accepted the award with quiet acclaim and humility.', example_ko_3 = '그녀는 조용한 찬사와 겸손함으로 상을 받았어요.', example_en_4 = 'The director''s work has earned him international acclaim.', example_ko_4 = '그 감독의 작품은 그에게 국제적인 찬사를 안겨줬어요.', example_en_5 = 'Despite the critical acclaim, the film struggled at the box office.', example_ko_5 = '비평적 찬사에도 불구하고 그 영화는 박스오피스에서 고전했어요.' WHERE id = 'w_culture_B2_24';

UPDATE words SET example_en_2 = 'The film faced censure from several cultural organisations.', example_ko_2 = '그 영화는 여러 문화 단체로부터 비난을 받았어요.', example_en_3 = 'She responded calmly to the censure from the press.', example_ko_3 = '그녀는 언론의 비난에 침착하게 대응했어요.', example_en_4 = 'The censure of the artwork revealed deep divisions in public taste.', example_ko_4 = '예술 작품에 대한 비난은 대중 취향의 깊은 분열을 드러냈어요.', example_en_5 = 'Public censure rarely deters a truly committed artist.', example_ko_5 = '대중적 비난이 진정으로 헌신적인 예술가를 저지하는 경우는 드물어요.' WHERE id = 'w_culture_B2_25';

UPDATE words SET example_en_2 = 'The film is a loving pastiche of golden-age Hollywood musicals.', example_ko_2 = '그 영화는 황금기 할리우드 뮤지컬을 사랑스럽게 모방한 작품이에요.', example_en_3 = 'Her novel is a postmodern pastiche of Victorian detective fiction.', example_ko_3 = '그녀의 소설은 빅토리아 시대 추리 소설을 포스트모던 방식으로 모방했어요.', example_en_4 = 'Pastiche can be both homage and commentary on its source material.', example_ko_4 = '패스티시는 원본 자료에 대한 오마주이자 논평이 될 수 있어요.', example_en_5 = 'Critics debated whether the work was a pastiche or pure imitation.', example_ko_5 = '비평가들은 그 작품이 패스티시인지 순수한 모방인지 논쟁했어요.' WHERE id = 'w_culture_B2_26';

UPDATE words SET example_en_2 = 'The painting''s depiction of poverty was uncomfortably realistic.', example_ko_2 = '그림에서의 빈곤 묘사는 불편할 정도로 사실적이었어요.', example_en_3 = 'Critics praised the film''s sensitive depiction of grief.', example_ko_3 = '비평가들은 그 영화의 슬픔에 대한 섬세한 묘사를 칭찬했어요.', example_en_4 = 'The depiction of women in these paintings reflects the era''s attitudes.', example_ko_4 = '이 그림들에서 여성의 묘사는 그 시대의 태도를 반영해요.', example_en_5 = 'She found the depiction of her culture inaccurate and offensive.', example_ko_5 = '그녀는 자신의 문화 묘사가 부정확하고 불쾌하다고 느꼈어요.' WHERE id = 'w_culture_B2_27';

UPDATE words SET example_en_2 = 'The film''s subversive humour undermines its surface cheerfulness.', example_ko_2 = '그 영화의 전복적인 유머는 표면의 밝음을 약화시켜요.', example_en_3 = 'She uses subversive imagery to challenge gender norms.', example_ko_3 = '그녀는 전복적인 이미지를 사용해 성 규범에 도전해요.', example_en_4 = 'His subversive style earned him both admirers and critics.', example_ko_4 = '그의 전복적인 스타일은 찬미자와 비평가 모두를 불러모았어요.', example_en_5 = 'Subversive art can change minds more subtly than protest.', example_ko_5 = '전복적인 예술은 시위보다 더 미묘하게 사람들의 생각을 바꿀 수 있어요.' WHERE id = 'w_culture_B2_28';

UPDATE words SET example_en_2 = 'The director''s commentary revealed his original vision for the film.', example_ko_2 = '감독의 해설은 영화에 대한 그의 원래 비전을 드러냈어요.', example_en_3 = 'The exhibition catalogue includes a detailed commentary on each work.', example_ko_3 = '전시 카탈로그에는 각 작품에 대한 상세한 해설이 포함되어 있어요.', example_en_4 = 'His photography serves as a commentary on urban isolation.', example_ko_4 = '그의 사진은 도시적 고립에 대한 논평 역할을 해요.', example_en_5 = 'Her commentary on gender in art has become widely cited.', example_ko_5 = '예술에서의 젠더에 대한 그녀의 논평은 널리 인용되고 있어요.' WHERE id = 'w_culture_B2_29';

UPDATE words SET example_en_2 = 'She uses her art to subvert stereotypes about her community.', example_ko_2 = '그녀는 예술을 사용해 자신의 공동체에 대한 고정관념을 뒤집어요.', example_en_3 = 'The film critiques the stereotype of the lone creative genius.', example_ko_3 = '그 영화는 고독한 창조적 천재라는 고정관념을 비판해요.', example_en_4 = 'Breaking stereotypes in media requires deliberate effort.', example_ko_4 = '미디어에서 고정관념을 깨는 것은 의도적인 노력이 필요해요.', example_en_5 = 'Art can be a powerful tool for challenging harmful stereotypes.', example_ko_5 = '예술은 해로운 고정관념에 도전하는 강력한 도구가 될 수 있어요.' WHERE id = 'w_culture_B2_30';

UPDATE words SET example_en_2 = 'The album set a new benchmark for production quality.', example_ko_2 = '그 앨범은 음반 제작 품질의 새로운 기준을 세웠어요.', example_en_3 = 'The exhibition has become a benchmark for immersive art experiences.', example_ko_3 = '그 전시회는 몰입형 예술 경험의 기준이 됐어요.', example_en_4 = 'Critics used the first album as a benchmark to judge all later work.', example_ko_4 = '비평가들은 첫 번째 앨범을 이후 모든 작품을 평가하는 기준으로 사용했어요.', example_en_5 = 'Her choreography has set a new benchmark in contemporary dance.', example_ko_5 = '그녀의 안무는 현대 무용에 새로운 기준을 세웠어요.' WHERE id = 'w_culture_B2_31';

UPDATE words SET example_en_2 = 'She challenged the Western canon by highlighting non-European works.', example_ko_2 = '그녀는 비유럽 작품을 부각시킴으로써 서양 정전에 도전했어요.', example_en_3 = 'The literary canon has expanded significantly in the past thirty years.', example_ko_3 = '문학 정전은 지난 30년 동안 크게 확장됐어요.', example_en_4 = 'His debut novel quickly entered the national literary canon.', example_ko_4 = '그의 데뷔 소설은 빠르게 국가 문학 정전에 들어갔어요.', example_en_5 = 'Which films belong in the canon of world cinema?', example_ko_5 = '어떤 영화들이 세계 영화 정전에 속하나요?' WHERE id = 'w_culture_B2_32';

UPDATE words SET example_en_2 = 'The colour red is a recurring motif throughout the exhibition.', example_ko_2 = '빨간색은 전시회 전체에 걸쳐 반복되는 모티프예요.', example_en_3 = 'The composer uses a three-note motif to unify the symphony.', example_ko_3 = '작곡가는 교향곡을 하나로 묶기 위해 세 음표의 모티프를 사용해요.', example_en_4 = 'She traces the evolution of the nature motif in his paintings.', example_ko_4 = '그녀는 그의 그림에서 자연 모티프의 발전을 추적해요.', example_en_5 = 'The film''s visual motif of broken mirrors reinforces its themes.', example_ko_5 = '영화의 깨진 거울이라는 시각적 모티프가 주제를 강화해요.' WHERE id = 'w_culture_B2_33';

UPDATE words SET example_en_2 = 'The choice of medium greatly affects the feel of the artwork.', example_ko_2 = '매체의 선택은 예술 작품의 느낌에 크게 영향을 미쳐요.', example_en_3 = 'She switched from watercolour to oil as her primary medium.', example_ko_3 = '그녀는 주요 매체를 수채화에서 유화로 바꿨어요.', example_en_4 = 'Photography became the dominant medium of the twentieth century.', example_ko_4 = '사진은 20세기의 지배적인 매체가 됐어요.', example_en_5 = 'What medium does the artist use to create these textures?', example_ko_5 = '예술가는 이 질감들을 만들기 위해 어떤 매체를 사용하나요?' WHERE id = 'w_culture_B2_34';

UPDATE words SET example_en_2 = 'The story contains a clear allusion to Shakespeare''s Hamlet.', example_ko_2 = '그 이야기는 셰익스피어의 햄릿에 대한 명확한 암시를 담고 있어요.', example_en_3 = 'She caught the allusion to the classical myth immediately.', example_ko_3 = '그녀는 고전 신화에 대한 암시를 즉시 알아차렸어요.', example_en_4 = 'The painting is full of allusions to Renaissance iconography.', example_ko_4 = '그 그림은 르네상스 도상학에 대한 암시로 가득 차 있어요.', example_en_5 = 'Understanding the allusion enriches the reading of the poem.', example_ko_5 = '암시를 이해하면 시 읽기가 더욱 풍부해져요.' WHERE id = 'w_culture_B2_35';

