-- C2 (35단어)
-- ══════════════════════════════════════

UPDATE words SET example_en_2 = 'The ontology of the artwork is at the centre of debates in analytic aesthetics.', example_ko_2 = '예술 작품의 존재론은 분석 미학 논쟁의 중심에 있어요.', example_en_3 = 'She questioned the ontology of performance: does it exist only in the moment?', example_ko_3 = '그녀는 공연의 존재론에 의문을 제기했어요: 그것은 오직 순간에만 존재하는 걸까요?', example_en_4 = 'The ontology of digital art differs fundamentally from that of physical objects.', example_ko_4 = '디지털 예술의 존재론은 물리적 객체의 그것과 근본적으로 달라요.', example_en_5 = 'Ontology asks not what art means but what kind of thing it is.', example_ko_5 = '존재론은 예술이 무엇을 의미하는지가 아니라 예술이 어떤 종류의 것인지를 물어요.' WHERE id = 'w_culture_C2_01';

UPDATE words SET example_en_2 = 'Each historical period operates under a different episteme, according to Foucault.', example_ko_2 = '푸코에 따르면, 각 역사적 시기는 다른 에피스테메 아래에서 작동해요.', example_en_3 = 'The shift from one episteme to another is rarely smooth or linear.', example_ko_3 = '하나의 에피스테메에서 다른 것으로의 전환은 거의 부드럽거나 선형적이지 않아요.', example_en_4 = 'Understanding the episteme of an era is essential for interpreting its art.', example_ko_4 = '시대의 에피스테메를 이해하는 것은 그 예술을 해석하는 데 필수적이에요.', example_en_5 = 'She argues that our current episteme is defined by digital mediation.', example_ko_5 = '그녀는 현재의 에피스테메가 디지털 매개에 의해 정의된다고 주장해요.' WHERE id = 'w_culture_C2_02';

UPDATE words SET example_en_2 = 'Heteroglossia in the novel prevents any single voice from dominating.', example_ko_2 = '소설의 헤테로글로시아는 어떤 단일 목소리도 지배하는 것을 막아요.', example_en_3 = 'Bakhtin saw heteroglossia as the defining feature of the novel as a form.', example_ko_3 = '바흐친은 헤테로글로시아를 형식으로서의 소설의 결정적 특징으로 봤어요.', example_en_4 = 'She valued heteroglossia as a model for creating truly democratic cultural spaces.', example_ko_4 = '그녀는 헤테로글로시아를 진정한 민주적 문화 공간 창출의 모델로 중시했어요.', example_en_5 = 'Heteroglossia challenges the authority of any single cultural narrative.', example_ko_5 = '헤테로글로시아는 어떤 단일 문화 서사의 권위에도 도전해요.' WHERE id = 'w_culture_C2_03';

UPDATE words SET example_en_2 = 'The aporia in her argument was precisely what made it interesting.', example_ko_2 = '그녀의 주장 속의 아포리아가 바로 그것을 흥미롭게 만드는 것이었어요.', example_en_3 = 'Derrida used aporia as a productive rather than paralyzing concept.', example_ko_3 = '데리다는 아포리아를 마비시키는 개념이 아니라 생산적인 것으로 사용했어요.', example_en_4 = 'The film stages an aporia between love and obligation.', example_ko_4 = '그 영화는 사랑과 의무 사이의 아포리아를 무대 위에 올려요.', example_en_5 = 'Recognising aporia in a text is the first step toward more honest interpretation.', example_ko_5 = '텍스트에서 아포리아를 인식하는 것이 더 솔직한 해석으로 가는 첫 번째 단계예요.' WHERE id = 'w_culture_C2_04';

UPDATE words SET example_en_2 = 'The library building is itself a palimpsest of different architectural eras.', example_ko_2 = '그 도서관 건물 자체가 다른 건축 시대의 팔림프세스트예요.', example_en_3 = 'She reads the landscape as a palimpsest of colonial history.', example_ko_3 = '그녀는 경관을 식민지 역사의 팔림프세스트로 읽어요.', example_en_4 = 'Every artwork is a palimpsest of the influences that shaped its creator.', example_ko_4 = '모든 예술 작품은 그 창작자를 형성한 영향들의 팔림프세스트예요.', example_en_5 = 'The palimpsest is a useful metaphor for understanding cultural memory.', example_ko_5 = '팔림프세스트는 문화적 기억을 이해하는 데 유용한 은유예요.' WHERE id = 'w_culture_C2_05';

UPDATE words SET example_en_2 = 'Her documentary is a bricolage of home videos, news footage, and original interviews.', example_ko_2 = '그녀의 다큐멘터리는 홈 비디오, 뉴스 영상, 독창적인 인터뷰의 브리콜라주예요.', example_en_3 = 'Bricolage as a method resists the idea that creation requires pure raw material.', example_ko_3 = '방법으로서의 브리콜라주는 창조에 순수한 원자재가 필요하다는 생각에 저항해요.', example_en_4 = 'The installation is a bricolage of discarded consumer objects.', example_ko_4 = '그 설치물은 버려진 소비재 물건들의 브리콜라주예요.', example_en_5 = 'Cultural bricolage occurs whenever elements from different traditions are recombined.', example_ko_5 = '문화적 브리콜라주는 다른 전통의 요소들이 재결합될 때마다 발생해요.' WHERE id = 'w_culture_C2_06';

UPDATE words SET example_en_2 = 'Logocentrism assumes that speech is more authentic than writing.', example_ko_2 = '로고중심주의는 발화가 글쓰기보다 더 진본적이라고 가정해요.', example_en_3 = 'She critiques the logocentrism embedded in Western narrative theory.', example_ko_3 = '그녀는 서양 서사 이론에 내재된 로고중심주의를 비판해요.', example_en_4 = 'Derrida''s Of Grammatology is a sustained attack on logocentrism.', example_ko_4 = '데리다의 『그라마톨로지에 대하여』는 로고중심주의에 대한 지속적인 공격이에요.', example_en_5 = 'Overcoming logocentrism requires rethinking the foundations of meaning itself.', example_ko_5 = '로고중심주의를 극복하려면 의미 자체의 기초를 재고해야 해요.' WHERE id = 'w_culture_C2_07';

UPDATE words SET example_en_2 = 'Différance destabilises the idea that words have stable, self-present meanings.', example_ko_2 = '디페랑스는 단어가 안정적이고 자기 현재적인 의미를 갖는다는 생각을 불안정하게 해요.', example_en_3 = 'She applies the concept of différance to read gaps in the exhibition narrative.', example_ko_3 = '그녀는 디페랑스 개념을 전시 서사의 공백을 읽는 데 적용해요.', example_en_4 = 'Différance implies that meaning is always arriving but never fully present.', example_ko_4 = '디페랑스는 의미가 항상 도착 중이지만 결코 완전히 현존하지 않음을 함의해요.', example_en_5 = 'For Derrida, différance is not a concept but a mark of the limits of conceptuality.', example_ko_5 = '데리다에게 디페랑스는 개념이 아니라 개념성의 한계를 나타내는 표지예요.' WHERE id = 'w_culture_C2_08';

UPDATE words SET example_en_2 = 'The rhizome model allows for multiple, non-hierarchical connections across cultural fields.', example_ko_2 = '리좀 모델은 문화적 분야 전반에 걸쳐 다수의 비위계적 연결을 허용해요.', example_en_3 = 'She used the rhizome as a metaphor for the networked structure of contemporary art.', example_ko_3 = '그녀는 리좀을 현대 미술의 네트워크 구조에 대한 은유로 사용했어요.', example_en_4 = 'The rhizome resists linear narratives and hierarchical classifications.', example_ko_4 = '리좀은 선형적 서사와 위계적 분류에 저항해요.', example_en_5 = 'Applying the rhizome to cultural analysis opens unexpected connections.', example_ko_5 = '리좀을 문화 분석에 적용하면 예상치 못한 연결들이 열려요.' WHERE id = 'w_culture_C2_09';

UPDATE words SET example_en_2 = 'Hypertext challenges the linear sequence of traditional narrative.', example_ko_2 = '하이퍼텍스트는 전통적 서사의 선형적 순서에 도전해요.', example_en_3 = 'She wrote a hypertext novel in which the reader chooses the order of chapters.', example_ko_3 = '그녀는 독자가 챕터 순서를 선택하는 하이퍼텍스트 소설을 썼어요.', example_en_4 = 'Hypertext has blurred the distinction between author and reader.', example_ko_4 = '하이퍼텍스트는 작가와 독자 사이의 구분을 흐려놓았어요.', example_en_5 = 'The exhibition used hypertext principles to let visitors navigate freely.', example_ko_5 = '전시회는 방문객들이 자유롭게 탐색할 수 있도록 하이퍼텍스트 원칙을 사용했어요.' WHERE id = 'w_culture_C2_10';

UPDATE words SET example_en_2 = 'Baudrillard argued that the simulacrum has replaced reality in consumer culture.', example_ko_2 = '보드리야르는 소비 문화에서 시뮬라크르가 현실을 대체했다고 주장했어요.', example_en_3 = 'The theme park is a perfect example of the simulacrum: a copy without an original.', example_ko_3 = '테마파크는 원본 없는 사본인 시뮬라크르의 완벽한 예예요.', example_en_4 = 'Her installation questions whether contemporary images can escape the simulacrum.', example_ko_4 = '그녀의 설치물은 현대적 이미지가 시뮬라크르에서 벗어날 수 있는지를 의문시해요.', example_en_5 = 'The simulacrum unsettles our faith in the authenticity of representation.', example_ko_5 = '시뮬라크르는 표현의 진정성에 대한 우리의 믿음을 흔들어요.' WHERE id = 'w_culture_C2_11';

UPDATE words SET example_en_2 = 'The exhibition centred on the perspectives of subaltern communities previously excluded from art history.', example_ko_2 = '그 전시회는 미술사에서 이전에 배제된 하위주체 공동체의 관점을 중심으로 했어요.', example_en_3 = 'She argues that the subaltern cannot speak within dominant cultural structures.', example_ko_3 = '그녀는 하위주체가 지배적인 문화 구조 안에서는 말할 수 없다고 주장해요.', example_en_4 = 'Giving visibility to subaltern voices requires more than token representation.', example_ko_4 = '하위주체의 목소리를 가시화하려면 상징적인 대표 이상이 필요해요.', example_en_5 = 'His film gives the subaltern a platform that mainstream cinema rarely allows.', example_ko_5 = '그의 영화는 주류 영화가 거의 허용하지 않는 플랫폼을 하위주체에게 제공해요.' WHERE id = 'w_culture_C2_12';

UPDATE words SET example_en_2 = 'A genealogy of modern art reveals its roots in colonial power structures.', example_ko_2 = '현대 미술의 계보학은 식민지 권력 구조에 있는 뿌리를 드러내요.', example_en_3 = 'She conducted a genealogy of the concept of artistic originality.', example_ko_3 = '그녀는 예술적 독창성 개념의 계보학을 수행했어요.', example_en_4 = 'Foucauldian genealogy is a way of tracing how present norms came to seem natural.', example_ko_4 = '푸코식 계보학은 현재의 규범이 어떻게 자연스럽게 보이게 됐는지를 추적하는 방법이에요.', example_en_5 = 'The genealogy of the gallery institution links aesthetics to social class.', example_ko_5 = '갤러리 기관의 계보학은 미학을 사회 계층과 연결해요.' WHERE id = 'w_culture_C2_13';

UPDATE words SET example_en_2 = 'Hauntology describes how the past continues to haunt the cultural present.', example_ko_2 = '유령론은 과거가 어떻게 문화적 현재를 계속 출몰하는지를 묘사해요.', example_en_3 = 'She uses hauntology to analyse the persistence of socialist imagery in post-Soviet film.', example_ko_3 = '그녀는 유령론을 사용해 포스트소비에트 영화에서 사회주의 이미지의 지속성을 분석해요.', example_en_4 = 'Hauntology captures the uncanny feeling of living in a time out of joint.', example_ko_4 = '유령론은 시간에서 어긋난 시대에 사는 것의 낯선 느낌을 포착해요.', example_en_5 = 'The album''s sound design evokes a hauntology of lost futures.', example_ko_5 = '그 앨범의 사운드 디자인은 잃어버린 미래들의 유령론을 불러일으켜요.' WHERE id = 'w_culture_C2_14';

UPDATE words SET example_en_2 = 'Lacan''s jouissance refers to a pleasure beyond the pleasure principle.', example_ko_2 = '라캉의 쥬이상스는 쾌락 원리를 넘어서는 즐거움을 가리켜요.', example_en_3 = 'The film''s obsessive quality can be read in terms of jouissance.', example_ko_3 = '영화의 강박적 성격은 쥬이상스의 관점에서 읽을 수 있어요.', example_en_4 = 'She argues that jouissance, not beauty, drives the compulsive return to certain artworks.', example_ko_4 = '그녀는 특정 예술 작품으로의 강박적 귀환을 이끄는 것이 아름다움이 아니라 쥬이상스라고 주장해요.', example_en_5 = 'Understanding jouissance helps explain why transgressive art attracts and repels simultaneously.', example_ko_5 = '쥬이상스를 이해하면 위반적인 예술이 왜 동시에 끌어당기고 밀어내는지를 설명하는 데 도움이 돼요.' WHERE id = 'w_culture_C2_15';

UPDATE words SET example_en_2 = 'Kristeva''s concept of the abject explores what must be expelled for subjectivity to form.', example_ko_2 = '크리스테바의 비체 개념은 주체성이 형성되기 위해 추방되어야 하는 것을 탐구해요.', example_en_3 = 'The abject surfaces in art when the boundaries of the self are called into question.', example_ko_3 = '비체는 자아의 경계가 의문시될 때 예술에서 나타나요.', example_en_4 = 'Her paintings deliberately invoke the abject to unsettle comfortable viewers.', example_ko_4 = '그녀의 그림은 편안한 관람객들을 불안하게 하기 위해 의도적으로 비체를 불러내요.', example_en_5 = 'The abject is not merely disgusting; it is that which threatens the border of the subject.', example_ko_5 = '비체는 단순히 혐오스러운 것이 아니라 주체의 경계를 위협하는 것이에요.' WHERE id = 'w_culture_C2_16';

UPDATE words SET example_en_2 = 'Foucault described the cinema as a heterotopia of time: a site of accumulated images.', example_ko_2 = '푸코는 영화를 시간의 헤테로토피아, 즉 축적된 이미지들의 장소로 묘사했어요.', example_en_3 = 'The garden functions as a heterotopia in this novel, suspended outside everyday rules.', example_ko_3 = '이 소설에서 정원은 일상적인 규칙 밖에 걸쳐 있는 헤테로토피아로 기능해요.', example_en_4 = 'She analyses the gallery as a heterotopia that reframes experience.', example_ko_4 = '그녀는 경험을 재구성하는 헤테로토피아로 갤러리를 분석해요.', example_en_5 = 'A heterotopia is a real place that mirrors and distorts all other spaces.', example_ko_5 = '헤테로토피아는 다른 모든 공간을 반영하고 왜곡하는 실제 장소예요.' WHERE id = 'w_culture_C2_17';

UPDATE words SET example_en_2 = 'Deterritorialisation of culture does not erase difference; it multiplies it.', example_ko_2 = '문화의 탈영토화는 차이를 지우지 않고 오히려 증가시켜요.', example_en_3 = 'She examines deterritorialisation as a process that opens new creative possibilities.', example_ko_3 = '그녀는 탈영토화를 새로운 창조적 가능성을 여는 과정으로 검토해요.', example_en_4 = 'Music streaming has accelerated the deterritorialisation of musical genres.', example_ko_4 = '음악 스트리밍은 음악 장르의 탈영토화를 가속화했어요.', example_en_5 = 'Deterritorialisation is followed by reterritorialisation: new structures always emerge.', example_ko_5 = '탈영토화 다음에는 재영토화가 따라오며, 항상 새로운 구조가 나타나요.' WHERE id = 'w_culture_C2_18';

UPDATE words SET example_en_2 = 'Intersubjectivity underpins the possibility of shared aesthetic experience.', example_ko_2 = '상호주관성은 공유된 미학적 경험의 가능성을 뒷받침해요.', example_en_3 = 'She argues that art creates zones of intersubjectivity between strangers.', example_ko_3 = '그녀는 예술이 낯선 사람들 사이에 상호주관성의 영역을 만든다고 주장해요.', example_en_4 = 'The performance art piece explored the fragility of intersubjectivity.', example_ko_4 = '그 퍼포먼스 아트 작품은 상호주관성의 취약함을 탐구했어요.', example_en_5 = 'Without intersubjectivity, the communication of meaning would be impossible.', example_ko_5 = '상호주관성 없이는 의미의 소통이 불가능할 거예요.' WHERE id = 'w_culture_C2_19';

UPDATE words SET example_en_2 = 'The paratext shapes reader expectations before the first page is turned.', example_ko_2 = '주변텍스트는 첫 페이지가 넘어가기 전에 독자의 기대를 형성해요.', example_en_3 = 'She analyses the exhibition title and wall text as paratexts that frame meaning.', example_ko_3 = '그녀는 전시 제목과 벽면 텍스트를 의미를 틀 짓는 주변텍스트로 분석해요.', example_en_4 = 'Genette''s theory of the paratext extended structuralism beyond the text itself.', example_ko_4 = '제네트의 주변텍스트 이론은 구조주의를 텍스트 자체 너머로 확장했어요.', example_en_5 = 'The paratext is not secondary; it is constitutive of the reading experience.', example_ko_5 = '주변텍스트는 부차적인 것이 아니라 독서 경험을 구성하는 요소예요.' WHERE id = 'w_culture_C2_20';

UPDATE words SET example_en_2 = 'Defamiliarisation makes the ordinary strange in order to renew perception.', example_ko_2 = '낯설게하기는 인식을 새롭게 하기 위해 평범한 것을 낯설게 만들어요.', example_en_3 = 'She uses slow motion as a technique of defamiliarisation in her films.', example_ko_3 = '그녀는 영화에서 슬로모션을 낯설게하기의 기법으로 사용해요.', example_en_4 = 'Brecht''s theatre relied on defamiliarisation to prevent audience identification.', example_ko_4 = '브레히트의 연극은 관객의 동일화를 막기 위해 낯설게하기에 의존했어요.', example_en_5 = 'Defamiliarisation restores the sense of seeing the world for the first time.', example_ko_5 = '낯설게하기는 세상을 처음 보는 것 같은 감각을 회복시켜요.' WHERE id = 'w_culture_C2_21';

UPDATE words SET example_en_2 = 'Interpellation works by recruiting individuals into ideological positions.', example_ko_2 = '호명은 개인을 이데올로기적 입장으로 끌어들임으로써 작동해요.', example_en_3 = 'She analyses how film genres rely on interpellation to construct the ideal viewer.', example_ko_3 = '그녀는 영화 장르가 이상적인 관람객을 구성하기 위해 호명에 어떻게 의존하는지를 분석해요.', example_en_4 = 'Althusser used the example of the policeman''s hail to explain interpellation.', example_ko_4 = '알튀세르는 호명을 설명하기 위해 경찰관의 부름이라는 예시를 사용했어요.', example_en_5 = 'Interpellation is never complete; subjects can always resist their assigned positions.', example_ko_5 = '호명은 결코 완전하지 않아요; 주체들은 언제나 지정된 입장에 저항할 수 있어요.' WHERE id = 'w_culture_C2_22';

UPDATE words SET example_en_2 = 'Feminist film theory transformed the field of spectatorship by introducing the male gaze.', example_ko_2 = '페미니스트 영화 이론은 남성적 시선을 도입함으로써 관람 행위 분야를 변화시켰어요.', example_en_3 = 'She studies spectatorship in immersive virtual reality experiences.', example_ko_3 = '그녀는 몰입형 가상 현실 경험에서의 관람 행위를 연구해요.', example_en_4 = 'Spectatorship is always active; viewers make meaning, not just receive it.', example_ko_4 = '관람 행위는 항상 능동적이에요; 관람객들은 의미를 받는 것만이 아니라 만들어요.', example_en_5 = 'Her work examines how race shapes the conditions of spectatorship.', example_ko_5 = '그녀의 연구는 인종이 관람 행위의 조건을 어떻게 형성하는지를 검토해요.' WHERE id = 'w_culture_C2_23';

UPDATE words SET example_en_2 = 'The chronotope of the prison shapes the narrative possibilities of crime fiction.', example_ko_2 = '감옥의 크로노토프는 범죄 소설의 서사 가능성을 형성해요.', example_en_3 = 'Bakhtin''s chronotope reveals how time and space together produce narrative meaning.', example_ko_3 = '바흐친의 크로노토프는 시간과 공간이 함께 어떻게 서사적 의미를 생성하는지를 드러내요.', example_en_4 = 'She analysed the chronotope of the café as central to modernist fiction.', example_ko_4 = '그녀는 카페의 크로노토프를 모더니스트 소설의 핵심으로 분석했어요.', example_en_5 = 'Different genres create different chronotopes, shaping what kinds of events can occur.', example_ko_5 = '다른 장르들은 다른 크로노토프를 만들어 어떤 종류의 사건이 일어날 수 있는지를 형성해요.' WHERE id = 'w_culture_C2_24';

UPDATE words SET example_en_2 = 'In acousmatic music, the source of the sound is deliberately hidden from the listener.', example_ko_2 = '아쿠스마틱 음악에서는 소리의 출처가 의도적으로 청취자에게 숨겨져 있어요.', example_en_3 = 'The acousmatic experience separates hearing from seeing.', example_ko_3 = '아쿠스마틱 경험은 듣는 것과 보는 것을 분리시켜요.', example_en_4 = 'She composed an acousmatic piece that played continuously through the installation.', example_ko_4 = '그녀는 설치물 전반에 걸쳐 지속적으로 재생되는 아쿠스마틱 작품을 작곡했어요.', example_en_5 = 'Acousmatic listening asks us to attend to sound as pure sensation.', example_ko_5 = '아쿠스마틱 청취는 소리를 순수한 감각으로 주의 깊게 듣도록 요청해요.' WHERE id = 'w_culture_C2_25';

UPDATE words SET example_en_2 = 'Bloom''s clinamen describes the way a poet misreads a predecessor creatively.', example_ko_2 = '블룸의 클리나멘은 시인이 선행자를 창조적으로 잘못 읽는 방식을 묘사해요.', example_en_3 = 'The clinamen is not an error but a necessary deviation toward originality.', example_ko_3 = '클리나멘은 오류가 아니라 독창성을 향한 필요한 일탈이에요.', example_en_4 = 'She applied the concept of clinamen to analyse how directors reinterpret classic texts.', example_ko_4 = '그녀는 감독들이 고전 텍스트를 어떻게 재해석하는지를 분석하기 위해 클리나멘 개념을 적용했어요.', example_en_5 = 'Every great artist performs a clinamen from the tradition that shaped them.', example_ko_5 = '모든 위대한 예술가는 자신을 형성한 전통으로부터 클리나멘을 수행해요.' WHERE id = 'w_culture_C2_26';

UPDATE words SET example_en_2 = 'The pharmakon structure appears whenever art is both healing and disturbing.', example_ko_2 = '예술이 치유적이면서 동시에 교란적일 때마다 파르마콘 구조가 나타나요.', example_en_3 = 'She reads cinema as a pharmakon: capable of both enlightening and enslaving its audience.', example_ko_3 = '그녀는 영화를 파르마콘으로 읽어요: 관객을 계몽하는 동시에 예속시킬 수 있는 것으로요.', example_en_4 = 'Technology is the pharmakon of the digital age, offering connection and isolation alike.', example_ko_4 = '기술은 디지털 시대의 파르마콘으로, 연결과 고립 모두를 제공해요.', example_en_5 = 'Derrida uses pharmakon to show that good and harmful effects cannot be cleanly separated.', example_ko_5 = '데리다는 파르마콘을 사용해 좋은 효과와 해로운 효과를 깔끔하게 분리할 수 없음을 보여줘요.' WHERE id = 'w_culture_C2_27';

UPDATE words SET example_en_2 = 'The polysemy of the image is what makes it endlessly discussable.', example_ko_2 = '이미지의 다의성이 그것을 끝없이 논의 가능하게 만드는 것이에요.', example_en_3 = 'She values polysemy as a sign of artistic richness rather than ambiguity.', example_ko_3 = '그녀는 다의성을 모호함이 아니라 예술적 풍요로움의 표시로 중시해요.', example_en_4 = 'The polysemy of certain symbols makes cross-cultural translation extremely difficult.', example_ko_4 = '특정 기호들의 다의성은 문화 간 번역을 매우 어렵게 만들어요.', example_en_5 = 'Polysemy is a feature of all natural language, not just literary texts.', example_ko_5 = '다의성은 문학 텍스트만이 아니라 모든 자연 언어의 특성이에요.' WHERE id = 'w_culture_C2_28';

UPDATE words SET example_en_2 = 'Her ekphrastic poem about a Korean celadon vase was widely anthologised.', example_ko_2 = '한국 청자에 관한 그녀의 에크프라시스 시는 많은 선집에 수록됐어요.', example_en_3 = 'The ekphrastic tradition allows literature and visual art to illuminate each other.', example_ko_3 = '에크프라시스 전통은 문학과 시각 예술이 서로를 비추도록 해줘요.', example_en_4 = 'She delivered an ekphrastic reading of a photograph taken in the ruins of a theatre.', example_ko_4 = '그녀는 한 극장 폐허에서 찍힌 사진에 대한 에크프라시스 낭독을 했어요.', example_en_5 = 'Ekphrastic poems raise profound questions about the limits of verbal and visual representation.', example_ko_5 = '에크프라시스 시는 언어적 및 시각적 표현의 한계에 대한 깊은 질문들을 제기해요.' WHERE id = 'w_culture_C2_29';

UPDATE words SET example_en_2 = 'The novel explores xenoglossy as a metaphor for the untranslatability of cultural experience.', example_ko_2 = '그 소설은 문화적 경험의 번역 불가능성에 대한 은유로서 이국어 사용을 탐구해요.', example_en_3 = 'She found xenoglossy a useful concept for analysing multilingual performance art.', example_ko_3 = '그녀는 다국어 퍼포먼스 아트를 분석하는 데 이국어 사용이 유용한 개념임을 발견했어요.', example_en_4 = 'Xenoglossy reminds us that language is never merely communicative but always embodied.', example_ko_4 = '이국어 사용은 언어가 단순히 소통적인 것이 아니라 항상 체화된 것임을 상기시켜요.', example_en_5 = 'The performance created an experience of xenoglossy by deliberately mixing unintelligible tongues.', example_ko_5 = '그 공연은 의도적으로 이해할 수 없는 언어들을 섞음으로써 이국어 사용의 경험을 만들었어요.' WHERE id = 'w_culture_C2_30';

UPDATE words SET example_en_2 = 'For Brecht, praxis meant transforming social conditions, not merely reflecting them.', example_ko_2 = '브레히트에게 실천은 사회적 조건을 단순히 반영하는 것이 아니라 변화시키는 것을 의미했어요.', example_en_3 = 'The collective''s praxis is rooted in community engagement and collective decision-making.', example_ko_3 = '그 집단의 실천은 공동체 참여와 집단적 의사결정에 뿌리를 두고 있어요.', example_en_4 = 'She argues that art without praxis is merely decoration.', example_ko_4 = '그녀는 실천 없는 예술은 단순한 장식에 불과하다고 주장해요.', example_en_5 = 'The gap between theory and praxis is a recurring theme in critical art discourse.', example_ko_5 = '이론과 실천 사이의 간극은 비평 예술 담론에서 반복되는 주제예요.' WHERE id = 'w_culture_C2_31';

UPDATE words SET example_en_2 = 'Bhabha''s concept of hybridity challenges essentialist notions of cultural identity.', example_ko_2 = '바바의 혼종성 개념은 문화적 정체성에 대한 본질주의적 개념들에 도전해요.', example_en_3 = 'The artist celebrates hybridity by weaving together motifs from East and West.', example_ko_3 = '그 예술가는 동양과 서양의 모티프들을 엮음으로써 혼종성을 기념해요.', example_en_4 = 'Hybridity is not a weakness but a source of creative vitality.', example_ko_4 = '혼종성은 약점이 아니라 창조적 활력의 원천이에요.', example_en_5 = 'The third space of hybridity opens possibilities that neither tradition alone could generate.', example_ko_5 = '혼종성의 제3공간은 어느 전통도 단독으로 생성할 수 없는 가능성들을 열어요.' WHERE id = 'w_culture_C2_32';

UPDATE words SET example_en_2 = 'The enunciation of the film positions the viewer in a specific relation to the narrative.', example_ko_2 = '영화의 발화는 관람객을 서사와의 특정 관계 속에 위치시켜요.', example_en_3 = 'She examines how the mode of enunciation differs across documentary subgenres.', example_ko_3 = '그녀는 발화 방식이 다큐멘터리 하위 장르에 걸쳐 어떻게 다른지를 검토해요.', example_en_4 = 'The enunciation of authority in the museum is communicated through spatial arrangement.', example_ko_4 = '박물관에서 권위의 발화는 공간적 배치를 통해 전달돼요.', example_en_5 = 'A shift in enunciation can completely transform the meaning of the same visual content.', example_ko_5 = '발화의 변화는 동일한 시각적 내용의 의미를 완전히 변화시킬 수 있어요.' WHERE id = 'w_culture_C2_33';

UPDATE words SET example_en_2 = 'Apophenia drives the human tendency to find patterns in random noise.', example_ko_2 = '아포페니아는 무작위 잡음에서 패턴을 찾으려는 인간의 경향을 이끌어요.', example_en_3 = 'She argues that aesthetic experience is a controlled form of apophenia.', example_ko_3 = '그녀는 미학적 경험이 아포페니아의 통제된 형태라고 주장해요.', example_en_4 = 'The artist deliberately induces apophenia by presenting ambiguous visual fields.', example_ko_4 = '그 예술가는 모호한 시각적 영역을 제시함으로써 의도적으로 아포페니아를 유발해요.', example_en_5 = 'Apophenia connects the creative act of art-making to the cognitive drive to find meaning.', example_ko_5 = '아포페니아는 예술 창작 행위를 의미 찾기의 인지적 충동과 연결해요.' WHERE id = 'w_culture_C2_34';

UPDATE words SET example_en_2 = 'Thanatopolitics asks which lives are deemed grievable and which are not.', example_ko_2 = '죽음 정치학은 어떤 삶이 애도 가능하고 어떤 삶이 그렇지 않은지를 물어요.', example_en_3 = 'She applies thanatopolitics to analyse whose deaths are represented in war photography.', example_ko_3 = '그녀는 죽음 정치학을 전쟁 사진에서 누구의 죽음이 표현되는지를 분석하는 데 적용해요.', example_en_4 = 'Thanatopolitics emerges at the intersection of sovereignty, race, and biopower.', example_ko_4 = '죽음 정치학은 주권, 인종, 생체권력의 교차점에서 나타나요.', example_en_5 = 'Art that confronts thanatopolitics forces audiences to reckon with structures of disposability.', example_ko_5 = '죽음 정치학에 맞서는 예술은 관객들이 가처분성의 구조와 씨름하게 해요.' WHERE id = 'w_culture_C2_35';

