UPDATE words SET example_en_2 = 'I think we should leave early.', example_ko_2 = '일찍 출발해야 할 것 같아요.', example_en_3 = 'What do you think about the new rule?', example_ko_3 = '새 규칙에 대해 어떻게 생각해요?', example_en_4 = 'I think it is a good plan.', example_ko_4 = '좋은 계획 같아요.', example_en_5 = 'She thinks we need more time.', example_ko_5 = '그녀는 우리에게 더 많은 시간이 필요하다고 생각해요.' WHERE id = 'w_discussion_A1_01';

UPDATE words SET example_en_2 = 'He said he would be there at noon.', example_ko_2 = '그는 정오에 거기 있겠다고 했어요.', example_en_3 = 'Please say what you really mean.', example_ko_3 = '진짜 하고 싶은 말을 해주세요.', example_en_4 = 'She said nothing during the meeting.', example_ko_4 = '그녀는 회의 중에 아무 말도 안 했어요.', example_en_5 = 'What did you say just now?', example_ko_5 = '방금 뭐라고 하셨어요?' WHERE id = 'w_discussion_A1_02';

UPDATE words SET example_en_2 = 'Do you agree with me on this?', example_ko_2 = '이 부분에서 저와 동의하시나요?', example_en_3 = 'We all agree that safety comes first.', example_ko_3 = '우리 모두 안전이 먼저라는 데 동의해요.', example_en_4 = 'He does not agree with the new policy.', example_ko_4 = '그는 새 정책에 동의하지 않아요.', example_en_5 = 'She agreed to try the new method.', example_ko_5 = '그녀는 새 방법을 시도해보기로 동의했어요.' WHERE id = 'w_discussion_A1_03';

UPDATE words SET example_en_2 = 'I want to know your opinion.', example_ko_2 = '당신의 의견을 알고 싶어요.', example_en_3 = 'They want to find a better solution.', example_ko_3 = '그들은 더 나은 해결책을 찾고 싶어해요.', example_en_4 = 'Do you want to join the discussion?', example_ko_4 = '토론에 참여하고 싶으세요?', example_en_5 = 'I want everyone to feel comfortable speaking.', example_ko_5 = '모두가 편하게 말할 수 있었으면 해요.' WHERE id = 'w_discussion_A1_04';

UPDATE words SET example_en_2 = 'Do you know when the meeting starts?', example_ko_2 = '회의가 언제 시작하는지 알아요?', example_en_3 = 'I know this topic is difficult.', example_ko_3 = '이 주제가 어렵다는 걸 알아요.', example_en_4 = 'She knows a lot about the subject.', example_ko_4 = '그녀는 그 주제에 대해 많이 알아요.', example_en_5 = 'Let me know if you have questions.', example_ko_5 = '질문이 있으면 알려주세요.' WHERE id = 'w_discussion_A1_05';

UPDATE words SET example_en_2 = 'I really like how you explained that.', example_ko_2 = '그걸 설명하신 방식이 정말 마음에 들어요.', example_en_3 = 'She likes to ask questions in class.', example_ko_3 = '그녀는 수업에서 질문하는 걸 좋아해요.', example_en_4 = 'I like your point about the budget.', example_ko_4 = '예산에 관한 당신의 의견이 마음에 들어요.', example_en_5 = 'Do you like discussing new ideas?', example_ko_5 = '새로운 아이디어에 대해 토론하는 걸 좋아하세요?' WHERE id = 'w_discussion_A1_06';

UPDATE words SET example_en_2 = 'Maybe we can meet after lunch.', example_ko_2 = '아마도 점심 후에 만날 수 있을 것 같아요.', example_en_3 = 'Maybe he has a different point of view.', example_ko_3 = '아마도 그는 다른 관점을 가지고 있을 거예요.', example_en_4 = 'Maybe that is not the best choice.', example_ko_4 = '아마도 그건 최선의 선택이 아닐 거예요.', example_en_5 = 'Maybe we should ask for more information.', example_ko_5 = '아마도 더 많은 정보를 요청해야 할 것 같아요.' WHERE id = 'w_discussion_A1_07';

UPDATE words SET example_en_2 = 'Yes, that makes a lot of sense.', example_ko_2 = '네, 그건 정말 말이 돼요.', example_en_3 = 'Yes, I saw the same thing.', example_ko_3 = '네, 저도 같은 걸 봤어요.', example_en_4 = 'Yes, please go ahead and share.', example_ko_4 = '네, 어서 말씀해 주세요.', example_en_5 = 'Yes, I think we agree on this.', example_ko_5 = '네, 이 점에서는 동의하는 것 같아요.' WHERE id = 'w_discussion_A1_08';

UPDATE words SET example_en_2 = 'No, that is not what I meant.', example_ko_2 = '아니요, 그게 제가 말한 게 아니에요.', example_en_3 = 'No, I have not heard that yet.', example_ko_3 = '아니요, 아직 그 얘기를 못 들었어요.', example_en_4 = 'No, we should think about it more.', example_ko_4 = '아니요, 좀 더 생각해봐야 해요.', example_en_5 = 'No, I do not think that is correct.', example_ko_5 = '아니요, 그건 맞지 않는 것 같아요.' WHERE id = 'w_discussion_A1_09';

UPDATE words SET example_en_2 = 'Am I right that we have two options?', example_ko_2 = '우리에게 두 가지 선택지가 있다는 게 맞나요?', example_en_3 = 'You are right, we need to check the data.', example_ko_3 = '맞아요, 데이터를 확인해야 해요.', example_en_4 = 'I think you are right about the schedule.', example_ko_4 = '일정에 대해 당신이 맞는 것 같아요.', example_en_5 = 'Is it right to change the plan now?', example_ko_5 = '지금 계획을 바꾸는 게 맞는 건가요?' WHERE id = 'w_discussion_A1_10';

UPDATE words SET example_en_2 = 'She gave a good presentation today.', example_ko_2 = '그녀는 오늘 좋은 발표를 했어요.', example_en_3 = 'That is a good way to solve it.', example_ko_3 = '그건 해결하는 좋은 방법이에요.', example_en_4 = 'It is good to hear different opinions.', example_ko_4 = '다양한 의견을 듣는 건 좋아요.', example_en_5 = 'What a good idea you have!', example_ko_5 = '정말 좋은 아이디어예요!' WHERE id = 'w_discussion_A1_11';

UPDATE words SET example_en_2 = 'It is a bad time to change everything.', example_ko_2 = '모든 것을 바꾸기에 나쁜 시기예요.', example_en_3 = 'Missing the meeting was a bad choice.', example_ko_3 = '회의에 빠진 건 나쁜 선택이었어요.', example_en_4 = 'He felt bad about disagreeing so loudly.', example_ko_4 = '그는 그렇게 큰 소리로 반대한 것에 미안함을 느꼈어요.', example_en_5 = 'That bad experience taught us something important.', example_ko_5 = '그 나쁜 경험이 우리에게 중요한 것을 가르쳐줬어요.' WHERE id = 'w_discussion_A1_12';

UPDATE words SET example_en_2 = 'Can we talk after the meeting?', example_ko_2 = '회의 후에 이야기할 수 있을까요?', example_en_3 = 'Let us talk about the main problem.', example_ko_3 = '주요 문제에 대해 이야기해요.', example_en_4 = 'She talked for a long time about her view.', example_ko_4 = '그녀는 자신의 견해에 대해 오랫동안 이야기했어요.', example_en_5 = 'It is good to talk before making a decision.', example_ko_5 = '결정하기 전에 이야기하는 게 좋아요.' WHERE id = 'w_discussion_A1_13';

UPDATE words SET example_en_2 = 'Can you help me find the right word?', example_ko_2 = '맞는 단어를 찾는 데 도와줄 수 있나요?', example_en_3 = 'She helped me understand the problem better.', example_ko_3 = '그녀는 제가 문제를 더 잘 이해하도록 도와줬어요.', example_en_4 = 'It helps to write down your ideas first.', example_ko_4 = '먼저 아이디어를 적어두면 도움이 돼요.', example_en_5 = 'Thank you for helping me prepare my argument.', example_ko_5 = '제 주장을 준비하는 데 도와줘서 감사해요.' WHERE id = 'w_discussion_A1_14';

UPDATE words SET example_en_2 = 'It looks like everyone has a different view.', example_ko_2 = '모두 다른 견해를 가지고 있는 것 같아요.', example_en_3 = 'Look at the problem from another angle.', example_ko_3 = '문제를 다른 각도에서 바라봐요.', example_en_4 = 'That plan looks too complicated to me.', example_ko_4 = '저에게는 그 계획이 너무 복잡해 보여요.', example_en_5 = 'The data looks very clear on this point.', example_ko_5 = '이 점에서 데이터는 매우 명확해 보여요.' WHERE id = 'w_discussion_A1_15';

UPDATE words SET example_en_2 = 'Is it true that the meeting was cancelled?', example_ko_2 = '회의가 취소된 게 사실인가요?', example_en_3 = 'That statement is simply not true.', example_ko_3 = '그 말은 단순히 사실이 아니에요.', example_en_4 = 'It is true that we need more resources.', example_ko_4 = '더 많은 자원이 필요하다는 건 사실이에요.', example_en_5 = 'Can you tell me if that is true?', example_ko_5 = '그게 사실인지 알려줄 수 있나요?' WHERE id = 'w_discussion_A1_16';

UPDATE words SET example_en_2 = 'May I ask a quick question?', example_ko_2 = '짧은 질문 하나 드려도 될까요?', example_en_3 = 'She raised an important question at the end.', example_ko_3 = '그녀는 마지막에 중요한 질문을 제기했어요.', example_en_4 = 'The question is whether we have enough time.', example_ko_4 = '문제는 우리에게 충분한 시간이 있는지예요.', example_en_5 = 'His question made everyone think deeply.', example_ko_5 = '그의 질문은 모두를 깊이 생각하게 만들었어요.' WHERE id = 'w_discussion_A1_17';

UPDATE words SET example_en_2 = 'I do not know the answer to that.', example_ko_2 = '그것에 대한 답을 모르겠어요.', example_en_3 = 'Her answer was very clear and direct.', example_ko_3 = '그녀의 답변은 매우 명확하고 직접적이었어요.', example_en_4 = 'Please give a short answer first.', example_ko_4 = '먼저 짧게 답변해 주세요.', example_en_5 = 'The answer depends on the situation.', example_ko_5 = '답변은 상황에 따라 달라져요.' WHERE id = 'w_discussion_A1_18';

UPDATE words SET example_en_2 = 'That was a great idea from you.', example_ko_2 = '당신에게서 나온 훌륭한 아이디어였어요.', example_en_3 = 'Do you have any new ideas for today?', example_ko_3 = '오늘을 위한 새로운 아이디어가 있나요?', example_en_4 = 'Her idea changed how we see the problem.', example_ko_4 = '그녀의 아이디어가 우리가 문제를 보는 방식을 바꿨어요.', example_en_5 = 'The idea sounds simple but it works well.', example_ko_5 = '그 아이디어는 단순해 보이지만 잘 작동해요.' WHERE id = 'w_discussion_A1_19';

UPDATE words SET example_en_2 = 'Please speak a little more slowly.', example_ko_2 = '조금 더 천천히 말씀해 주세요.', example_en_3 = 'Please give me time to think.', example_ko_3 = '생각할 시간을 주세요.', example_en_4 = 'Please listen before you respond.', example_ko_4 = '응답하기 전에 먼저 들어주세요.', example_en_5 = 'Please share your honest opinion.', example_ko_5 = '솔직한 의견을 나눠주세요.' WHERE id = 'w_discussion_A1_20';

UPDATE words SET example_en_2 = 'I am sorry, I did not hear you clearly.', example_ko_2 = '죄송해요, 잘 못 들었어요.', example_en_3 = 'Sorry, can you repeat that point?', example_ko_3 = '죄송하지만 그 부분을 다시 말씀해줄 수 있나요?', example_en_4 = 'I am sorry if I misunderstood you.', example_ko_4 = '잘못 이해했다면 죄송해요.', example_en_5 = 'I am sorry, but I see it differently.', example_ko_5 = '죄송하지만 저는 다르게 봐요.' WHERE id = 'w_discussion_A1_21';

UPDATE words SET example_en_2 = 'Why do you feel that way about it?', example_ko_2 = '왜 그렇게 느끼시나요?', example_en_3 = 'Why is this point so important to you?', example_ko_3 = '왜 이 부분이 당신에게 그렇게 중요한가요?', example_en_4 = 'I want to understand why you disagree.', example_ko_4 = '왜 동의하지 않는지 이해하고 싶어요.', example_en_5 = 'Why should we change the plan now?', example_ko_5 = '왜 지금 계획을 바꿔야 하나요?' WHERE id = 'w_discussion_A1_22';

UPDATE words SET example_en_2 = 'How do you feel about this topic?', example_ko_2 = '이 주제에 대해 어떻게 생각하세요?', example_en_3 = 'How can we make the discussion better?', example_ko_3 = '토론을 어떻게 더 좋게 만들 수 있을까요?', example_en_4 = 'How did you come to that conclusion?', example_ko_4 = '어떻게 그런 결론에 이르렀나요?', example_en_5 = 'How should we handle this disagreement?', example_ko_5 = '이 의견 차이를 어떻게 처리해야 할까요?' WHERE id = 'w_discussion_A1_23';

UPDATE words SET example_en_2 = 'What is your opinion on this topic?', example_ko_2 = '이 주제에 대한 당신의 의견이 뭔가요?', example_en_3 = 'What are the main reasons for that?', example_ko_3 = '그 이유가 뭔가요?', example_en_4 = 'What would you do in this situation?', example_ko_4 = '이 상황에서 어떻게 하시겠어요?', example_en_5 = 'What is the most important thing to consider?', example_ko_5 = '가장 중요하게 고려해야 할 것이 뭔가요?' WHERE id = 'w_discussion_A1_24';

UPDATE words SET example_en_2 = 'This idea came from last week''s meeting.', example_ko_2 = '이 아이디어는 지난 주 회의에서 나왔어요.', example_en_3 = 'This is the problem we need to discuss.', example_ko_3 = '이게 우리가 논의해야 할 문제예요.', example_en_4 = 'I do not understand this point fully.', example_ko_4 = '이 부분을 완전히 이해하지 못하겠어요.', example_en_5 = 'This topic is very interesting to me.', example_ko_5 = '이 주제는 저에게 매우 흥미로워요.' WHERE id = 'w_discussion_A1_25';

UPDATE words SET example_en_2 = 'Could you tell me more about your view?', example_ko_2 = '당신의 견해에 대해 더 말해줄 수 있나요?', example_en_3 = 'I need more time to think it over.', example_ko_3 = '더 생각할 시간이 필요해요.', example_en_4 = 'There is more to this issue than we see.', example_ko_4 = '이 문제에는 우리가 보는 것 이상의 것이 있어요.', example_en_5 = 'Can you give me one more example?', example_ko_5 = '예시를 하나 더 들어줄 수 있나요?' WHERE id = 'w_discussion_A1_26';

UPDATE words SET example_en_2 = 'I see it the same way as you do.', example_ko_2 = '저도 당신과 같은 방식으로 봐요.', example_en_3 = 'We reached the same conclusion in the end.', example_ko_3 = '우리는 결국 같은 결론에 이르렀어요.', example_en_4 = 'His opinion is the same as mine.', example_ko_4 = '그의 의견은 저와 같아요.', example_en_5 = 'Can we agree on the same plan?', example_ko_5 = '같은 계획에 동의할 수 있을까요?' WHERE id = 'w_discussion_A1_27';

UPDATE words SET example_en_2 = 'The two plans are very different.', example_ko_2 = '두 가지 계획은 매우 달라요.', example_en_3 = 'She has a different way of thinking.', example_ko_3 = '그녀는 다른 사고방식을 가지고 있어요.', example_en_4 = 'It is fine to have different views.', example_ko_4 = '다른 견해를 가지는 건 괜찮아요.', example_en_5 = 'Why are our conclusions so different?', example_ko_5 = '왜 우리의 결론이 이렇게 다른 걸까요?' WHERE id = 'w_discussion_A1_28';

UPDATE words SET example_en_2 = 'Anyone can share their opinion here.', example_ko_2 = '누구나 여기서 의견을 나눌 수 있어요.', example_en_3 = 'We can solve this if we work together.', example_ko_3 = '함께 하면 이것을 해결할 수 있어요.', example_en_4 = 'Can you give me an example of that?', example_ko_4 = '그것의 예시를 들어줄 수 있나요?', example_en_5 = 'You can always change your mind later.', example_ko_5 = '나중에 언제든지 마음을 바꿀 수 있어요.' WHERE id = 'w_discussion_A1_29';

UPDATE words SET example_en_2 = 'Let us start with the main question.', example_ko_2 = '주요 질문부터 시작해요.', example_en_3 = 'Let me show you what I mean.', example_ko_3 = '제가 무슨 말인지 보여드릴게요.', example_en_4 = 'Let everyone have a turn to speak.', example_ko_4 = '모두에게 말할 차례를 주세요.', example_en_5 = 'Let us not rush to a conclusion.', example_ko_5 = '결론을 서두르지 마요.' WHERE id = 'w_discussion_A1_30';

UPDATE words SET example_en_2 = 'OK, let us move on to the next point.', example_ko_2 = '알겠어요, 다음 요점으로 넘어가요.', example_en_3 = 'OK, I will try to see it your way.', example_ko_3 = '알겠어요, 당신의 방식으로 이해해볼게요.', example_en_4 = 'Is it OK if I share a different idea?', example_ko_4 = '다른 아이디어를 나눠도 괜찮을까요?', example_en_5 = 'OK, that sounds like a fair approach.', example_ko_5 = '알겠어요, 그건 공정한 접근 같아요.' WHERE id = 'w_discussion_A1_31';

UPDATE words SET example_en_2 = 'I do not think that is the right answer.', example_ko_2 = '그게 맞는 답이라고 생각하지 않아요.', example_en_3 = 'She does not want to change her view.', example_ko_3 = '그녀는 자신의 견해를 바꾸고 싶어하지 않아요.', example_en_4 = 'That is not the best way to explain it.', example_ko_4 = '그게 설명하는 가장 좋은 방법이 아니에요.', example_en_5 = 'I do not understand why you disagree.', example_ko_5 = '왜 동의하지 않는지 이해가 안 돼요.' WHERE id = 'w_discussion_A1_32';

UPDATE words SET example_en_2 = 'I see your point, but I still think otherwise.', example_ko_2 = '요점은 알겠지만 여전히 다르게 생각해요.', example_en_3 = 'The idea is simple but the problem is complex.', example_ko_3 = '아이디어는 단순하지만 문제는 복잡해요.', example_en_4 = 'She agreed at first, but then changed her mind.', example_ko_4 = '처음에는 동의했지만 그다음 마음을 바꿨어요.', example_en_5 = 'I like the plan, but I have one concern.', example_ko_5 = '계획이 마음에 들지만 한 가지 우려가 있어요.' WHERE id = 'w_discussion_A1_33';

UPDATE words SET example_en_2 = 'I said that because the data shows it.', example_ko_2 = '데이터가 보여주기 때문에 그렇게 말한 거예요.', example_en_3 = 'She stayed quiet because she was thinking.', example_ko_3 = '그녀는 생각 중이라서 조용히 있었어요.', example_en_4 = 'I changed my mind because of your argument.', example_ko_4 = '당신의 주장 때문에 마음을 바꿨어요.', example_en_5 = 'We need to talk because there is a problem.', example_ko_5 = '문제가 있기 때문에 이야기할 필요가 있어요.' WHERE id = 'w_discussion_A1_34';

UPDATE words SET example_en_2 = 'So, what is the next step for us?', example_ko_2 = '그래서 우리의 다음 단계는 뭔가요?', example_en_3 = 'She disagreed, so we talked it through.', example_ko_3 = '그녀가 동의하지 않아서 우리는 끝까지 이야기했어요.', example_en_4 = 'So, can we agree on this point?', example_ko_4 = '그래서 이 점에 동의할 수 있나요?', example_en_5 = 'I heard the feedback, so I will reconsider.', example_ko_5 = '피드백을 들었으니 다시 생각해볼게요.' WHERE id = 'w_discussion_A1_35';

