UPDATE words SET example_en_2 = 'In my opinion, we should wait a bit longer.', example_ko_2 = '제 의견으로는 조금 더 기다려야 할 것 같아요.', example_en_3 = 'What is your opinion about the new plan?', example_ko_3 = '새 계획에 대한 당신의 의견이 뭐예요?', example_en_4 = 'Everyone is entitled to their own opinion.', example_ko_4 = '누구나 자신의 의견을 가질 권리가 있어요.', example_en_5 = 'My opinion changed after hearing your point.', example_ko_5 = '당신의 요점을 듣고 나서 제 의견이 바뀌었어요.' WHERE id = 'w_discussion_A2_01';

UPDATE words SET example_en_2 = 'I would like to suggest a meeting this week.', example_ko_2 = '이번 주에 회의를 제안하고 싶어요.', example_en_3 = 'Can I suggest we take a short break?', example_ko_3 = '잠깐 쉬는 시간을 갖자고 제안해도 될까요?', example_en_4 = 'She suggested starting with the easy questions.', example_ko_4 = '그녀는 쉬운 질문부터 시작하자고 제안했어요.', example_en_5 = 'He suggested that we reconsider the deadline.', example_ko_5 = '그는 마감일을 재고해보자고 제안했어요.' WHERE id = 'w_discussion_A2_02';

UPDATE words SET example_en_2 = 'I believe we can find a good solution.', example_ko_2 = '좋은 해결책을 찾을 수 있다고 생각해요.', example_en_3 = 'Do you believe what he said?', example_ko_3 = '그가 한 말을 믿나요?', example_en_4 = 'She believes this is the right way forward.', example_ko_4 = '그녀는 이것이 옳은 방향이라고 생각해요.', example_en_5 = 'I believe open discussion leads to better ideas.', example_ko_5 = '열린 토론이 더 나은 아이디어로 이어진다고 생각해요.' WHERE id = 'w_discussion_A2_03';

UPDATE words SET example_en_2 = 'I understand why you feel that way.', example_ko_2 = '왜 그렇게 느끼시는지 이해해요.', example_en_3 = 'Do you understand what she is trying to say?', example_ko_3 = '그녀가 말하려는 걸 이해하시나요?', example_en_4 = 'It took me time to understand his point.', example_ko_4 = '그의 요점을 이해하는 데 시간이 걸렸어요.', example_en_5 = 'Please explain again so I can understand.', example_ko_5 = '이해할 수 있도록 다시 설명해 주세요.' WHERE id = 'w_discussion_A2_04';

UPDATE words SET example_en_2 = 'I disagree with your conclusion.', example_ko_2 = '당신의 결론에 동의하지 않아요.', example_en_3 = 'It is fine to disagree, as long as we are respectful.', example_ko_3 = '서로 존중하는 한 동의하지 않아도 괜찮아요.', example_en_4 = 'She disagrees but has not said why yet.', example_ko_4 = '그녀는 동의하지 않지만 아직 이유를 말하지 않았어요.', example_en_5 = 'We can disagree and still find common ground.', example_ko_5 = '동의하지 않더라도 여전히 공통점을 찾을 수 있어요.' WHERE id = 'w_discussion_A2_05';

UPDATE words SET example_en_2 = 'We need to discuss this further before deciding.', example_ko_2 = '결정하기 전에 더 논의해야 해요.', example_en_3 = 'They discussed the issue for over an hour.', example_ko_3 = '그들은 한 시간 이상 그 문제를 논의했어요.', example_en_4 = 'Let us discuss what went wrong.', example_ko_4 = '무엇이 잘못되었는지 논의해 봐요.', example_en_5 = 'Have you discussed this with your team yet?', example_ko_5 = '이미 팀과 이것에 대해 논의하셨나요?' WHERE id = 'w_discussion_A2_06';

UPDATE words SET example_en_2 = 'I see your point, but I disagree.', example_ko_2 = '당신의 요점은 알겠지만 동의하지는 않아요.', example_en_3 = 'Can you get straight to the point?', example_ko_3 = '요점만 바로 말씀해줄 수 있나요?', example_en_4 = 'The main point of her talk was very clear.', example_ko_4 = '그녀의 발표의 주요 요점은 매우 명확했어요.', example_en_5 = 'That is an interesting point worth considering.', example_ko_5 = '그건 고려할 만한 흥미로운 요점이에요.' WHERE id = 'w_discussion_A2_07';

UPDATE words SET example_en_2 = 'Can you explain your reason for thinking that?', example_ko_2 = '그렇게 생각하는 이유를 설명해줄 수 있나요?', example_en_3 = 'There is a good reason to change the plan.', example_ko_3 = '계획을 바꿀 충분한 이유가 있어요.', example_en_4 = 'What is the reason behind your decision?', example_ko_4 = '결정의 이유가 뭔가요?', example_en_5 = 'She gave several reasons to support her view.', example_ko_5 = '그녀는 자신의 견해를 뒷받침하는 몇 가지 이유를 들었어요.' WHERE id = 'w_discussion_A2_08';

UPDATE words SET example_en_2 = 'Can you give an example to explain that?', example_ko_2 = '그것을 설명하는 예시를 들어줄 수 있나요?', example_en_3 = 'For example, we could use this method instead.', example_ko_3 = '예를 들어 이 방법을 대신 사용할 수 있어요.', example_en_4 = 'Her example made the idea much clearer.', example_ko_4 = '그녀의 예시가 아이디어를 훨씬 더 명확하게 해줬어요.', example_en_5 = 'That was a perfect example of what I mean.', example_ko_5 = '그건 제가 말하는 것의 완벽한 예시예요.' WHERE id = 'w_discussion_A2_09';

UPDATE words SET example_en_2 = 'Can you explain that a bit more simply?', example_ko_2 = '조금 더 간단하게 설명해줄 수 있나요?', example_en_3 = 'He explained the problem step by step.', example_ko_3 = '그는 문제를 단계적으로 설명했어요.', example_en_4 = 'Please explain why you changed your opinion.', example_ko_4 = '왜 의견을 바꿨는지 설명해 주세요.', example_en_5 = 'She explained her argument very well.', example_ko_5 = '그녀는 자신의 주장을 매우 잘 설명했어요.' WHERE id = 'w_discussion_A2_10';

UPDATE words SET example_en_2 = 'What do you mean by "fair"?', example_ko_2 = '"공정하다"는 게 무슨 뜻인가요?', example_en_3 = 'I mean that we should listen more.', example_ko_3 = '더 많이 들어야 한다는 말이에요.', example_en_4 = 'That word can mean different things.', example_ko_4 = '그 단어는 다른 의미를 가질 수 있어요.', example_en_5 = 'What do you really mean by that comment?', example_ko_5 = '그 발언으로 정말 무슨 말을 하는 건가요?' WHERE id = 'w_discussion_A2_11';

UPDATE words SET example_en_2 = 'I was wrong to rush my decision.', example_ko_2 = '결정을 서두른 건 잘못됐어요.', example_en_3 = 'That information is completely wrong.', example_ko_3 = '그 정보는 완전히 틀렸어요.', example_en_4 = 'What went wrong with our plan?', example_ko_4 = '우리 계획의 어디가 잘못됐나요?', example_en_5 = 'You are not wrong, but there is more to it.', example_ko_5 = '틀리진 않았지만 더 있는 내용이 있어요.' WHERE id = 'w_discussion_A2_12';

UPDATE words SET example_en_2 = 'Your figures are correct according to the report.', example_ko_2 = '보고서에 따르면 당신의 수치는 맞아요.', example_en_3 = 'Is my understanding of this correct?', example_ko_3 = '이것에 대한 제 이해가 맞나요?', example_en_4 = 'Please tell me if my answer is correct.', example_ko_4 = '제 답이 맞는지 알려주세요.', example_en_5 = 'She gave the correct response right away.', example_ko_5 = '그녀는 바로 올바른 대답을 했어요.' WHERE id = 'w_discussion_A2_13';

UPDATE words SET example_en_2 = 'The real problem is a lack of communication.', example_ko_2 = '진짜 문제는 소통 부족이에요.', example_en_3 = 'How can we solve this problem together?', example_ko_3 = '이 문제를 어떻게 함께 해결할 수 있을까요?', example_en_4 = 'The problem with that idea is the cost.', example_ko_4 = '그 아이디어의 문제는 비용이에요.', example_en_5 = 'I see a problem with your reasoning.', example_ko_5 = '당신의 논리에서 문제가 보여요.' WHERE id = 'w_discussion_A2_14';

UPDATE words SET example_en_2 = 'We found a good solution at the end.', example_ko_2 = '결국 좋은 해결책을 찾았어요.', example_en_3 = 'The solution must work for everyone.', example_ko_3 = '해결책은 모두에게 효과적이어야 해요.', example_en_4 = 'Her solution was creative and practical.', example_ko_4 = '그녀의 해결책은 창의적이고 실용적이었어요.', example_en_5 = 'Do you have any solution in mind for this?', example_ko_5 = '이것을 위해 생각해둔 해결책이 있나요?' WHERE id = 'w_discussion_A2_15';

UPDATE words SET example_en_2 = 'Both arguments have strong and weak points.', example_ko_2 = '두 주장 모두 강점과 약점이 있어요.', example_en_3 = 'Both of us need to be willing to compromise.', example_ko_3 = '우리 둘 다 타협할 의향이 있어야 해요.', example_en_4 = 'I can see merit in both approaches.', example_ko_4 = '두 접근법 모두에서 장점을 볼 수 있어요.', example_en_5 = 'Both sides should listen carefully.', example_ko_5 = '양쪽 모두 주의 깊게 들어야 해요.' WHERE id = 'w_discussion_A2_16';

UPDATE words SET example_en_2 = 'It is important to be honest in a discussion.', example_ko_2 = '토론에서 솔직한 게 중요해요.', example_en_3 = 'This step is the most important one.', example_ko_3 = '이 단계가 가장 중요한 거예요.', example_en_4 = 'She made an important point about timing.', example_ko_4 = '그녀는 타이밍에 관한 중요한 지적을 했어요.', example_en_5 = 'It is important to stay on topic.', example_ko_5 = '주제에서 벗어나지 않는 게 중요해요.' WHERE id = 'w_discussion_A2_17';

UPDATE words SET example_en_2 = 'This approach is better than the last one.', example_ko_2 = '이 접근법이 지난번 것보다 나아요.', example_en_3 = 'I think the second option is better.', example_ko_3 = '두 번째 선택지가 더 낫다고 생각해요.', example_en_4 = 'Do you have a better idea?', example_ko_4 = '더 나은 아이디어가 있나요?', example_en_5 = 'Her suggestion was much better than mine.', example_ko_5 = '그녀의 제안이 제 것보다 훨씬 나았어요.' WHERE id = 'w_discussion_A2_18';

UPDATE words SET example_en_2 = 'I want to make my position clear.', example_ko_2 = '제 입장을 명확히 하고 싶어요.', example_en_3 = 'Is the meeting schedule clear to everyone?', example_ko_3 = '회의 일정이 모두에게 명확한가요?', example_en_4 = 'Please be clear about what you need.', example_ko_4 = '필요한 것에 대해 명확하게 말씀해 주세요.', example_en_5 = 'Her explanation was clear and easy to follow.', example_ko_5 = '그녀의 설명은 명확하고 따라가기 쉬웠어요.' WHERE id = 'w_discussion_A2_19';

UPDATE words SET example_en_2 = 'I feel like we are missing the main point.', example_ko_2 = '주요 요점을 놓치고 있는 것 같아요.', example_en_3 = 'How do you feel about the final decision?', example_ko_3 = '최종 결정에 대해 어떻게 느끼시나요?', example_en_4 = 'She feels that her opinion was ignored.', example_ko_4 = '그녀는 자신의 의견이 무시됐다고 느껴요.', example_en_5 = 'I feel we should discuss this more.', example_ko_5 = '이것에 대해 더 논의해야 한다는 느낌이 들어요.' WHERE id = 'w_discussion_A2_20';

UPDATE words SET example_en_2 = 'I am not sure I understood that correctly.', example_ko_2 = '제가 올바르게 이해했는지 잘 모르겠어요.', example_en_3 = 'Are you sure about that information?', example_ko_3 = '그 정보에 대해 확신하시나요?', example_en_4 = 'She is sure her answer is right.', example_ko_4 = '그녀는 자신의 답이 맞다고 확신해요.', example_en_5 = 'I am not sure we have enough time.', example_ko_5 = '우리에게 충분한 시간이 있는지 모르겠어요.' WHERE id = 'w_discussion_A2_21';

UPDATE words SET example_en_2 = 'Can we figure this out together?', example_ko_2 = '함께 이걸 해결할 수 있을까요?', example_en_3 = 'We work better when we discuss together.', example_ko_3 = '함께 논의할 때 더 잘 돼요.', example_en_4 = 'Let us write the summary together.', example_ko_4 = '함께 요약을 작성해 봐요.', example_en_5 = 'They came to a decision together after a long talk.', example_ko_5 = '긴 이야기 끝에 그들은 함께 결론에 이르렀어요.' WHERE id = 'w_discussion_A2_22';

UPDATE words SET example_en_2 = 'Let us compare the two ideas side by side.', example_ko_2 = '두 아이디어를 나란히 비교해 봐요.', example_en_3 = 'Comparing options helps us make better choices.', example_ko_3 = '선택지를 비교하면 더 나은 선택을 할 수 있어요.', example_en_4 = 'How do these two plans compare in terms of cost?', example_ko_4 = '이 두 계획은 비용 면에서 어떻게 비교되나요?', example_en_5 = 'She compared her approach with the traditional method.', example_ko_5 = '그녀는 자신의 접근법과 전통적인 방법을 비교했어요.' WHERE id = 'w_discussion_A2_23';

UPDATE words SET example_en_2 = 'We need to choose one direction and stick with it.', example_ko_2 = '한 방향을 선택해서 그것을 고수해야 해요.', example_en_3 = 'I chose to support her idea in the end.', example_ko_3 = '저는 결국 그녀의 아이디어를 지지하기로 선택했어요.', example_en_4 = 'How do you choose between two good options?', example_ko_4 = '두 가지 좋은 선택지 사이에서 어떻게 선택하나요?', example_en_5 = 'The group chose the simplest solution available.', example_ko_5 = '그룹은 가장 간단한 해결책을 선택했어요.' WHERE id = 'w_discussion_A2_24';

UPDATE words SET example_en_2 = 'Things change quickly in this field.', example_ko_2 = '이 분야에서는 상황이 빠르게 변해요.', example_en_3 = 'He changed his position after listening carefully.', example_ko_3 = '그는 신중하게 듣고 나서 입장을 바꿨어요.', example_en_4 = 'Is it too late to change our approach?', example_ko_4 = '접근 방식을 바꾸기엔 너무 늦었나요?', example_en_5 = 'Why did you change your opinion so quickly?', example_ko_5 = '왜 그렇게 빨리 의견을 바꾸셨나요?' WHERE id = 'w_discussion_A2_25';

UPDATE words SET example_en_2 = 'What is the main purpose of this discussion?', example_ko_2 = '이 토론의 주된 목적이 뭔가요?', example_en_3 = 'Focus on the main idea first.', example_ko_3 = '먼저 주된 아이디어에 집중해요.', example_en_4 = 'Her main concern was about the timeline.', example_ko_4 = '그녀의 주된 우려는 타임라인에 관한 것이었어요.', example_en_5 = 'The main advantage of this plan is its simplicity.', example_ko_5 = '이 계획의 주된 장점은 단순함이에요.' WHERE id = 'w_discussion_A2_26';

UPDATE words SET example_en_2 = 'Can you prove that your method is more effective?', example_ko_2 = '당신의 방법이 더 효과적임을 증명할 수 있나요?', example_en_3 = 'She proved her point with real examples.', example_ko_3 = '그녀는 실제 예시로 자신의 요점을 증명했어요.', example_en_4 = 'It is hard to prove something without evidence.', example_ko_4 = '증거 없이 무언가를 증명하기는 어려워요.', example_en_5 = 'How would you prove that claim?', example_ko_5 = '그 주장을 어떻게 증명하시겠어요?' WHERE id = 'w_discussion_A2_27';

UPDATE words SET example_en_2 = 'Let us discuss only the facts.', example_ko_2 = '사실만을 가지고 논의해요.', example_en_3 = 'That is a fact, not just an opinion.', example_ko_3 = '그건 단순한 의견이 아니라 사실이에요.', example_en_4 = 'We should check the facts before concluding.', example_ko_4 = '결론 내리기 전에 사실을 확인해야 해요.', example_en_5 = 'The fact that she agreed changed everything.', example_ko_5 = '그녀가 동의했다는 사실이 모든 것을 바꿨어요.' WHERE id = 'w_discussion_A2_28';

UPDATE words SET example_en_2 = 'Please keep an open mind during the talk.', example_ko_2 = '이야기하는 동안 열린 마음을 유지해 주세요.', example_en_3 = 'I changed my mind after reading more.', example_ko_3 = '더 읽고 나서 마음을 바꿨어요.', example_en_4 = 'Do you mind if I offer a different view?', example_ko_4 = '다른 견해를 제시해도 괜찮을까요?', example_en_5 = 'Having an open mind makes discussion more productive.', example_ko_5 = '열린 마음을 갖는 것이 토론을 더 생산적으로 만들어요.' WHERE id = 'w_discussion_A2_29';

UPDATE words SET example_en_2 = 'Please share your thoughts on the matter.', example_ko_2 = '그 문제에 대한 생각을 나눠주세요.', example_en_3 = 'I would like to share a personal experience.', example_ko_3 = '개인적인 경험을 나누고 싶어요.', example_en_4 = 'We should share information openly with each other.', example_ko_4 = '서로 정보를 솔직하게 나눠야 해요.', example_en_5 = 'She shared some useful feedback after the meeting.', example_ko_5 = '그녀는 회의 후에 유용한 피드백을 나눠줬어요.' WHERE id = 'w_discussion_A2_30';

UPDATE words SET example_en_2 = 'Try to focus on the positive side of the plan.', example_ko_2 = '계획의 긍정적인 면에 집중해보세요.', example_en_3 = 'Her positive attitude helped the team stay motivated.', example_ko_3 = '그녀의 긍정적인 태도가 팀이 동기를 유지하는 데 도움이 됐어요.', example_en_4 = 'There is a positive outcome from every discussion.', example_ko_4 = '모든 토론에서 긍정적인 결과가 있어요.', example_en_5 = 'I received a lot of positive feedback on my idea.', example_ko_5 = '제 아이디어에 대해 많은 긍정적인 피드백을 받았어요.' WHERE id = 'w_discussion_A2_31';

UPDATE words SET example_en_2 = 'The negative response surprised everyone.', example_ko_2 = '부정적인 반응이 모두를 놀라게 했어요.', example_en_3 = 'Try not to focus only on the negative aspects.', example_ko_3 = '부정적인 면에만 집중하지 않으려고 해요.', example_en_4 = 'We have to address the negative feedback too.', example_ko_4 = '부정적인 피드백도 다뤄야 해요.', example_en_5 = 'Negative criticism can still be helpful if it is fair.', example_ko_5 = '공정하다면 부정적인 비판도 도움이 될 수 있어요.' WHERE id = 'w_discussion_A2_32';

UPDATE words SET example_en_2 = 'Let us hear both sides of the argument.', example_ko_2 = '논쟁의 양쪽을 모두 들어봐요.', example_en_3 = 'I understand your side, but I still disagree.', example_ko_3 = '당신의 입장은 이해하지만 여전히 동의하지 않아요.', example_en_4 = 'Which side do you think is more convincing?', example_ko_4 = '어느 쪽이 더 설득력 있다고 생각해요?', example_en_5 = 'Each side needs to respect the other.', example_ko_5 = '각 입장은 상대방을 존중해야 해요.' WHERE id = 'w_discussion_A2_33';

UPDATE words SET example_en_2 = 'I would like to hear your view on this.', example_ko_2 = '이것에 대한 당신의 견해를 듣고 싶어요.', example_en_3 = 'Her view on the issue was very insightful.', example_ko_3 = '그 문제에 대한 그녀의 견해는 매우 통찰력 있었어요.', example_en_4 = 'Do you have a clear view of what we need?', example_ko_4 = '우리가 무엇이 필요한지 명확한 견해가 있나요?', example_en_5 = 'My view changed after we spoke.', example_ko_5 = '우리가 이야기한 후 제 견해가 바뀌었어요.' WHERE id = 'w_discussion_A2_34';

UPDATE words SET example_en_2 = 'How did she respond to the criticism?', example_ko_2 = '그녀는 비판에 어떻게 반응했나요?', example_en_3 = 'Please respond to each point carefully.', example_ko_3 = '각 요점에 신중하게 응답해 주세요.', example_en_4 = 'He responded quickly and clearly to the question.', example_ko_4 = '그는 질문에 빠르고 명확하게 응답했어요.', example_en_5 = 'I did not know how to respond at first.', example_ko_5 = '처음에는 어떻게 응답해야 할지 몰랐어요.' WHERE id = 'w_discussion_A2_35';

