UPDATE words SET example_en_2 = 'He argues that the policy needs to change.', example_ko_2 = '그는 정책이 바뀌어야 한다고 주장해요.', example_en_3 = 'I would argue that the cost is too high.', example_ko_3 = '비용이 너무 높다고 주장하고 싶어요.', example_en_4 = 'They argued for hours without reaching an agreement.', example_ko_4 = '그들은 합의에 이르지 못한 채 몇 시간을 논쟁했어요.', example_en_5 = 'Can you argue against that position convincingly?', example_ko_5 = '그 입장에 설득력 있게 반론할 수 있나요?' WHERE id = 'w_discussion_B1_01';

UPDATE words SET example_en_2 = 'From a different perspective, the plan looks risky.', example_ko_2 = '다른 관점에서 보면 그 계획은 위험해 보여요.', example_en_3 = 'Try to see things from her perspective.', example_ko_3 = '그녀의 관점에서 사물을 바라보려고 해요.', example_en_4 = 'Each team member brought a unique perspective.', example_ko_4 = '각 팀원이 독특한 관점을 제시했어요.', example_en_5 = 'A global perspective helps us understand the issue better.', example_ko_5 = '글로벌 관점이 우리가 문제를 더 잘 이해하는 데 도움이 돼요.' WHERE id = 'w_discussion_B1_02';

UPDATE words SET example_en_2 = 'There is strong evidence that the plan works.', example_ko_2 = '그 계획이 효과적이라는 강력한 증거가 있어요.', example_en_3 = 'Without evidence, your argument is weak.', example_ko_3 = '증거가 없으면 당신의 주장은 약해요.', example_en_4 = 'The evidence contradicts the original claim.', example_ko_4 = '증거가 원래 주장과 모순돼요.', example_en_5 = 'Please present your evidence before drawing a conclusion.', example_ko_5 = '결론을 내리기 전에 증거를 제시해 주세요.' WHERE id = 'w_discussion_B1_03';

UPDATE words SET example_en_2 = 'I will support your argument if you have evidence.', example_ko_2 = '증거가 있다면 당신의 주장을 지지할게요.', example_en_3 = 'The research supports the conclusion we reached.', example_ko_3 = '연구가 우리가 내린 결론을 뒷받침해요.', example_en_4 = 'Can you find data to support your claim?', example_ko_4 = '주장을 뒷받침할 데이터를 찾을 수 있나요?', example_en_5 = 'His examples strongly supported the argument.', example_ko_5 = '그의 예시들이 주장을 강하게 뒷받침했어요.' WHERE id = 'w_discussion_B1_04';

UPDATE words SET example_en_2 = 'She quickly countered his point with new data.', example_ko_2 = '그녀는 새 데이터로 그의 요점에 빠르게 반론했어요.', example_en_3 = 'How would you counter that argument?', example_ko_3 = '그 주장에 어떻게 반론하시겠어요?', example_en_4 = 'He countered every objection with a calm explanation.', example_ko_4 = '그는 침착한 설명으로 모든 반대를 반론했어요.', example_en_5 = 'It is difficult to counter a well-supported argument.', example_ko_5 = '잘 뒷받침된 주장에 반론하기는 어려워요.' WHERE id = 'w_discussion_B1_05';

UPDATE words SET example_en_2 = 'His stance on the issue has not changed.', example_ko_2 = '그 문제에 대한 그의 입장은 바뀌지 않았어요.', example_en_3 = 'What is her current stance on the proposal?', example_ko_3 = '그 제안에 대한 그녀의 현재 입장이 뭔가요?', example_en_4 = 'I had to reconsider my stance after seeing the data.', example_ko_4 = '데이터를 보고 나서 제 입장을 다시 생각해야 했어요.', example_en_5 = 'Taking a firm stance can strengthen your argument.', example_ko_5 = '확고한 입장을 취하면 주장이 강해질 수 있어요.' WHERE id = 'w_discussion_B1_06';

UPDATE words SET example_en_2 = 'Could you elaborate on your proposal?', example_ko_2 = '제안에 대해 좀 더 자세히 설명해 주실 수 있나요?', example_en_3 = 'She elaborated on her idea with several examples.', example_ko_3 = '그녀는 여러 예시로 자신의 아이디어를 자세히 설명했어요.', example_en_4 = 'Please elaborate on what you mean by "fair".', example_ko_4 = '"공정하다"는 말의 의미를 자세히 설명해 주세요.', example_en_5 = 'He was asked to elaborate, so he gave more details.', example_ko_5 = '더 자세히 설명해달라는 요청에 그는 세부 사항을 더 말했어요.' WHERE id = 'w_discussion_B1_07';

UPDATE words SET example_en_2 = 'That claim needs to be backed up by facts.', example_ko_2 = '그 주장은 사실로 뒷받침되어야 해요.', example_en_3 = 'Her main claim is that the system is broken.', example_ko_3 = '그녀의 주된 주장은 시스템이 고장났다는 거예요.', example_en_4 = 'Do not make a claim you cannot prove.', example_ko_4 = '증명할 수 없는 주장을 하지 마세요.', example_en_5 = 'His claim about the results was challenged by others.', example_ko_5 = '결과에 대한 그의 주장은 다른 사람들에게 도전을 받았어요.' WHERE id = 'w_discussion_B1_08';

UPDATE words SET example_en_2 = 'We should respect different viewpoints in this discussion.', example_ko_2 = '이 토론에서 다양한 관점을 존중해야 해요.', example_en_3 = 'Her viewpoint helped me see the problem differently.', example_ko_3 = '그녀의 관점이 문제를 다르게 보는 데 도움이 됐어요.', example_en_4 = 'Sharing your viewpoint clearly is very important.', example_ko_4 = '관점을 명확하게 나누는 게 매우 중요해요.', example_en_5 = 'From that viewpoint, the solution makes sense.', example_ko_5 = '그 관점에서 보면 해결책이 말이 돼요.' WHERE id = 'w_discussion_B1_09';

UPDATE words SET example_en_2 = 'The debate about the new policy lasted all day.', example_ko_2 = '새 정책에 관한 토론이 하루 종일 계속됐어요.', example_en_3 = 'There is a big debate over how to proceed.', example_ko_3 = '어떻게 진행할지에 대한 큰 토론이 있어요.', example_en_4 = 'Both teams prepared well for the debate.', example_ko_4 = '두 팀 모두 토론을 잘 준비했어요.', example_en_5 = 'The debate was heated, but everyone stayed respectful.', example_ko_5 = '토론이 치열했지만 모두가 예의를 지켰어요.' WHERE id = 'w_discussion_B1_10';

UPDATE words SET example_en_2 = 'I acknowledge that my argument was not perfect.', example_ko_2 = '제 주장이 완벽하지 않았음을 인정해요.', example_en_3 = 'She acknowledged the difficulty of the situation.', example_ko_3 = '그녀는 상황의 어려움을 인정했어요.', example_en_4 = 'We acknowledge that there are other ways to look at this.', example_ko_4 = '이것을 바라보는 다른 방식이 있음을 인정해요.', example_en_5 = 'Please acknowledge receipt of this information.', example_ko_5 = '이 정보를 받았음을 확인해 주세요.' WHERE id = 'w_discussion_B1_11';

UPDATE words SET example_en_2 = 'I want to challenge the assumption behind that.', example_ko_2 = '그 뒤에 있는 가정에 이의를 제기하고 싶어요.', example_en_3 = 'He challenged her view with a counter-example.', example_ko_3 = '그는 반례로 그녀의 견해에 이의를 제기했어요.', example_en_4 = 'It is good to challenge your own thinking.', example_ko_4 = '자신의 생각에 의문을 제기하는 게 좋아요.', example_en_5 = 'She was not afraid to challenge the popular view.', example_ko_5 = '그녀는 인기 있는 견해에 이의를 제기하는 것을 두려워하지 않았어요.' WHERE id = 'w_discussion_B1_12';

UPDATE words SET example_en_2 = 'It is important to make a logical argument.', example_ko_2 = '논리적인 주장을 하는 게 중요해요.', example_en_3 = 'That step does not seem logical to me.', example_ko_3 = '그 단계는 저에게 논리적으로 보이지 않아요.', example_en_4 = 'A logical thinker considers all the facts.', example_ko_4 = '논리적인 사람은 모든 사실을 고려해요.', example_en_5 = 'Your conclusion seems logical given the evidence.', example_ko_5 = '증거를 감안하면 당신의 결론은 논리적으로 보여요.' WHERE id = 'w_discussion_B1_13';

UPDATE words SET example_en_2 = 'What do you conclude from this information?', example_ko_2 = '이 정보에서 무엇을 결론 내리시나요?', example_en_3 = 'We concluded that both sides have valid points.', example_ko_3 = '양쪽 모두 타당한 요점이 있다는 결론을 내렸어요.', example_en_4 = 'The report concludes with a set of recommendations.', example_ko_4 = '보고서는 일련의 권고 사항으로 결론을 맺어요.', example_en_5 = 'I concluded that further discussion was needed.', example_ko_5 = '추가적인 논의가 필요하다고 결론 내렸어요.' WHERE id = 'w_discussion_B1_14';

UPDATE words SET example_en_2 = 'Do not assume that everyone agrees with you.', example_ko_2 = '모두가 당신에게 동의한다고 가정하지 마세요.', example_en_3 = 'She assumed the other person understood her point.', example_ko_3 = '그녀는 상대방이 자신의 요점을 이해했다고 가정했어요.', example_en_4 = 'I assumed the data was correct, but it was not.', example_ko_4 = '데이터가 맞다고 가정했지만 그렇지 않았어요.', example_en_5 = 'We should not assume without checking first.', example_ko_5 = '먼저 확인하지 않고 가정해서는 안 돼요.' WHERE id = 'w_discussion_B1_15';

UPDATE words SET example_en_2 = 'That information is not relevant to our topic.', example_ko_2 = '그 정보는 우리 주제와 관련이 없어요.', example_en_3 = 'Please only share relevant examples.', example_ko_3 = '관련 있는 예시만 나눠주세요.', example_en_4 = 'How is that comment relevant to the discussion?', example_ko_4 = '그 발언이 토론과 어떻게 관련이 있나요?', example_en_5 = 'She made sure all her arguments were relevant.', example_ko_5 = '그녀는 모든 주장이 관련이 있는지 확인했어요.' WHERE id = 'w_discussion_B1_16';

UPDATE words SET example_en_2 = 'That is a valid reason to change the plan.', example_ko_2 = '그건 계획을 바꿀 타당한 이유예요.', example_en_3 = 'Your concern is valid and I take it seriously.', example_ko_3 = '당신의 우려는 타당하며 진지하게 받아들여요.', example_en_4 = 'Is this argument still valid given the new data?', example_ko_4 = '새 데이터를 감안하면 이 주장이 여전히 유효한가요?', example_en_5 = 'She made a valid point about the deadline.', example_ko_5 = '그녀는 마감일에 관해 타당한 지적을 했어요.' WHERE id = 'w_discussion_B1_17';

UPDATE words SET example_en_2 = 'We should consider the impact on everyone involved.', example_ko_2 = '관련된 모든 사람에게 미치는 영향을 고려해야 해요.', example_en_3 = 'Have you considered the other side of the argument?', example_ko_3 = '논쟁의 다른 측면을 고려해봤나요?', example_en_4 = 'Please consider my suggestion before deciding.', example_ko_4 = '결정하기 전에 제 제안을 고려해 주세요.', example_en_5 = 'She considered every option before making a choice.', example_ko_5 = '그녀는 선택하기 전에 모든 선택지를 고려했어요.' WHERE id = 'w_discussion_B1_18';

UPDATE words SET example_en_2 = 'May I raise a concern about the timeline?', example_ko_2 = '타임라인에 관한 우려를 제기해도 될까요?', example_en_3 = 'He raised the question of who is responsible.', example_ko_3 = '그는 누가 책임이 있는지에 대한 질문을 제기했어요.', example_en_4 = 'She raised her hand to share her opinion.', example_ko_4 = '그녀는 의견을 나누기 위해 손을 들었어요.', example_en_5 = 'The speaker raised several important issues.', example_ko_5 = '발표자는 몇 가지 중요한 문제를 제기했어요.' WHERE id = 'w_discussion_B1_19';

UPDATE words SET example_en_2 = 'She convinced me with a strong argument.', example_ko_2 = '그녀는 강력한 주장으로 저를 설득했어요.', example_en_3 = 'I am not convinced that this is the right way.', example_ko_3 = '이것이 옳은 방법이라고 확신하지 못해요.', example_en_4 = 'It is hard to convince someone without evidence.', example_ko_4 = '증거 없이 누군가를 설득하기는 어려워요.', example_en_5 = 'He convinced the group to try a new approach.', example_ko_5 = '그는 그룹이 새 접근법을 시도하도록 설득했어요.' WHERE id = 'w_discussion_B1_20';

UPDATE words SET example_en_2 = 'Let me summarize what we have discussed so far.', example_ko_2 = '지금까지 논의한 내용을 요약해 드릴게요.', example_en_3 = 'Can you summarize the main arguments briefly?', example_ko_3 = '주요 주장을 간략하게 요약해줄 수 있나요?', example_en_4 = 'He summarized the key takeaways at the end.', example_ko_4 = '그는 마지막에 핵심 내용을 요약했어요.', example_en_5 = 'She summarized the debate in just a few sentences.', example_ko_5 = '그녀는 토론을 몇 문장으로 요약했어요.' WHERE id = 'w_discussion_B1_21';

UPDATE words SET example_en_2 = 'We need an objective assessment of the situation.', example_ko_2 = '상황에 대한 객관적인 평가가 필요해요.', example_en_3 = 'It is hard to be objective when you are personally involved.', example_ko_3 = '개인적으로 연관되어 있을 때 객관적이기는 어려워요.', example_en_4 = 'Her objective analysis helped us make a better decision.', example_ko_4 = '그녀의 객관적인 분석이 더 나은 결정을 내리는 데 도움이 됐어요.', example_en_5 = 'Try to be as objective as possible in your review.', example_ko_5 = '검토할 때 가능한 한 객관적으로 하려고 해요.' WHERE id = 'w_discussion_B1_22';

UPDATE words SET example_en_2 = 'That judgment is highly subjective.', example_ko_2 = '그 판단은 매우 주관적이에요.', example_en_3 = 'Art appreciation is naturally subjective.', example_ko_3 = '예술 감상은 본질적으로 주관적이에요.', example_en_4 = 'Your rating is too subjective to be useful here.', example_ko_4 = '당신의 평가는 여기서 유용하기엔 너무 주관적이에요.', example_en_5 = 'Let us separate subjective feelings from objective facts.', example_ko_5 = '주관적인 감정과 객관적인 사실을 분리해 봐요.' WHERE id = 'w_discussion_B1_23';

UPDATE words SET example_en_2 = 'Without context, this statement sounds alarming.', example_ko_2 = '맥락 없이 이 발언은 놀라운 것처럼 들려요.', example_en_3 = 'We need to understand the historical context first.', example_ko_3 = '먼저 역사적 맥락을 이해해야 해요.', example_en_4 = 'In the context of this discussion, that is relevant.', example_ko_4 = '이 토론의 맥락에서 그건 관련이 있어요.', example_en_5 = 'Context really matters when interpreting someone''s words.', example_ko_5 = '누군가의 말을 해석할 때 맥락이 정말 중요해요.' WHERE id = 'w_discussion_B1_24';

UPDATE words SET example_en_2 = 'What did you imply with that remark?', example_ko_2 = '그 발언으로 무엇을 암시했나요?', example_en_3 = 'Are you implying that I am wrong?', example_ko_3 = '제가 틀렸다고 암시하시는 건가요?', example_en_4 = 'Her silence implied she was not happy.', example_ko_4 = '그녀의 침묵은 그녀가 기쁘지 않다는 것을 암시했어요.', example_en_5 = 'The data implies that our approach needs to change.', example_ko_5 = '데이터는 우리의 접근 방식이 바뀌어야 한다는 것을 암시해요.' WHERE id = 'w_discussion_B1_25';

UPDATE words SET example_en_2 = 'The impact of this change on the team is significant.', example_ko_2 = '이 변화가 팀에 미치는 영향은 상당해요.', example_en_3 = 'What impact will this policy have on consumers?', example_ko_3 = '이 정책이 소비자에게 어떤 영향을 미칠까요?', example_en_4 = 'Her speech had a great impact on the audience.', example_ko_4 = '그녀의 연설은 청중에게 큰 영향을 미쳤어요.', example_en_5 = 'Consider the long-term impact before deciding.', example_ko_5 = '결정하기 전에 장기적인 영향을 고려해요.' WHERE id = 'w_discussion_B1_26';

UPDATE words SET example_en_2 = 'He strongly opposes the new regulations.', example_ko_2 = '그는 새 규정에 강하게 반대해요.', example_en_3 = 'She opposes changing the plan at this stage.', example_ko_3 = '그녀는 이 단계에서 계획 변경에 반대해요.', example_en_4 = 'I do not oppose the idea, but I have concerns.', example_ko_4 = '그 아이디어에 반대하지는 않지만 우려가 있어요.', example_en_5 = 'They opposed the decision, so a vote was held.', example_ko_5 = '그들이 결정에 반대해서 투표가 진행됐어요.' WHERE id = 'w_discussion_B1_27';

UPDATE words SET example_en_2 = 'She maintained her position throughout the discussion.', example_ko_2 = '그녀는 토론 내내 자신의 입장을 유지했어요.', example_en_3 = 'He maintains that the original plan was better.', example_ko_3 = '그는 원래 계획이 더 좋았다는 주장을 유지해요.', example_en_4 = 'I maintain that the evidence supports my view.', example_ko_4 = '증거가 제 견해를 지지한다는 주장을 유지해요.', example_en_5 = 'It is hard to maintain your argument under pressure.', example_ko_5 = '압박 아래서 주장을 유지하기는 어려워요.' WHERE id = 'w_discussion_B1_28';

UPDATE words SET example_en_2 = 'I want to emphasize that safety is the priority.', example_ko_2 = '안전이 최우선임을 강조하고 싶어요.', example_en_3 = 'She emphasized the need for more data.', example_ko_3 = '그녀는 더 많은 데이터의 필요성을 강조했어요.', example_en_4 = 'Let me emphasize this point one more time.', example_ko_4 = '이 부분을 한 번 더 강조할게요.', example_en_5 = 'He emphasized that everyone should be heard.', example_ko_5 = '그는 모두의 의견이 들려야 한다는 것을 강조했어요.' WHERE id = 'w_discussion_B1_29';

UPDATE words SET example_en_2 = 'The rules should be fair for everyone.', example_ko_2 = '규칙은 모두에게 공정해야 해요.', example_en_3 = 'Is it fair to change the rules in the middle?', example_ko_3 = '중간에 규칙을 바꾸는 게 공정한가요?', example_en_4 = 'She wanted a fair chance to present her view.', example_ko_4 = '그녀는 자신의 견해를 발표할 공정한 기회를 원했어요.', example_en_5 = 'Let us make sure the process is fair and transparent.', example_ko_5 = '과정이 공정하고 투명한지 확인해요.' WHERE id = 'w_discussion_B1_30';

UPDATE words SET example_en_2 = 'I have to admit that I was mistaken.', example_ko_2 = '제가 잘못됐다는 걸 인정해야 해요.', example_en_3 = 'He admitted that his argument had flaws.', example_ko_3 = '그는 자신의 주장에 결함이 있음을 인정했어요.', example_en_4 = 'Admitting a mistake takes courage.', example_ko_4 = '실수를 인정하는 건 용기가 필요해요.', example_en_5 = 'She admitted she had not read the full report.', example_ko_5 = '그녀는 전체 보고서를 읽지 않았다는 것을 인정했어요.' WHERE id = 'w_discussion_B1_31';

UPDATE words SET example_en_2 = 'Do you have any alternatives to suggest?', example_ko_2 = '제안할 대안이 있나요?', example_en_3 = 'We should explore alternative ways to solve this.', example_ko_3 = '이것을 해결하는 대안적 방법을 탐색해야 해요.', example_en_4 = 'An alternative approach might work better.', example_ko_4 = '대안적 접근법이 더 잘 작동할 수도 있어요.', example_en_5 = 'If that does not work, what is the alternative?', example_ko_5 = '그것이 효과가 없다면 대안이 뭔가요?' WHERE id = 'w_discussion_B1_32';

UPDATE words SET example_en_2 = 'I propose we start with a smaller test.', example_ko_2 = '더 작은 테스트부터 시작하자고 제안해요.', example_en_3 = 'She proposed a new way to organize the meeting.', example_ko_3 = '그녀는 회의를 조직하는 새로운 방법을 제안했어요.', example_en_4 = 'What solution would you propose for this problem?', example_ko_4 = '이 문제를 위해 어떤 해결책을 제안하시겠어요?', example_en_5 = 'He proposed a vote to settle the disagreement.', example_ko_5 = '그는 의견 차이를 해결하기 위해 투표를 제안했어요.' WHERE id = 'w_discussion_B1_33';

UPDATE words SET example_en_2 = 'Let us reflect on how the discussion went.', example_ko_2 = '토론이 어떻게 진행됐는지 돌이켜봐요.', example_en_3 = 'Her attitude reflects a very open mindset.', example_ko_3 = '그녀의 태도는 매우 열린 사고방식을 반영해요.', example_en_4 = 'I reflected on the feedback and made changes.', example_ko_4 = '피드백을 돌이켜보고 변화를 줬어요.', example_en_5 = 'His comment reflects his personal experience.', example_ko_5 = '그의 발언은 그의 개인적인 경험을 반영해요.' WHERE id = 'w_discussion_B1_34';

UPDATE words SET example_en_2 = 'The exchange of ideas made the meeting productive.', example_ko_2 = '아이디어 교환이 회의를 생산적으로 만들었어요.', example_en_3 = 'We had a lively exchange of views.', example_ko_3 = '우리는 활발한 견해 교환을 했어요.', example_en_4 = 'This kind of exchange helps us grow intellectually.', example_ko_4 = '이런 교환은 우리가 지적으로 성장하는 데 도움이 돼요.', example_en_5 = 'After a brief exchange, both sides understood better.', example_ko_5 = '짧은 교환 후에 양쪽 모두 더 잘 이해하게 됐어요.' WHERE id = 'w_discussion_B1_35';

