UPDATE words SET example_en_2 = 'The dialectic between tradition and innovation drives progress.', example_ko_2 = '전통과 혁신 사이의 변증법이 진보를 이끌어요.', example_en_3 = 'She applied Socratic dialectic to reveal hidden assumptions.', example_ko_3 = '그녀는 소크라테스식 변증법을 적용해 숨겨진 가정을 드러냈어요.', example_en_4 = 'The dialectic of the debate forced both sides to refine their views.', example_ko_4 = '토론의 변증법이 양쪽이 견해를 다듬도록 강요했어요.', example_en_5 = 'Understanding dialectic is key to rigorous philosophical inquiry.', example_ko_5 = '변증법을 이해하는 것이 엄밀한 철학적 탐구의 핵심이에요.' WHERE id = 'w_discussion_C1_01';

UPDATE words SET example_en_2 = 'She argued the proposition that freedom requires responsibility.', example_ko_2 = '그녀는 자유는 책임을 필요로 한다는 명제를 주장했어요.', example_en_3 = 'Let us examine each proposition before accepting it.', example_ko_3 = '각 명제를 받아들이기 전에 검토해봐요.', example_en_4 = 'His proposition was provocative but logically sound.', example_ko_4 = '그의 명제는 도발적이었지만 논리적으로 건전했어요.', example_en_5 = 'The proposition that all knowledge is uncertain was debated.', example_ko_5 = '모든 지식은 불확실하다는 명제가 토론됐어요.' WHERE id = 'w_discussion_C1_02';

UPDATE words SET example_en_2 = 'All men are mortal — this syllogism is a classic example.', example_ko_2 = '모든 사람은 죽는다 — 이 삼단논법은 고전적인 예시예요.', example_en_3 = 'Her argument followed a valid syllogism from premise to conclusion.', example_ko_3 = '그녀의 주장은 전제에서 결론까지 유효한 삼단논법을 따랐어요.', example_en_4 = 'A flaw in one premise invalidates the entire syllogism.', example_ko_4 = '전제 하나의 결함이 전체 삼단논법을 무효화해요.', example_en_5 = 'Aristotle formalized the syllogism as a tool of logic.', example_ko_5 = '아리스토텔레스는 삼단논법을 논리의 도구로 형식화했어요.' WHERE id = 'w_discussion_C1_03';

UPDATE words SET example_en_2 = 'Epistemology examines the sources and limits of human knowledge.', example_ko_2 = '인식론은 인간 지식의 원천과 한계를 탐구해요.', example_en_3 = 'The epistemology of science is a fascinating field.', example_ko_3 = '과학의 인식론은 매혹적인 분야예요.', example_en_4 = 'Her thesis touched on the epistemology of belief.', example_ko_4 = '그녀의 논문은 믿음의 인식론을 다뤘어요.', example_en_5 = 'Debates about truth often have a deep epistemological dimension.', example_ko_5 = '진리에 관한 토론에는 종종 깊은 인식론적 차원이 있어요.' WHERE id = 'w_discussion_C1_04';

UPDATE words SET example_en_2 = 'His argument was clever but full of sophistry.', example_ko_2 = '그의 주장은 영리했지만 궤변으로 가득했어요.', example_en_3 = 'She exposed the sophistry behind his confident claims.', example_ko_3 = '그녀는 그의 자신감 있는 주장 뒤의 궤변을 폭로했어요.', example_en_4 = 'Sophistry can mislead audiences who are not thinking critically.', example_ko_4 = '궤변은 비판적으로 생각하지 않는 청중을 오도할 수 있어요.', example_en_5 = 'True logic is different from the art of sophistry.', example_ko_5 = '진정한 논리는 궤변의 기술과 달라요.' WHERE id = 'w_discussion_C1_05';

UPDATE words SET example_en_2 = 'It is an axiom that no argument can be both true and false.', example_ko_2 = '어떤 주장도 동시에 참이고 거짓일 수 없다는 건 공리예요.', example_en_3 = 'The mathematician accepted that as an axiom and built from there.', example_ko_3 = '수학자는 그것을 공리로 받아들이고 거기서부터 구축했어요.', example_en_4 = 'Not every axiom is as self-evident as it seems.', example_ko_4 = '모든 공리가 보이는 것만큼 자명한 건 아니에요.', example_en_5 = 'Questioning accepted axioms can lead to new discoveries.', example_ko_5 = '받아들여진 공리에 의문을 제기하면 새로운 발견으로 이어질 수 있어요.' WHERE id = 'w_discussion_C1_06';

UPDATE words SET example_en_2 = 'Inductive reasoning builds general theories from observations.', example_ko_2 = '귀납적 추론은 관찰로부터 일반 이론을 구축해요.', example_en_3 = 'Her inductive argument was convincing but not conclusive.', example_ko_3 = '그녀의 귀납적 주장은 설득력 있었지만 결정적이지는 않았어요.', example_en_4 = 'An inductive approach is common in social science research.', example_ko_4 = '귀납적 접근법은 사회 과학 연구에서 흔해요.', example_en_5 = 'Inductive logic cannot guarantee certainty, only probability.', example_ko_5 = '귀납적 논리는 확실성이 아닌 개연성만을 보장할 수 있어요.' WHERE id = 'w_discussion_C1_07';

UPDATE words SET example_en_2 = 'Deductive reasoning starts with a universal truth.', example_ko_2 = '연역적 추론은 보편적 진리에서 시작해요.', example_en_3 = 'His deductive argument was valid but the premise was wrong.', example_ko_3 = '그의 연역적 주장은 유효했지만 전제가 틀렸어요.', example_en_4 = 'A deductive approach is often used in formal logic.', example_ko_4 = '연역적 접근법은 형식 논리에서 자주 사용돼요.', example_en_5 = 'Deductive reasoning can give certain conclusions — if the premises hold.', example_ko_5 = '연역적 추론은 확실한 결론을 내릴 수 있어요 — 전제가 맞다면요.' WHERE id = 'w_discussion_C1_08';

UPDATE words SET example_en_2 = 'His theory postulates a link between language and thought.', example_ko_2 = '그의 이론은 언어와 사고 사이의 연결을 가정해요.', example_en_3 = 'The model postulates that all agents act rationally.', example_ko_3 = '그 모델은 모든 행위자가 합리적으로 행동한다고 가정해요.', example_en_4 = 'She postulated a mechanism that has since been proven.', example_ko_4 = '그녀는 이후 증명된 메커니즘을 가정했어요.', example_en_5 = 'What this theory postulates remains open to verification.', example_ko_5 = '이 이론이 가정하는 것은 여전히 검증의 여지가 있어요.' WHERE id = 'w_discussion_C1_09';

UPDATE words SET example_en_2 = 'His refutation of the popular theory was groundbreaking.', example_ko_2 = '인기 있는 이론에 대한 그의 반박은 획기적이었어요.', example_en_3 = 'A successful refutation requires more than disagreement.', example_ko_3 = '성공적인 반박은 단순한 의견 불일치 이상의 것이 필요해요.', example_en_4 = 'She prepared a thorough refutation of each claim.', example_ko_4 = '그녀는 각 주장에 대한 철저한 반박을 준비했어요.', example_en_5 = 'The refutation was so strong that no one could counter it.', example_ko_5 = '그 반박은 너무 강력해서 아무도 반론할 수 없었어요.' WHERE id = 'w_discussion_C1_10';

UPDATE words SET example_en_2 = 'She presented a cogent argument for restructuring the team.', example_ko_2 = '그녀는 팀 구조조정을 위한 설득력 있는 주장을 제시했어요.', example_en_3 = 'A cogent explanation helps win the trust of an audience.', example_ko_3 = '설득력 있는 설명은 청중의 신뢰를 얻는 데 도움이 돼요.', example_en_4 = 'His defense was cogent and well-supported by facts.', example_ko_4 = '그의 변론은 설득력 있었고 사실로 잘 뒷받침됐어요.', example_en_5 = 'To be cogent, an argument must be both valid and relevant.', example_ko_5 = '설득력 있으려면 주장이 유효하고 관련성이 있어야 해요.' WHERE id = 'w_discussion_C1_11';

UPDATE words SET example_en_2 = 'Her pedantic insistence on minor details slowed the discussion.', example_ko_2 = '사소한 세부 사항에 대한 그녀의 현학적인 고집이 토론을 늦췄어요.', example_en_3 = 'A pedantic reading misses the spirit of the argument.', example_ko_3 = '현학적인 독해는 주장의 정신을 놓쳐요.', example_en_4 = 'He was criticized for being too pedantic in his critique.', example_ko_4 = '그는 비평에서 지나치게 현학적이라는 비판을 받았어요.', example_en_5 = 'Pedantic comments about formatting distracted from the core debate.', example_ko_5 = '형식에 대한 현학적인 발언이 핵심 토론에서 주의를 분산시켰어요.' WHERE id = 'w_discussion_C1_12';

UPDATE words SET example_en_2 = 'Without data, his claim remains mere conjecture.', example_ko_2 = '데이터 없이는 그의 주장은 단순한 추측에 불과해요.', example_en_3 = 'Her conjecture turned out to be surprisingly accurate.', example_ko_3 = '그녀의 추측이 놀랍도록 정확했어요.', example_en_4 = 'Conjecture is useful in early stages but must be tested.', example_ko_4 = '추측은 초기 단계에서 유용하지만 검증되어야 해요.', example_en_5 = 'I do not want to argue from conjecture alone.', example_ko_5 = '추측만으로 주장하고 싶지 않아요.' WHERE id = 'w_discussion_C1_13';

UPDATE words SET example_en_2 = 'The false dichotomy between reason and emotion limits thinking.', example_ko_2 = '이성과 감정 사이의 잘못된 이분법은 사고를 제한해요.', example_en_3 = 'This debate creates a dichotomy that is not really there.', example_ko_3 = '이 토론은 실제로 존재하지 않는 이분법을 만들어요.', example_en_4 = 'She challenged the classic dichotomy between nature and nurture.', example_ko_4 = '그녀는 본성과 양육 사이의 고전적인 이분법에 이의를 제기했어요.', example_en_5 = 'Reducing the issue to a dichotomy oversimplifies reality.', example_ko_5 = '문제를 이분법으로 환원하면 현실을 지나치게 단순화해요.' WHERE id = 'w_discussion_C1_14';

UPDATE words SET example_en_2 = 'Saying "the result is a result of the outcome" is a tautology.', example_ko_2 = '"결과는 결말의 결과다"라고 말하는 건 동어반복이에요.', example_en_3 = 'His definition was circular — a classic tautology.', example_ko_3 = '그의 정의는 순환적이었어요 — 고전적인 동어반복이에요.', example_en_4 = 'Avoid tautology by making sure each sentence adds something new.', example_ko_4 = '각 문장이 새로운 것을 추가하는지 확인해 동어반복을 피해요.', example_en_5 = 'The argument collapsed because it was essentially a tautology.', example_ko_5 = '주장이 본질적으로 동어반복이었기 때문에 무너졌어요.' WHERE id = 'w_discussion_C1_15';

UPDATE words SET example_en_2 = 'That question presupposes we all share the same goal.', example_ko_2 = '그 질문은 우리 모두가 같은 목표를 공유한다는 것을 전제로 해요.', example_en_3 = 'His argument presupposes a level of trust that does not exist.', example_ko_3 = '그의 주장은 존재하지 않는 수준의 신뢰를 전제로 해요.', example_en_4 = 'We should examine what the theory presupposes before accepting it.', example_ko_4 = '이론을 받아들이기 전에 그것이 무엇을 전제로 하는지 검토해야 해요.', example_en_5 = 'The debate presupposes that both parties want a resolution.', example_ko_5 = '그 토론은 양쪽 모두 해결을 원한다는 것을 전제로 해요.' WHERE id = 'w_discussion_C1_16';

UPDATE words SET example_en_2 = 'Calling it "just politics" is a reductive explanation.', example_ko_2 = '그걸 "단지 정치"라고 부르는 건 환원주의적 설명이에요.', example_en_3 = 'His analysis was reductive and failed to capture complexity.', example_ko_3 = '그의 분석은 환원주의적이었고 복잡성을 포착하지 못했어요.', example_en_4 = 'A reductive framework can mislead as much as it illuminates.', example_ko_4 = '환원주의적 틀은 밝히는 만큼 오도할 수 있어요.', example_en_5 = 'She challenged the reductive portrayal of the issue in the media.', example_ko_5 = '그녀는 미디어의 그 문제에 대한 환원주의적 묘사에 이의를 제기했어요.' WHERE id = 'w_discussion_C1_17';

UPDATE words SET example_en_2 = 'His evidence seemed plausible but was actually specious.', example_ko_2 = '그의 증거는 그럴듯해 보였지만 실제로는 잘못된 것이었어요.', example_en_3 = 'A specious argument fools those who do not look closely.', example_ko_3 = '그럴듯한 주장은 자세히 들여다보지 않는 사람들을 속여요.', example_en_4 = 'She identified the specious reasoning buried in his appeal.', example_ko_4 = '그녀는 그의 호소 속에 묻혀 있는 그럴듯한 논리를 발견했어요.', example_en_5 = 'Specious logic may sound convincing but cannot survive scrutiny.', example_ko_5 = '그럴듯한 논리는 설득력 있게 들릴 수 있지만 면밀한 검토를 견디지 못해요.' WHERE id = 'w_discussion_C1_18';

UPDATE words SET example_en_2 = 'His comment was tangential to the main topic.', example_ko_2 = '그의 발언은 주제에서 벗어난 이야기였어요.', example_en_3 = 'Tangential remarks slow down productive discussion.', example_ko_3 = '본론에서 벗어난 발언은 생산적인 토론을 늦춰요.', example_en_4 = 'The tangential point, while interesting, was not relevant.', example_ko_4 = '그 주변적 요점은 흥미롭긴 했지만 관련성이 없었어요.', example_en_5 = 'She gently redirected the tangential conversation back on topic.', example_ko_5 = '그녀는 본론에서 벗어난 대화를 부드럽게 주제로 되돌렸어요.' WHERE id = 'w_discussion_C1_19';

UPDATE words SET example_en_2 = 'Allow me to iterate the main argument one more time.', example_ko_2 = '주요 주장을 한 번 더 반복해 드릴게요.', example_en_3 = 'We iterate over our ideas to make them stronger.', example_ko_3 = '아이디어를 더 강하게 만들기 위해 반복적으로 검토해요.', example_en_4 = 'She iterated her position clearly to avoid any confusion.', example_ko_4 = '그녀는 혼란을 피하기 위해 자신의 입장을 분명하게 반복했어요.', example_en_5 = 'The design team iterated until they had a solid solution.', example_ko_5 = '디자인 팀은 견고한 해결책을 찾을 때까지 반복했어요.' WHERE id = 'w_discussion_C1_20';

UPDATE words SET example_en_2 = 'His entire argument is predicated on a false assumption.', example_ko_2 = '그의 전체 주장은 잘못된 가정에 근거해 있어요.', example_en_3 = 'The policy is predicated on the belief that growth is always good.', example_ko_3 = '그 정책은 성장이 항상 좋다는 믿음에 근거하고 있어요.', example_en_4 = 'Success is predicated on thorough preparation.', example_ko_4 = '성공은 철저한 준비에 달려 있어요.', example_en_5 = 'She challenged the premises on which the argument was predicated.', example_ko_5 = '그녀는 주장이 근거하는 전제들에 이의를 제기했어요.' WHERE id = 'w_discussion_C1_21';

UPDATE words SET example_en_2 = 'A neutral third party was brought in to arbitrate the dispute.', example_ko_2 = '중립적인 제3자가 분쟁을 중재하도록 불려왔어요.', example_en_3 = 'The board agreed to arbitrate rather than litigate.', example_ko_3 = '이사회는 소송보다 중재하기로 동의했어요.', example_en_4 = 'It is difficult to arbitrate when emotions run high.', example_ko_4 = '감정이 격해지면 중재하기 어려워요.', example_en_5 = 'They asked her to arbitrate between the competing proposals.', example_ko_5 = '그들은 그녀에게 경쟁하는 제안들 사이를 중재해달라고 했어요.' WHERE id = 'w_discussion_C1_22';

UPDATE words SET example_en_2 = 'Can we reconcile these two conflicting theories?', example_ko_2 = '이 두 가지 상충하는 이론들을 조화시킬 수 있을까요?', example_en_3 = 'He tried to reconcile his personal values with the group''s goals.', example_ko_3 = '그는 자신의 개인적 가치와 그룹의 목표를 조화시키려 했어요.', example_en_4 = 'Reconciling opposing views is the mark of a good mediator.', example_ko_4 = '상반된 견해를 조화시키는 것이 좋은 중재자의 표시예요.', example_en_5 = 'They could not reconcile their differences, so they agreed to disagree.', example_ko_5 = '그들은 차이를 조화시킬 수 없어서 의견 차이를 인정하기로 했어요.' WHERE id = 'w_discussion_C1_23';

UPDATE words SET example_en_2 = 'Does this evidence really warrant such a strong conclusion?', example_ko_2 = '이 증거가 정말 그렇게 강한 결론을 정당화하나요?', example_en_3 = 'The results do not warrant the level of alarm he expressed.', example_ko_3 = '결과는 그가 표현한 수준의 경보를 정당화하지 않아요.', example_en_4 = 'Only sufficient evidence warrants a definitive claim.', example_ko_4 = '충분한 증거만이 확정적인 주장을 정당화해요.', example_en_5 = 'What warrants you to make such a bold assertion?', example_ko_5 = '그렇게 대담한 주장을 할 근거가 무엇인가요?' WHERE id = 'w_discussion_C1_24';

UPDATE words SET example_en_2 = 'We should not extrapolate global trends from a single case.', example_ko_2 = '단일 사례에서 글로벌 트렌드를 추론해서는 안 돼요.', example_en_3 = 'She extrapolated the findings to predict future behavior.', example_ko_3 = '그녀는 발견 내용을 미래 행동을 예측하는 데 추론했어요.', example_en_4 = 'Extrapolating beyond the data is risky without caution.', example_ko_4 = '데이터를 넘어서 추론하는 건 주의 없이는 위험해요.', example_en_5 = 'He extrapolated carefully and noted the limits of his inference.', example_ko_5 = '그는 신중하게 추론하고 추론의 한계를 명시했어요.' WHERE id = 'w_discussion_C1_25';

UPDATE words SET example_en_2 = 'A nuanced reading of the text reveals hidden tensions.', example_ko_2 = '텍스트를 섬세하게 읽으면 숨겨진 긴장감이 드러나요.', example_en_3 = 'Her opinion on the issue was nuanced and difficult to summarize.', example_ko_3 = '그 문제에 대한 그녀의 의견은 섬세해서 요약하기 어려웠어요.', example_en_4 = 'A nuanced approach acknowledges complexity without being vague.', example_ko_4 = '섬세한 접근법은 모호하지 않으면서도 복잡성을 인정해요.', example_en_5 = 'Nuanced thinking is harder but leads to better conclusions.', example_ko_5 = '섬세한 사고는 더 어렵지만 더 나은 결론으로 이어져요.' WHERE id = 'w_discussion_C1_26';

UPDATE words SET example_en_2 = 'She made a categorical denial of all the allegations.', example_ko_2 = '그녀는 모든 혐의를 단호하게 부인했어요.', example_en_3 = 'He offered a categorical refusal to negotiate.', example_ko_3 = '그는 협상을 단호하게 거부했어요.', example_en_4 = 'A categorical statement leaves no room for ambiguity.', example_ko_4 = '단호한 진술은 모호함의 여지를 남기지 않아요.', example_en_5 = 'Is your objection categorical or conditional?', example_ko_5 = '당신의 반대는 단호한 건가요, 조건부인가요?' WHERE id = 'w_discussion_C1_27';

UPDATE words SET example_en_2 = 'She invoked the principle of free speech in her defense.', example_ko_2 = '그녀는 방어에서 언론의 자유 원칙을 들먹였어요.', example_en_3 = 'He invoked historical precedent to support his claim.', example_ko_3 = '그는 주장을 뒷받침하기 위해 역사적 선례를 원용했어요.', example_en_4 = 'You should not invoke authority without proper context.', example_ko_4 = '적절한 맥락 없이 권위를 들먹여서는 안 돼요.', example_en_5 = 'The philosopher invoked Kant to support his argument.', example_ko_5 = '철학자는 주장을 뒷받침하기 위해 칸트를 원용했어요.' WHERE id = 'w_discussion_C1_28';

UPDATE words SET example_en_2 = 'Let me deconstruct each premise of your argument.', example_ko_2 = '당신 주장의 각 전제를 분석해 볼게요.', example_en_3 = 'She deconstructed the popular narrative with precision.', example_ko_3 = '그녀는 인기 있는 서사를 정밀하게 해체했어요.', example_en_4 = 'Deconstructing an argument reveals its hidden assumptions.', example_ko_4 = '주장을 해체하면 숨겨진 가정이 드러나요.', example_en_5 = 'He was skilled at deconstructing complex theories.', example_ko_5 = '그는 복잡한 이론을 해체하는 데 능숙했어요.' WHERE id = 'w_discussion_C1_29';

UPDATE words SET example_en_2 = 'There are epistemic limits to what any theory can claim.', example_ko_2 = '어떤 이론도 주장할 수 있는 것에는 인식론적 한계가 있어요.', example_en_3 = 'The epistemic status of this claim is unclear.', example_ko_3 = '이 주장의 인식론적 지위는 불명확해요.', example_en_4 = 'She raised an epistemic objection to the method.', example_ko_4 = '그녀는 방법에 대한 인식론적 반대 의견을 제기했어요.', example_en_5 = 'The debate touched on deep epistemic questions about certainty.', example_ko_5 = '토론은 확실성에 관한 깊은 인식론적 질문을 다뤘어요.' WHERE id = 'w_discussion_C1_30';

UPDATE words SET example_en_2 = 'Do not impute bad intentions to those who simply disagree.', example_ko_2 = '단순히 동의하지 않는 사람들에게 나쁜 의도를 귀속시키지 마세요.', example_en_3 = 'He imputed the failure to management''s poor planning.', example_ko_3 = '그는 실패를 경영진의 나쁜 계획 탓으로 돌렸어요.', example_en_4 = 'It is unfair to impute motives without clear evidence.', example_ko_4 = '명확한 증거 없이 동기를 귀속시키는 건 불공정해요.', example_en_5 = 'She was careful not to impute ignorance to the opposing side.', example_ko_5 = '그녀는 반대편에게 무지를 귀속시키지 않도록 주의했어요.' WHERE id = 'w_discussion_C1_31';

UPDATE words SET example_en_2 = 'The modality of the claim shifted from possible to certain.', example_ko_2 = '그 주장의 양상이 가능성에서 확실성으로 바뀌었어요.', example_en_3 = 'In logic, modality refers to necessity and possibility.', example_ko_3 = '논리에서 양상은 필연성과 가능성을 가리켜요.', example_en_4 = 'He was inconsistent in the modality of his claims.', example_ko_4 = '그는 주장의 양상에서 일관성이 없었어요.', example_en_5 = 'Attending to modality helps us distinguish strong from weak claims.', example_ko_5 = '양상에 주의를 기울이면 강한 주장과 약한 주장을 구별하는 데 도움이 돼요.' WHERE id = 'w_discussion_C1_32';

UPDATE words SET example_en_2 = 'She was absolved of any wrongdoing after the investigation.', example_ko_2 = '그녀는 조사 후 어떤 잘못에서도 면제됐어요.', example_en_3 = 'You cannot simply absolve yourself of moral responsibility.', example_ko_3 = '도덕적 책임에서 단순히 자신을 면제할 수는 없어요.', example_en_4 = 'He sought to be absolved by apologizing publicly.', example_ko_4 = '그는 공개 사과를 통해 책임을 벗으려 했어요.', example_en_5 = 'Absolving the argument of its flaws requires more than good intentions.', example_ko_5 = '주장의 결함을 면제하려면 선의 이상의 것이 필요해요.' WHERE id = 'w_discussion_C1_33';

UPDATE words SET example_en_2 = 'She interpolated her own reading into the original text.', example_ko_2 = '그녀는 원문에 자신의 독해를 끼워 넣었어요.', example_en_3 = 'Do not interpolate meaning that is not clearly stated.', example_ko_3 = '명확하게 기술되지 않은 의미를 끼워 넣지 마세요.', example_en_4 = 'He interpolated a phrase into the quote, changing its meaning.', example_ko_4 = '그는 인용문에 어구를 끼워 넣어 의미를 바꿨어요.', example_en_5 = 'The editor was criticized for interpolating commentary into the data.', example_ko_5 = '편집자는 데이터에 논평을 끼워 넣은 것으로 비판받았어요.' WHERE id = 'w_discussion_C1_34';

UPDATE words SET example_en_2 = 'She is writing her dissertation on the ethics of AI.', example_ko_2 = '그녀는 AI 윤리에 관한 논문을 쓰고 있어요.', example_en_3 = 'A dissertation must present an original argument.', example_ko_3 = '논문은 독창적인 주장을 제시해야 해요.', example_en_4 = 'His dissertation challenged a long-held assumption in the field.', example_ko_4 = '그의 논문은 그 분야에서 오래 지지된 가정에 도전했어요.', example_en_5 = 'She defended her dissertation before a panel of experts.', example_ko_5 = '그녀는 전문가 패널 앞에서 논문을 발표하고 심사를 받았어요.' WHERE id = 'w_discussion_C1_35';

