UPDATE words SET example_en_2 = 'Her salary covers all her living expenses with a little left over.', example_ko_2 = '그녀의 급여는 모든 생활비를 충당하고 약간 남아요.', example_en_3 = 'He negotiated a higher salary before accepting the job offer.', example_ko_3 = '그는 취업 제안을 수락하기 전에 더 높은 급여를 협상했어요.', example_en_4 = 'Salary is important, but so is work-life balance.', example_ko_4 = '급여도 중요하지만 일과 삶의 균형도 중요해요.', example_en_5 = 'A competitive salary helps companies attract talented employees.', example_ko_5 = '경쟁력 있는 급여는 회사가 유능한 직원을 유치하는 데 도움이 돼요.' WHERE id = 'w_economy_A2_10';

