UPDATE words SET example_en_2 = 'A lower interest rate encourages people to borrow and spend.', example_ko_2 = '낮은 금리는 사람들이 빌려서 소비하도록 장려해요.', example_en_3 = 'The interest rate on my mortgage went up this year.', example_ko_3 = '올해 내 주택 담보 대출 금리가 올랐어요.', example_en_4 = 'Changes in the interest rate affect the whole economy.', example_ko_4 = '금리 변화는 경제 전체에 영향을 미쳐요.', example_en_5 = 'The central bank cut the interest rate to stimulate growth.', example_ko_5 = '중앙은행이 성장을 자극하기 위해 금리를 내렸어요.' WHERE id = 'w_economy_B1_03';

