UPDATE words SET example_en_2 = 'The company maintained strong liquidity despite the economic downturn.', example_ko_2 = '경기 침체에도 불구하고 회사는 강한 유동성을 유지했어요.', example_en_3 = 'Property is a good investment but it lacks liquidity.', example_ko_3 = '부동산은 좋은 투자이지만 유동성이 부족해요.', example_en_4 = 'Central banks inject liquidity into the market during crises.', example_ko_4 = '중앙은행들은 위기 중에 시장에 유동성을 주입해요.', example_en_5 = 'Investors moved to cash to improve their liquidity during the uncertainty.', example_ko_5 = '투자자들은 불확실한 시기에 유동성을 높이기 위해 현금으로 이동했어요.' WHERE id = 'w_economy_B2_03';

UPDATE words SET example_en_2 = 'Equity markets around the world fell sharply on the news.', example_ko_2 = '소식에 전 세계 주식 시장이 급락했어요.', example_en_3 = 'Investing in equity carries higher risk but also higher potential returns.', example_ko_3 = '주식에 투자하는 것은 더 높은 위험과 함께 더 높은 잠재 수익도 있어요.', example_en_4 = 'The startup founders gave up some equity in exchange for funding.', example_ko_4 = '스타트업 창업자들은 자금 조달 대가로 일부 지분을 포기했어요.', example_en_5 = 'Home equity can be used as collateral to secure a loan.', example_ko_5 = '주택 자기자본은 대출 담보로 사용될 수 있어요.' WHERE id = 'w_economy_B2_04';

UPDATE words SET example_en_2 = 'Airlines hedge against rising fuel costs using forward contracts.', example_ko_2 = '항공사들은 선물 계약을 사용하여 연료비 상승 위험을 분산해요.', example_en_3 = 'She decided to hedge her currency exposure before the trip.', example_ko_3 = '그녀는 여행 전에 환노출 위험을 분산하기로 결정했어요.', example_en_4 = 'Buying gold is a common way to hedge against inflation.', example_ko_4 = '금을 사는 것은 인플레이션에 대비한 흔한 위험 분산 방법이에요.', example_en_5 = 'Smart investors hedge their bets rather than putting everything in one place.', example_ko_5 = '현명한 투자자들은 모든 것을 한 곳에 넣기보다 위험을 분산해요.' WHERE id = 'w_economy_B2_05';

UPDATE words SET example_en_2 = 'His portfolio includes stocks, bonds, and real estate.', example_ko_2 = '그의 포트폴리오에는 주식, 채권, 부동산이 포함되어 있어요.', example_en_3 = 'A well-balanced portfolio reduces exposure to market volatility.', example_ko_3 = '균형 잡힌 포트폴리오는 시장 변동성에 대한 노출을 줄여요.', example_en_4 = 'She reviewed her portfolio with a financial advisor once a year.', example_ko_4 = '그녀는 재정 고문과 함께 1년에 한 번 포트폴리오를 검토했어요.', example_en_5 = 'During the crash, many investors saw the value of their portfolios drop sharply.', example_ko_5 = '폭락 시 많은 투자자들이 포트폴리오 가치가 급락하는 것을 봤어요.' WHERE id = 'w_economy_B2_06';

UPDATE words SET example_en_2 = 'She invested in government bonds for a stable, low-risk return.', example_ko_2 = '그녀는 안정적이고 낮은 위험의 수익을 위해 국채에 투자했어요.', example_en_3 = 'Bond prices fall when interest rates rise.', example_ko_3 = '금리가 오르면 채권 가격이 하락해요.', example_en_4 = 'Corporate bonds offer higher yields than government bonds.', example_ko_4 = '회사채는 국채보다 더 높은 수익률을 제공해요.', example_en_5 = 'The country issued bonds to finance infrastructure projects.', example_ko_5 = '그 나라는 인프라 프로젝트를 재원하기 위해 채권을 발행했어요.' WHERE id = 'w_economy_B2_07';

UPDATE words SET example_en_2 = 'Trading in complex derivatives requires deep financial knowledge.', example_ko_2 = '복잡한 파생상품 거래는 깊은 금융 지식이 필요해요.', example_en_3 = 'Many derivatives are designed to manage interest rate risk.', example_ko_3 = '많은 파생상품은 금리 위험을 관리하기 위해 설계돼요.', example_en_4 = 'The misuse of derivatives played a role in the 2008 financial crisis.', example_ko_4 = '파생상품의 오용이 2008년 금융 위기에서 역할을 했어요.', example_en_5 = 'Regulators have tightened rules on derivatives trading since the crisis.', example_ko_5 = '규제 기관들은 위기 이후 파생상품 거래 규칙을 강화했어요.' WHERE id = 'w_economy_B2_08';

UPDATE words SET example_en_2 = 'Gold is seen as a safe commodity in times of uncertainty.', example_ko_2 = '금은 불확실한 시기에 안전한 원자재로 여겨져요.', example_en_3 = 'Commodity prices fluctuate depending on global supply and demand.', example_ko_3 = '원자재 가격은 세계 공급과 수요에 따라 변동해요.', example_en_4 = 'Agricultural commodities like wheat are traded on global exchanges.', example_ko_4 = '밀 같은 농산물 원자재는 세계 거래소에서 거래돼요.', example_en_5 = 'Rising commodity prices added to inflationary pressure.', example_ko_5 = '원자재 가격 상승이 인플레이션 압력을 가중시켰어요.' WHERE id = 'w_economy_B2_09';

UPDATE words SET example_en_2 = 'The Nasdaq index tracks the performance of technology stocks.', example_ko_2 = 'Nasdaq 지수는 기술주의 성과를 추적해요.', example_en_3 = 'An index fund is a low-cost way to invest in the market.', example_ko_3 = '인덱스 펀드는 시장에 투자하는 저비용 방법이에요.', example_en_4 = 'The index measures the economic output of the top five hundred companies.', example_ko_4 = '그 지수는 상위 500개 회사의 경제 산출량을 측정해요.', example_en_5 = 'She tracks several economic indices to monitor market trends.', example_ko_5 = '그녀는 시장 동향을 모니터링하기 위해 여러 경제 지수를 추적해요.' WHERE id = 'w_economy_B2_10';

UPDATE words SET example_en_2 = 'Geopolitical tensions increased market volatility significantly.', example_ko_2 = '지정학적 긴장이 시장 변동성을 크게 높였어요.', example_en_3 = 'High volatility makes it difficult to predict short-term price movements.', example_ko_3 = '높은 변동성은 단기 가격 움직임을 예측하기 어렵게 만들어요.', example_en_4 = 'Some traders profit from volatility by buying and selling quickly.', example_ko_4 = '일부 트레이더들은 빠르게 사고팔아 변동성에서 수익을 얻어요.', example_en_5 = 'Currency volatility is a major concern for international businesses.', example_ko_5 = '통화 변동성은 국제 사업체들에게 주요 우려사항이에요.' WHERE id = 'w_economy_B2_11';

UPDATE words SET example_en_2 = 'The yield on ten-year government bonds rose to four percent.', example_ko_2 = '10년 만기 국채 수익률이 4%로 상승했어요.', example_en_3 = 'Higher yield usually means higher risk in the bond market.', example_ko_3 = '채권 시장에서 더 높은 수익률은 보통 더 높은 위험을 의미해요.', example_en_4 = 'She chose bonds with a higher yield to boost her income.', example_ko_4 = '그녀는 소득을 늘리기 위해 더 높은 수익률의 채권을 선택했어요.', example_en_5 = 'The yield curve inverted before the last recession.', example_ko_5 = '수익률 곡선은 지난 경기 침체 전에 역전됐어요.' WHERE id = 'w_economy_B2_12';

UPDATE words SET example_en_2 = 'The company used financial leverage to expand rapidly.', example_ko_2 = '회사는 빠른 확장을 위해 금융 레버리지를 사용했어요.', example_en_3 = 'High leverage amplifies both gains and losses.', example_ko_3 = '높은 레버리지는 이익과 손실을 모두 증폭시켜요.', example_en_4 = 'Many hedge funds use leverage to boost their potential returns.', example_ko_4 = '많은 헤지펀드들이 잠재 수익을 높이기 위해 레버리지를 사용해요.', example_en_5 = 'The bank''s excessive leverage left it vulnerable during the financial crisis.', example_ko_5 = '은행의 과도한 레버리지는 금융 위기 중에 취약하게 만들었어요.' WHERE id = 'w_economy_B2_13';

UPDATE words SET example_en_2 = 'Diversification across asset classes reduces overall portfolio risk.', example_ko_2 = '자산 클래스에 걸친 분산투자는 전체 포트폴리오 위험을 줄여요.', example_en_3 = 'Geographic diversification helps protect against regional economic downturns.', example_ko_3 = '지역적 분산투자는 지역 경기 침체로부터 보호하는 데 도움이 돼요.', example_en_4 = 'Putting all your savings in one stock is the opposite of diversification.', example_ko_4 = '모든 저축을 한 주식에 넣는 것은 분산투자의 반대예요.', example_en_5 = 'The financial advisor recommended diversification as the safest strategy.', example_ko_5 = '재정 고문은 분산투자를 가장 안전한 전략으로 권장했어요.' WHERE id = 'w_economy_B2_14';

UPDATE words SET example_en_2 = 'Many investors lost money during the bear market of 2008.', example_ko_2 = '많은 투자자들이 2008년 약세장에서 돈을 잃었어요.', example_en_3 = 'In a bear market, even quality stocks tend to decline.', example_ko_3 = '약세장에서는 우량주도 하락하는 경향이 있어요.', example_en_4 = 'She remained calm and held her positions throughout the bear market.', example_ko_4 = '그녀는 약세장 내내 침착하게 포지션을 유지했어요.', example_en_5 = 'The bear market lasted about eighteen months before recovering.', example_ko_5 = '약세장은 회복되기까지 약 18개월 지속됐어요.' WHERE id = 'w_economy_B2_15';

UPDATE words SET example_en_2 = 'The bull market of the 1990s was driven by the tech boom.', example_ko_2 = '1990년대 강세장은 기술 붐에 의해 주도됐어요.', example_en_3 = 'During a bull market, investors tend to be optimistic and take more risk.', example_ko_3 = '강세장에서 투자자들은 낙관적이고 더 많은 위험을 감수하는 경향이 있어요.', example_en_4 = 'Timing when to enter a bull market is very difficult.', example_ko_4 = '강세장에 언제 진입할지 타이밍을 잡는 것은 매우 어려워요.', example_en_5 = 'The bull market continued despite rising inflation concerns.', example_ko_5 = '강세장은 인플레이션 우려가 높아지는 가운데도 계속됐어요.' WHERE id = 'w_economy_B2_16';

UPDATE words SET example_en_2 = 'Digital assets like cryptocurrency are highly volatile.', example_ko_2 = '암호화폐 같은 디지털 자산은 변동성이 매우 커요.', example_en_3 = 'The company''s most valuable asset is its brand reputation.', example_ko_3 = '그 회사의 가장 가치 있는 자산은 브랜드 명성이에요.', example_en_4 = 'She listed all her assets before applying for a mortgage.', example_ko_4 = '주택 담보 대출을 신청하기 전에 모든 자산을 목록으로 만들었어요.', example_en_5 = 'Diversifying across different asset types is a smart strategy.', example_ko_5 = '다양한 자산 유형에 걸쳐 분산하는 것은 현명한 전략이에요.' WHERE id = 'w_economy_B2_17';

UPDATE words SET example_en_2 = 'The company''s liabilities exceeded its assets, signaling insolvency.', example_ko_2 = '회사의 부채가 자산을 초과하여 지급불능을 나타냈어요.', example_en_3 = 'Tax liabilities must be settled before the financial year ends.', example_ko_3 = '세금 채무는 회계연도가 끝나기 전에 정산되어야 해요.', example_en_4 = 'Understanding your liabilities is essential for financial planning.', example_ko_4 = '부채를 이해하는 것은 재정 계획에 필수적이에요.', example_en_5 = 'The bank reduced its liabilities by selling off non-core assets.', example_ko_5 = '은행은 비핵심 자산을 매각하여 부채를 줄였어요.' WHERE id = 'w_economy_B2_18';

UPDATE words SET example_en_2 = 'The new fiscal policy included major cuts to public spending.', example_ko_2 = '새 재정 정책에는 공공 지출의 대규모 삭감이 포함됐어요.', example_en_3 = 'Expansionary fiscal policy can help stimulate a struggling economy.', example_ko_3 = '확장적 재정 정책은 침체된 경제를 자극하는 데 도움이 될 수 있어요.', example_en_4 = 'The debate over fiscal policy often divides along political lines.', example_ko_4 = '재정 정책에 대한 논쟁은 종종 정치적 노선을 따라 나뉘어요.', example_en_5 = 'Sound fiscal policy is essential for maintaining long-term growth.', example_ko_5 = '건전한 재정 정책은 장기적 성장을 유지하는 데 필수적이에요.' WHERE id = 'w_economy_B2_19';

UPDATE words SET example_en_2 = 'Years of austerity reduced public investment in key areas.', example_ko_2 = '수년간의 긴축이 주요 분야의 공공 투자를 줄였어요.', example_en_3 = 'People took to the streets to protest the new austerity measures.', example_ko_3 = '사람들이 새 긴축 조치에 항의하기 위해 거리로 나왔어요.', example_en_4 = 'The IMF recommended austerity as a condition for financial aid.', example_ko_4 = 'IMF는 금융 지원의 조건으로 긴축을 권고했어요.', example_en_5 = 'Critics argue that austerity during recessions makes things worse.', example_ko_5 = '비평가들은 경기 침체 중의 긴축이 상황을 더 악화시킨다고 주장해요.' WHERE id = 'w_economy_B2_20';

UPDATE words SET example_en_2 = 'Currency depreciation boosted tourism by making the country cheaper to visit.', example_ko_2 = '통화 가치 하락이 방문 비용을 낮춰 관광을 활성화했어요.', example_en_3 = 'Rapid currency depreciation can trigger inflation.', example_ko_3 = '급격한 통화 가치 하락은 인플레이션을 유발할 수 있어요.', example_en_4 = 'The central bank tried to slow currency depreciation by raising rates.', example_ko_4 = '중앙은행은 금리를 올려 통화 가치 하락을 늦추려 했어요.', example_en_5 = 'Currency depreciation raised the cost of imported goods significantly.', example_ko_5 = '통화 가치 하락으로 수입품 가격이 크게 올랐어요.' WHERE id = 'w_economy_B2_21';

UPDATE words SET example_en_2 = 'Tight monetary policy was used to combat rising inflation.', example_ko_2 = '인플레이션 상승에 대응하기 위해 긴축 통화 정책이 사용됐어요.', example_en_3 = 'The committee meets every six weeks to review monetary policy.', example_ko_3 = '위원회는 6주마다 만나 통화 정책을 검토해요.', example_en_4 = 'Changes in monetary policy affect borrowing costs for businesses.', example_ko_4 = '통화 정책 변화는 기업들의 차입 비용에 영향을 미쳐요.', example_en_5 = 'Ineffective monetary policy was one cause of the prolonged recession.', example_ko_5 = '비효율적인 통화 정책이 장기 경기 침체의 한 원인이었어요.' WHERE id = 'w_economy_B2_22';

UPDATE words SET example_en_2 = 'Small-cap stocks have a lower market capitalization than large-cap stocks.', example_ko_2 = '소형주는 대형주보다 시가총액이 낮아요.', example_en_3 = 'The company''s capitalization grew tenfold in five years.', example_ko_3 = '그 회사의 시가총액이 5년 만에 10배로 성장했어요.', example_en_4 = 'Market capitalization is calculated by multiplying share price by the number of shares.', example_ko_4 = '시가총액은 주가에 주식 수를 곱해서 계산해요.', example_en_5 = 'Many Asian tech companies have seen rapid growth in capitalization.', example_ko_5 = '많은 아시아 기술 회사들이 시가총액에서 빠른 성장을 경험했어요.' WHERE id = 'w_economy_B2_23';

UPDATE words SET example_en_2 = 'Stagflation presents a dilemma because standard tools address only one problem at a time.', example_ko_2 = '스태그플레이션은 표준 도구가 한 번에 하나의 문제만 다루기 때문에 딜레마를 제시해요.', example_en_3 = 'The energy crisis of the 1970s triggered stagflation in many Western countries.', example_ko_3 = '1970년대 에너지 위기는 많은 서방 국가에서 스태그플레이션을 촉발시켰어요.', example_en_4 = 'Economists feared that the supply disruption could lead to stagflation.', example_ko_4 = '경제학자들은 공급 붕괴가 스태그플레이션으로 이어질 수 있다고 우려했어요.', example_en_5 = 'Stagflation challenges policymakers because fighting inflation can worsen unemployment.', example_ko_5 = '스태그플레이션은 인플레이션 퇴치가 실업을 악화시킬 수 있어 정책 입안자들을 어렵게 해요.' WHERE id = 'w_economy_B2_24';

UPDATE words SET example_en_2 = 'A downgrade in credit rating raised the country''s borrowing costs.', example_ko_2 = '신용 등급 강등이 그 나라의 차입 비용을 올렸어요.', example_en_3 = 'Moody''s and S&P are among the most well-known credit rating agencies.', example_ko_3 = 'Moody''s와 S&P는 가장 잘 알려진 신용 평가 기관 중 하나예요.', example_en_4 = 'Your personal credit rating affects the interest rate you are offered.', example_ko_4 = '개인 신용 등급은 제공받는 금리에 영향을 미쳐요.', example_en_5 = 'The company improved its credit rating by paying off debt early.', example_ko_5 = '회사는 빚을 일찍 갚아서 신용 등급을 높였어요.' WHERE id = 'w_economy_B2_25';

UPDATE words SET example_en_2 = 'Venture capital is essential for early-stage companies that lack revenue.', example_ko_2 = '벤처 캐피털은 수익이 없는 초기 단계 회사에 필수적이에요.', example_en_3 = 'She pitched her startup idea to several venture capital firms.', example_ko_3 = '그녀는 여러 벤처 캐피털 회사에 스타트업 아이디어를 발표했어요.', example_en_4 = 'Venture capital helped many of today''s tech giants get started.', example_ko_4 = '벤처 캐피털은 오늘날의 많은 기술 대기업들이 시작하는 데 도움이 됐어요.', example_en_5 = 'The venture capital firm took a twenty percent stake in the startup.', example_ko_5 = '벤처 캐피털 회사는 스타트업의 20%를 지분으로 취득했어요.' WHERE id = 'w_economy_B2_26';

UPDATE words SET example_en_2 = 'The company increased its dividend after reporting record profits.', example_ko_2 = '회사는 기록적인 수익을 보고한 후 배당금을 늘렸어요.', example_en_3 = 'Some investors rely on dividends as a regular source of income.', example_ko_3 = '일부 투자자들은 배당금을 정기적인 소득원으로 의존해요.', example_en_4 = 'The dividend was cut after the company reported a loss.', example_ko_4 = '회사가 손실을 보고한 후 배당금이 삭감됐어요.', example_en_5 = 'Dividend stocks are popular among conservative, income-focused investors.', example_ko_5 = '배당주는 보수적인 소득 중심 투자자들 사이에서 인기 있어요.' WHERE id = 'w_economy_B2_27';

UPDATE words SET example_en_2 = 'Hedge funds often use complex strategies that retail investors cannot access.', example_ko_2 = '헤지펀드들은 종종 일반 투자자들이 접근할 수 없는 복잡한 전략을 사용해요.', example_en_3 = 'He invested a portion of his savings in a hedge fund.', example_ko_3 = '그는 저축의 일부를 헤지펀드에 투자했어요.', example_en_4 = 'The hedge fund manager was celebrated for consistent outperformance.', example_ko_4 = '헤지펀드 매니저는 일관된 초과 성과로 높이 평가받았어요.', example_en_5 = 'Hedge funds are typically open only to accredited investors.', example_ko_5 = '헤지펀드는 일반적으로 공인 투자자들에게만 열려 있어요.' WHERE id = 'w_economy_B2_28';

UPDATE words SET example_en_2 = 'Private equity firms often restructure the companies they acquire.', example_ko_2 = '사모펀드 회사들은 종종 인수한 회사들을 구조조정해요.', example_en_3 = 'Private equity investment can accelerate the growth of a business.', example_ko_3 = '사모펀드 투자는 사업의 성장을 가속화할 수 있어요.', example_en_4 = 'The private equity firm sold its stake after doubling the company''s value.', example_ko_4 = '사모펀드 회사는 회사 가치를 두 배로 높인 후 지분을 매각했어요.', example_en_5 = 'Critics argue private equity can harm workers by cutting jobs to boost profits.', example_ko_5 = '비평가들은 사모펀드가 수익을 높이기 위해 일자리를 줄여 근로자들에게 해가 된다고 주장해요.' WHERE id = 'w_economy_B2_29';

UPDATE words SET example_en_2 = 'Trading on the stock exchange is open from nine to five on weekdays.', example_ko_2 = '주식 거래소 거래는 주중 9시부터 5시까지 열려요.', example_en_3 = 'She followed her company''s share price on the stock exchange closely.', example_ko_3 = '그녀는 주식 거래소에서 회사 주가를 면밀히 추적했어요.', example_en_4 = 'The stock exchange suspended trading after a dramatic fall.', example_ko_4 = '주식 거래소는 급격한 하락 이후 거래를 중단했어요.', example_en_5 = 'Small startups often aim to list on a major stock exchange one day.', example_ko_5 = '작은 스타트업들은 종종 언젠가 주요 주식 거래소에 상장하는 것을 목표로 해요.' WHERE id = 'w_economy_B2_30';

UPDATE words SET example_en_2 = 'The bank required collateral before approving the large business loan.', example_ko_2 = '은행은 대규모 사업 대출을 승인하기 전에 담보를 요구했어요.', example_en_3 = 'The value of the collateral must equal at least the loan amount.', example_ko_3 = '담보 가치는 최소한 대출 금액과 같아야 해요.', example_en_4 = 'He used his car as collateral to borrow money quickly.', example_ko_4 = '그는 빠르게 돈을 빌리기 위해 자동차를 담보로 사용했어요.', example_en_5 = 'If you default on the loan, the bank can seize the collateral.', example_ko_5 = '대출을 이행하지 않으면 은행이 담보를 압류할 수 있어요.' WHERE id = 'w_economy_B2_31';

UPDATE words SET example_en_2 = 'A surge in the inflation rate prompted urgent action from the central bank.', example_ko_2 = '물가상승률 급등이 중앙은행의 긴급 조치를 촉구했어요.', example_en_3 = 'The monthly inflation rate showed a small but welcome decline.', example_ko_3 = '월간 물가상승률이 작지만 반가운 하락세를 보였어요.', example_en_4 = 'A high inflation rate erodes the value of savings over time.', example_ko_4 = '높은 물가상승률은 시간이 지남에 따라 저축의 가치를 잠식해요.', example_en_5 = 'The government''s target is to keep the inflation rate below two percent.', example_ko_5 = '정부 목표는 물가상승률을 2% 이하로 유지하는 거예요.' WHERE id = 'w_economy_B2_32';

UPDATE words SET example_en_2 = 'The analyst compared the fund''s return against its benchmark.', example_ko_2 = '애널리스트는 펀드의 수익을 기준과 비교했어요.', example_en_3 = 'The new product set a benchmark for quality in the industry.', example_ko_3 = '새 제품은 업계에서 품질의 기준을 설정했어요.', example_en_4 = 'Industry benchmarks help companies assess their own performance.', example_ko_4 = '업계 기준은 회사들이 자체 성과를 평가하는 데 도움이 돼요.', example_en_5 = 'The interest rate benchmark was reformed after a manipulation scandal.', example_ko_5 = '금리 기준은 조작 스캔들 이후 개혁됐어요.' WHERE id = 'w_economy_B2_33';

UPDATE words SET example_en_2 = 'Speculation in the housing market drove prices far above their real value.', example_ko_2 = '주택 시장의 투기가 가격을 실제 가치 훨씬 위로 끌어올렸어요.', example_en_3 = 'Risky speculation led to the collapse of the investment firm.', example_ko_3 = '무모한 투기가 투자 회사의 붕괴로 이어졌어요.', example_en_4 = 'There is a fine line between smart investing and dangerous speculation.', example_ko_4 = '현명한 투자와 위험한 투기 사이에는 미세한 경계가 있어요.', example_en_5 = 'Market speculation can create bubbles that eventually burst.', example_ko_5 = '시장 투기는 결국 터지는 거품을 만들 수 있어요.' WHERE id = 'w_economy_B2_34';

UPDATE words SET example_en_2 = 'Investors who understand the economic cycle can time their moves better.', example_ko_2 = '경기 순환을 이해하는 투자자들은 투자 타이밍을 더 잘 잡을 수 있어요.', example_en_3 = 'The economic cycle typically includes boom, slowdown, recession, and recovery.', example_ko_3 = '경기 순환은 일반적으로 호황, 둔화, 침체, 회복을 포함해요.', example_en_4 = 'No one can predict the exact timing of each phase in the economic cycle.', example_ko_4 = '경기 순환의 각 단계의 정확한 타이밍은 아무도 예측할 수 없어요.', example_en_5 = 'The government tried to smooth out the peaks and troughs of the economic cycle.', example_ko_5 = '정부는 경기 순환의 고점과 저점을 완화하려고 노력했어요.' WHERE id = 'w_economy_B2_35';

