UPDATE words SET example_en_2 = 'Econometrics allows researchers to quantify the impact of policy changes.', example_ko_2 = '계량경제학은 연구자들이 정책 변화의 영향을 정량화하도록 해줘요.', example_en_3 = 'She used econometrics to determine whether education raises wages.', example_ko_3 = '그녀는 계량경제학을 사용해 교육이 임금을 높이는지 확인했어요.', example_en_4 = 'Advances in econometrics have improved our ability to analyze complex economic data.', example_ko_4 = '계량경제학의 발전이 복잡한 경제 데이터를 분석하는 능력을 향상시켰어요.', example_en_5 = 'The course introduced students to basic econometrics and regression analysis.', example_ko_5 = '그 과정은 학생들에게 기본 계량경제학과 회귀 분석을 소개했어요.' WHERE id = 'w_economy_C2_01';

UPDATE words SET example_en_2 = 'The trustee was found to have breached her fiduciary duty to the beneficiaries.', example_ko_2 = '수탁자가 수혜자들에 대한 수탁 의무를 위반한 것으로 밝혀졌어요.', example_en_3 = 'Financial advisers must prioritize their clients'' interests under fiduciary law.', example_ko_3 = '금융 고문은 수탁 법하에 고객의 이익을 우선시해야 해요.', example_en_4 = 'The fiduciary relationship between pension fund managers and beneficiaries is closely regulated.', example_ko_4 = '연금 펀드 매니저와 수혜자 사이의 수탁 관계는 엄격히 규제돼요.', example_en_5 = 'Board members have a fiduciary responsibility to act in the company''s best interests.', example_ko_5 = '이사회 구성원들은 회사의 최선의 이익을 위해 행동할 수탁 책임이 있어요.' WHERE id = 'w_economy_C2_02';

UPDATE words SET example_en_2 = 'The securitization of auto loans has grown into a major financial market.', example_ko_2 = '자동차 대출의 증권화는 주요 금융 시장으로 성장했어요.', example_en_3 = 'Securitization allows banks to free up capital by selling packaged loans.', example_ko_3 = '증권화는 은행이 패키지 대출을 판매하여 자본을 해방시킬 수 있게 해요.', example_en_4 = 'The risks of securitization were poorly understood before the financial crisis.', example_ko_4 = '증권화의 위험성은 금융 위기 전에 잘 이해되지 않았어요.', example_en_5 = 'Regulators now require greater transparency in securitization transactions.', example_ko_5 = '규제 기관들은 이제 증권화 거래에서 더 큰 투명성을 요구해요.' WHERE id = 'w_economy_C2_03';

UPDATE words SET example_en_2 = 'The bank issued collateralized loan obligations to institutional investors.', example_ko_2 = '은행은 기관 투자자들에게 담보부 대출 채무증서를 발행했어요.', example_en_3 = 'Collateralized bonds typically offer lower yields because of their reduced risk.', example_ko_3 = '담보부 채권은 위험 감소로 인해 일반적으로 더 낮은 수익률을 제공해요.', example_en_4 = 'Many investors did not fully understand the collateralized securities they purchased.', example_ko_4 = '많은 투자자들은 자신들이 구매한 담보부 증권을 완전히 이해하지 못했어요.', example_en_5 = 'Collateralized debt instruments can amplify both gains and systemic risk.', example_ko_5 = '담보부 채무 수단은 이익과 시스템 위험 모두를 증폭시킬 수 있어요.' WHERE id = 'w_economy_C2_04';

UPDATE words SET example_en_2 = 'Walmart has been accused of acting as a monopsony in the retail supply chain.', example_ko_2 = 'Walmart는 소매 공급망에서 수요 독점으로 행동한다는 비난을 받아왔어요.', example_en_3 = 'A monopsony in the labor market can keep wages artificially low.', example_ko_3 = '노동 시장에서의 수요 독점은 임금을 인위적으로 낮게 유지할 수 있어요.', example_en_4 = 'The economic analysis revealed that the buyer had monopsony power in the region.', example_ko_4 = '경제 분석에서 그 구매자가 그 지역에서 수요 독점 권력을 가지고 있음이 드러났어요.', example_en_5 = 'A monopsony benefits the buyer but harms suppliers through suppressed prices.', example_ko_5 = '수요 독점은 구매자에게 이익이 되지만 억제된 가격으로 공급자에게 해가 돼요.' WHERE id = 'w_economy_C2_05';

UPDATE words SET example_en_2 = 'Rent-seeking by corporations diverts resources from productive investment.', example_ko_2 = '기업들의 지대추구는 자원을 생산적 투자에서 다른 곳으로 돌려요.', example_en_3 = 'Excessive licensing requirements can enable rent-seeking behavior.', example_ko_3 = '과도한 면허 요건은 지대추구 행동을 가능하게 할 수 있어요.', example_en_4 = 'Economists distinguish between value creation and rent-seeking in analyzing markets.', example_ko_4 = '경제학자들은 시장 분석에서 가치 창출과 지대추구를 구분해요.', example_en_5 = 'Strong institutions and rule of law reduce opportunities for rent-seeking.', example_ko_5 = '강한 제도와 법치주의는 지대추구의 기회를 줄여요.' WHERE id = 'w_economy_C2_06';

UPDATE words SET example_en_2 = 'The Keynesian approach emphasizes boosting aggregate demand to cure recessions.', example_ko_2 = '케인즈주의적 접근법은 경기 침체 치료를 위해 총수요 증대를 강조해요.', example_en_3 = 'Critics of Keynesian policy argue that it leads to long-run inflationary pressure.', example_ko_3 = '케인즈주의 정책의 비판론자들은 이것이 장기적인 인플레이션 압력으로 이어진다고 주장해요.', example_en_4 = 'A Keynesian economist would argue that austerity prolongs recessions.', example_ko_4 = '케인즈주의 경제학자는 긴축이 경기 침체를 연장한다고 주장할 거예요.', example_en_5 = 'The fiscal response to the pandemic was distinctly Keynesian in character.', example_ko_5 = '팬데믹에 대한 재정적 대응은 뚜렷하게 케인즈주의적 성격을 띠었어요.' WHERE id = 'w_economy_C2_07';

UPDATE words SET example_en_2 = 'Neoliberal economic reforms were adopted by many countries in the 1980s and 1990s.', example_ko_2 = '신자유주의 경제 개혁은 1980년대와 1990년대에 많은 나라에서 채택됐어요.', example_en_3 = 'The neoliberal consensus has been challenged by rising inequality and populism.', example_ko_3 = '신자유주의 합의는 증가하는 불평등과 포퓰리즘에 의해 도전받아왔어요.', example_en_4 = 'Neoliberal trade agreements opened new markets but also displaced workers.', example_ko_4 = '신자유주의 무역 협정이 새 시장을 열었지만 근로자들을 이동시키기도 했어요.', example_en_5 = 'The neoliberal emphasis on deregulation contributed to financial system fragility.', example_ko_5 = '규제 완화에 대한 신자유주의적 강조가 금융 시스템 취약성에 기여했어요.' WHERE id = 'w_economy_C2_08';

UPDATE words SET example_en_2 = 'She published a heterodox paper arguing that GDP is a poor measure of well-being.', example_ko_2 = '그녀는 GDP가 웰빙의 나쁜 지표라고 주장하는 비주류 논문을 발표했어요.', example_en_3 = 'Heterodox economists often focus on issues of power, institutions, and history.', example_ko_3 = '비주류 경제학자들은 종종 권력, 제도, 역사 문제에 초점을 맞춰요.', example_en_4 = 'His heterodox views on inflation were initially dismissed by mainstream economists.', example_ko_4 = '그의 인플레이션에 대한 비주류적 견해는 처음에 주류 경제학자들에 의해 무시됐어요.', example_en_5 = 'The debate between orthodox and heterodox economics has intensified since 2008.', example_ko_5 = '주류와 비주류 경제학 간의 논쟁은 2008년 이후 심화됐어요.' WHERE id = 'w_economy_C2_09';

UPDATE words SET example_en_2 = 'The model treats the exchange rate as an exogenous variable.', example_ko_2 = '그 모델은 환율을 외생 변수로 취급해요.', example_en_3 = 'Exogenous shocks like natural disasters are difficult to predict or control.', example_ko_3 = '자연재해 같은 외생적 충격은 예측하거나 통제하기 어려워요.', example_en_4 = 'The researchers held all exogenous variables constant to isolate the effect they were studying.', example_ko_4 = '연구자들은 연구하는 효과를 분리하기 위해 모든 외생 변수를 일정하게 유지했어요.', example_en_5 = 'Distinguishing between exogenous and endogenous factors is central to economic modeling.', example_ko_5 = '외생 요인과 내생 요인을 구분하는 것이 경제 모델링의 핵심이에요.' WHERE id = 'w_economy_C2_10';

UPDATE words SET example_en_2 = 'Endogenous growth models suggest that innovation sustains long-run growth.', example_ko_2 = '내생적 성장 모델은 혁신이 장기적 성장을 지속시킨다고 제안해요.', example_en_3 = 'The endogenous growth theory highlights the role of human capital in development.', example_ko_3 = '내생적 성장 이론은 개발에서 인적 자본의 역할을 강조해요.', example_en_4 = 'Policies that foster education and R&D support endogenous growth.', example_ko_4 = '교육과 R&D를 장려하는 정책이 내생적 성장을 지원해요.', example_en_5 = 'Endogenous growth theory departs from earlier models by making technology internally driven.', example_ko_5 = '내생적 성장 이론은 기술을 내부적으로 주도함으로써 이전 모델에서 벗어나요.' WHERE id = 'w_economy_C2_11';

UPDATE words SET example_en_2 = 'Pareto efficiency is a useful benchmark, but it does not guarantee fairness.', example_ko_2 = '파레토 효율성은 유용한 기준이지만 공정성을 보장하지는 않아요.', example_en_3 = 'A tax reform can move an economy closer to Pareto efficiency.', example_ko_3 = '세제 개혁은 경제를 파레토 효율성에 더 가깝게 이동시킬 수 있어요.', example_en_4 = 'Pareto efficiency assumes that any redistribution must make no one worse off.', example_ko_4 = '파레토 효율성은 어떤 재분배도 아무도 불리하게 만들지 않아야 한다고 가정해요.', example_en_5 = 'Markets tend toward Pareto efficiency when there are no externalities or public goods.', example_ko_5 = '외부 효과나 공공재가 없을 때 시장은 파레토 효율성을 향해 가는 경향이 있어요.' WHERE id = 'w_economy_C2_12';

UPDATE words SET example_en_2 = 'The Nash equilibrium in the pricing game led both firms to charge lower prices.', example_ko_2 = '가격 게임에서의 내시 균형은 두 회사 모두 더 낮은 가격을 책정하게 했어요.', example_en_3 = 'Finding the Nash equilibrium requires analyzing each player''s best response strategy.', example_ko_3 = '내시 균형을 찾으려면 각 플레이어의 최적 대응 전략을 분석해야 해요.', example_en_4 = 'In many oligopolistic markets, pricing behavior approximates a Nash equilibrium.', example_ko_4 = '많은 과점 시장에서 가격 행동이 내시 균형에 근접해요.', example_en_5 = 'The Nash equilibrium helped explain how countries get trapped in arms races.', example_ko_5 = '내시 균형은 나라들이 군비 경쟁에 갇히는 이유를 설명하는 데 도움이 됐어요.' WHERE id = 'w_economy_C2_13';

UPDATE words SET example_en_2 = 'Asymmetric information between employers and job seekers affects wage setting.', example_ko_2 = '고용주와 구직자 사이의 정보 비대칭이 임금 설정에 영향을 미쳐요.', example_en_3 = 'Asymmetric information in financial markets can lead to mispricing of assets.', example_ko_3 = '금융 시장에서의 정보 비대칭은 자산의 잘못된 가격 책정으로 이어질 수 있어요.', example_en_4 = 'Reducing asymmetric information improves market efficiency and consumer welfare.', example_ko_4 = '정보 비대칭을 줄이면 시장 효율성과 소비자 복지가 향상돼요.', example_en_5 = 'George Akerlof''s "lemons" paper demonstrated the power of asymmetric information.', example_ko_5 = '조지 아커로프의 "레몬" 논문은 정보 비대칭의 힘을 보여줬어요.' WHERE id = 'w_economy_C2_14';

UPDATE words SET example_en_2 = 'The regulator used moral suasion to encourage banks to hold more capital.', example_ko_2 = '규제 기관은 은행들이 더 많은 자본을 보유하도록 도의적 압박을 사용했어요.', example_en_3 = 'Moral suasion can be effective when institutions value their reputation.', example_ko_3 = '도의적 압박은 기관들이 평판을 중시할 때 효과적일 수 있어요.', example_en_4 = 'Central banks sometimes rely on moral suasion rather than formal regulation.', example_ko_4 = '중앙은행들은 때로 공식 규제 대신 도의적 압박에 의존해요.', example_en_5 = 'Moral suasion alone proved insufficient to prevent reckless lending.', example_ko_5 = '도의적 압박만으로는 무분별한 대출을 막기에 불충분했어요.' WHERE id = 'w_economy_C2_15';

UPDATE words SET example_en_2 = 'Credit default swaps allow investors to buy protection against bond defaults.', example_ko_2 = '신용부도스왑은 투자자들이 채권 디폴트에 대한 보호를 살 수 있게 해요.', example_en_3 = 'The widespread use of credit default swaps made the financial system more fragile.', example_ko_3 = '신용부도스왑의 광범위한 사용이 금융 시스템을 더 취약하게 만들었어요.', example_en_4 = 'The price of credit default swaps rose sharply as the company''s default risk increased.', example_ko_4 = '회사의 디폴트 위험이 높아지면서 신용부도스왑 가격이 급등했어요.', example_en_5 = 'Regulators moved to bring credit default swaps onto regulated exchanges after the crisis.', example_ko_5 = '규제 기관들은 위기 이후 신용부도스왑을 규제 거래소로 가져오기 위해 움직였어요.' WHERE id = 'w_economy_C2_16';

UPDATE words SET example_en_2 = 'Quantitative tightening reduces the money supply and can raise long-term interest rates.', example_ko_2 = '양적 긴축은 통화 공급을 줄이고 장기 금리를 높일 수 있어요.', example_en_3 = 'The Federal Reserve began quantitative tightening to curb inflation.', example_ko_3 = '연방준비제도는 인플레이션을 억제하기 위해 양적 긴축을 시작했어요.', example_en_4 = 'Quantitative tightening is the reverse of the quantitative easing used after the financial crisis.', example_ko_4 = '양적 긴축은 금융 위기 이후 사용된 양적 완화의 반대예요.', example_en_5 = 'The pace of quantitative tightening was carefully calibrated to avoid market disruption.', example_ko_5 = '양적 긴축의 속도는 시장 혼란을 피하기 위해 신중하게 조정됐어요.' WHERE id = 'w_economy_C2_17';

UPDATE words SET example_en_2 = 'Estimates of the fiscal multiplier vary widely depending on economic conditions.', example_ko_2 = '재정 승수의 추정치는 경제 상황에 따라 크게 다양해요.', example_en_3 = 'A fiscal multiplier above one means that stimulus spending expands GDP by more than the initial outlay.', example_ko_3 = '1보다 큰 재정 승수는 부양 지출이 초기 지출보다 더 많이 GDP를 확대한다는 것을 의미해요.', example_en_4 = 'During deep recessions, the fiscal multiplier tends to be higher.', example_ko_4 = '깊은 경기 침체 중에 재정 승수는 더 높은 경향이 있어요.', example_en_5 = 'Calculating the fiscal multiplier accurately requires complex econometric methods.', example_ko_5 = '재정 승수를 정확히 계산하려면 복잡한 계량경제학적 방법이 필요해요.' WHERE id = 'w_economy_C2_18';

UPDATE words SET example_en_2 = 'A Gini coefficient of zero represents perfect equality, while one represents maximum inequality.', example_ko_2 = '지니 계수 0은 완전한 평등을 나타내고, 1은 최대 불평등을 나타내요.', example_en_3 = 'The Gini coefficient has risen in many OECD countries over the past three decades.', example_ko_3 = '지난 30년간 많은 OECD 국가에서 지니 계수가 상승했어요.', example_en_4 = 'Researchers use the Gini coefficient to compare inequality across countries.', example_ko_4 = '연구자들은 국가 간 불평등을 비교하기 위해 지니 계수를 사용해요.', example_en_5 = 'Tax policy changes can have a measurable impact on the Gini coefficient.', example_ko_5 = '세금 정책 변화는 지니 계수에 측정 가능한 영향을 미칠 수 있어요.' WHERE id = 'w_economy_C2_19';

UPDATE words SET example_en_2 = 'The deadweight loss from monopoly pricing reduces total economic welfare.', example_ko_2 = '독점 가격 책정으로 인한 사중 손실은 전체 경제 복지를 감소시켜요.', example_en_3 = 'Any market inefficiency generates a deadweight loss borne by society.', example_ko_3 = '어떤 시장 비효율이든 사회가 부담하는 사중 손실을 발생시켜요.', example_en_4 = 'Economists calculate deadweight loss to measure the cost of market distortions.', example_ko_4 = '경제학자들은 시장 왜곡의 비용을 측정하기 위해 사중 손실을 계산해요.', example_en_5 = 'Even well-intentioned regulations can create deadweight loss if poorly designed.', example_ko_5 = '잘 설계되지 않으면 선의의 규제도 사중 손실을 만들 수 있어요.' WHERE id = 'w_economy_C2_20';

UPDATE words SET example_en_2 = 'Adverse selection in the used car market leads buyers to distrust sellers.', example_ko_2 = '중고차 시장에서의 역선택은 구매자가 판매자를 불신하게 만들어요.', example_en_3 = 'Signaling mechanisms help markets overcome the problem of adverse selection.', example_ko_3 = '신호 메커니즘은 시장이 역선택 문제를 극복하도록 도와요.', example_en_4 = 'Screening is a strategy used by insurers to reduce adverse selection.', example_ko_4 = '심사는 보험사들이 역선택을 줄이기 위해 사용하는 전략이에요.', example_en_5 = 'Adverse selection occurs when higher-risk individuals are more likely to seek insurance.', example_ko_5 = '역선택은 더 높은 위험의 개인들이 보험을 더 많이 찾을 때 발생해요.' WHERE id = 'w_economy_C2_21';

UPDATE words SET example_en_2 = 'Dutch disease caused the manufacturing sector to shrink dramatically after the oil boom.', example_ko_2 = '네덜란드병으로 석유 붐 이후 제조 부문이 크게 축소됐어요.', example_en_3 = 'Norwegian policymakers designed the oil fund to avoid Dutch disease.', example_ko_3 = '노르웨이 정책 입안자들은 네덜란드병을 피하기 위해 석유 기금을 설계했어요.', example_en_4 = 'Dutch disease can occur whenever a resource boom causes currency appreciation.', example_ko_4 = '네덜란드병은 자원 붐이 통화 절상을 유발할 때마다 발생할 수 있어요.', example_en_5 = 'Diversifying the economy is the key remedy for Dutch disease.', example_ko_5 = '경제 다각화가 네덜란드병의 핵심 치료책이에요.' WHERE id = 'w_economy_C2_22';

UPDATE words SET example_en_2 = 'The central bank struggled to escape the liquidity trap despite successive rate cuts.', example_ko_2 = '중앙은행은 거듭된 금리 인하에도 불구하고 유동성 함정에서 벗어나기 위해 고군분투했어요.', example_en_3 = 'In a liquidity trap, even massive money printing fails to raise inflation.', example_ko_3 = '유동성 함정에서는 대규모 화폐 발행도 인플레이션을 높이는 데 실패해요.', example_en_4 = 'Keynes described the liquidity trap as a situation where monetary policy loses its traction.', example_ko_4 = '케인즈는 유동성 함정을 통화 정책이 견인력을 잃는 상황으로 설명했어요.', example_en_5 = 'Some economists argue that quantitative easing can help break a liquidity trap.', example_ko_5 = '일부 경제학자들은 양적 완화가 유동성 함정을 타개하는 데 도움이 될 수 있다고 주장해요.' WHERE id = 'w_economy_C2_23';

UPDATE words SET example_en_2 = 'The principal-agent problem is central to debates about executive pay.', example_ko_2 = '주인-대리인 문제는 임원 보수에 대한 논쟁의 핵심이에요.', example_en_3 = 'Incentive pay is one way to align the interests of principals and agents.', example_ko_3 = '성과 기반 보수는 주인과 대리인의 이익을 일치시키는 방법 중 하나예요.', example_en_4 = 'The principal-agent problem explains why managers may not always act in shareholders'' interests.', example_ko_4 = '주인-대리인 문제는 관리자들이 항상 주주의 이익을 위해 행동하지 않는 이유를 설명해요.', example_en_5 = 'Strong governance structures help mitigate the principal-agent problem in public companies.', example_ko_5 = '강력한 지배구조가 공개 기업에서 주인-대리인 문제를 완화하는 데 도움이 돼요.' WHERE id = 'w_economy_C2_24';

UPDATE words SET example_en_2 = 'The velocity of money declined during the financial crisis as lending froze.', example_ko_2 = '대출이 동결되면서 금융 위기 중에 화폐 유통 속도가 하락했어요.', example_en_3 = 'An increase in the velocity of money can fuel inflation even without additional money creation.', example_ko_3 = '추가 화폐 창출 없이도 화폐 유통 속도의 증가가 인플레이션을 부추길 수 있어요.', example_en_4 = 'Tracking the velocity of money helps economists understand spending and saving behavior.', example_ko_4 = '화폐 유통 속도를 추적하면 경제학자들이 지출 및 저축 행동을 이해하는 데 도움이 돼요.', example_en_5 = 'The quantity theory of money links price levels to the velocity of money and money supply.', example_ko_5 = '화폐수량설은 물가 수준을 화폐 유통 속도와 통화량과 연결시켜요.' WHERE id = 'w_economy_C2_25';

UPDATE words SET example_en_2 = 'Crowdfunding democratizes access to capital for small entrepreneurs.', example_ko_2 = '크라우드펀딩은 소규모 창업가들의 자본 접근을 민주화해요.', example_en_3 = 'She used crowdfunding to launch her independent film project.', example_ko_3 = '그녀는 독립 영화 프로젝트를 시작하기 위해 크라우드펀딩을 사용했어요.', example_en_4 = 'Reward-based crowdfunding is different from equity crowdfunding.', example_ko_4 = '보상 기반 크라우드펀딩은 지분 기반 크라우드펀딩과 달라요.', example_en_5 = 'Crowdfunding platforms take a percentage fee from the total amount raised.', example_ko_5 = '크라우드펀딩 플랫폼은 조달된 총액에서 일정 비율의 수수료를 가져가요.' WHERE id = 'w_economy_C2_26';

UPDATE words SET example_en_2 = 'Shadow banking activities are not subject to the same oversight as traditional banking.', example_ko_2 = '그림자 금융 활동은 전통 은행과 같은 감독을 받지 않아요.', example_en_3 = 'The shadow banking sector played a major role in the 2008 financial crisis.', example_ko_3 = '그림자 금융 부문이 2008년 금융 위기에서 큰 역할을 했어요.', example_en_4 = 'Regulators have struggled to keep pace with innovation in the shadow banking sector.', example_ko_4 = '규제 기관들은 그림자 금융 부문의 혁신을 따라잡기 위해 애써왔어요.', example_en_5 = 'Money market funds are one example of shadow banking institutions.', example_ko_5 = '머니마켓 펀드는 그림자 금융 기관의 한 예예요.' WHERE id = 'w_economy_C2_27';

UPDATE words SET example_en_2 = 'Behavioral economics has challenged the traditional assumption that people are always rational.', example_ko_2 = '행동경제학은 사람들이 항상 합리적이라는 전통적 가정에 도전해왔어요.', example_en_3 = 'Governments use insights from behavioral economics to design better public policies.', example_ko_3 = '정부들은 더 나은 공공 정책을 설계하기 위해 행동경제학의 통찰을 사용해요.', example_en_4 = 'Loss aversion is a key concept in behavioral economics.', example_ko_4 = '손실 회피는 행동경제학의 핵심 개념이에요.', example_en_5 = 'Behavioral economics shows that small nudges can significantly change people''s financial choices.', example_ko_5 = '행동경제학은 작은 넛지가 사람들의 금융 선택을 크게 바꿀 수 있다는 것을 보여줘요.' WHERE id = 'w_economy_C2_28';

UPDATE words SET example_en_2 = 'The concept of helicopter money was proposed by Milton Friedman in the 1960s.', example_ko_2 = '헬리콥터 머니 개념은 1960년대 밀턴 프리드만이 제안했어요.', example_en_3 = 'Unlike quantitative easing, helicopter money goes directly to consumers.', example_ko_3 = '양적 완화와 달리 헬리콥터 머니는 소비자에게 직접 가요.', example_en_4 = 'Helicopter money could theoretically stimulate demand when interest rates are at zero.', example_ko_4 = '헬리콥터 머니는 이론적으로 금리가 제로일 때 수요를 자극할 수 있어요.', example_en_5 = 'Critics warn that helicopter money could trigger hyperinflation if used carelessly.', example_ko_5 = '비평가들은 헬리콥터 머니를 부주의하게 사용하면 초인플레이션을 촉발할 수 있다고 경고해요.' WHERE id = 'w_economy_C2_29';

UPDATE words SET example_en_2 = 'The seigniorage from the reserve currency provides the issuing country with a unique advantage.', example_ko_2 = '기축통화의 화폐발행이익은 발행국에 독특한 이점을 제공해요.', example_en_3 = 'Historically, seigniorage was a significant source of government revenue.', example_ko_3 = '역사적으로 화폐발행이익은 중요한 정부 수입원이었어요.', example_en_4 = 'Digital currencies may reduce seigniorage revenue for central banks.', example_ko_4 = '디지털 통화가 중앙은행의 화폐발행이익 수입을 줄일 수 있어요.', example_en_5 = 'The inflation that results from overprinting money is sometimes called an inflation tax on seigniorage.', example_ko_5 = '지나친 화폐 발행으로 인한 인플레이션은 때로 화폐발행이익에 대한 인플레이션 세금이라고 불려요.' WHERE id = 'w_economy_C2_30';

UPDATE words SET example_en_2 = 'Friedrich Hayek was one of the most influential thinkers of the Austrian school.', example_ko_2 = '프리드리히 하이에크는 오스트리아 학파에서 가장 영향력 있는 사상가 중 한 명이었어요.', example_en_3 = 'The Austrian school argues that central planning cannot efficiently allocate resources.', example_ko_3 = '오스트리아 학파는 중앙 계획이 자원을 효율적으로 배분할 수 없다고 주장해요.', example_en_4 = 'The Austrian school predicted that credit expansion would inevitably cause boom-bust cycles.', example_ko_4 = '오스트리아 학파는 신용 확장이 필연적으로 호황-침체 순환을 유발한다고 예측했어요.', example_en_5 = 'The Austrian school''s emphasis on entrepreneurship has influenced modern economic thought.', example_ko_5 = '기업가 정신에 대한 오스트리아 학파의 강조는 현대 경제 사상에 영향을 미쳤어요.' WHERE id = 'w_economy_C2_31';

UPDATE words SET example_en_2 = 'Modern monetary theory argues that currency-issuing governments cannot go bankrupt.', example_ko_2 = '현대화폐이론은 통화 발행 정부는 파산할 수 없다고 주장해요.', example_en_3 = 'Critics of modern monetary theory warn it could lead to runaway inflation.', example_ko_3 = '현대화폐이론의 비판론자들은 이것이 통제 불능의 인플레이션으로 이어질 수 있다고 경고해요.', example_en_4 = 'Modern monetary theory has gained attention as an alternative framework for fiscal policy.', example_ko_4 = '현대화폐이론은 재정 정책의 대안적 틀로 주목을 받아왔어요.', example_en_5 = 'The pandemic revived interest in modern monetary theory as governments spent heavily.', example_ko_5 = '정부들이 많은 지출을 하면서 팬데믹이 현대화폐이론에 대한 관심을 부활시켰어요.' WHERE id = 'w_economy_C2_32';

UPDATE words SET example_en_2 = 'The evidence for trickle-down economics benefiting the poor is disputed.', example_ko_2 = '낙수 경제학이 빈곤층에게 혜택을 준다는 증거는 논란의 여지가 있어요.', example_en_3 = 'Trickle-down economics was a central justification for Reagan-era tax cuts.', example_ko_3 = '낙수 경제학은 레이건 시대 세금 감면의 핵심 정당화 논거였어요.', example_en_4 = 'Critics say trickle-down economics has failed to deliver broad prosperity.', example_ko_4 = '비평가들은 낙수 경제학이 광범위한 번영을 제공하는 데 실패했다고 말해요.', example_en_5 = 'The debate over trickle-down economics reflects deeper disagreements about how wealth is created.', example_ko_5 = '낙수 경제학에 대한 논쟁은 富가 어떻게 창출되는지에 대한 더 깊은 불일치를 반영해요.' WHERE id = 'w_economy_C2_33';

UPDATE words SET example_en_2 = 'Information asymmetry between lenders and borrowers leads to credit rationing.', example_ko_2 = '대출자와 차용자 사이의 정보 비대칭은 신용 배급으로 이어져요.', example_en_3 = 'Transparency requirements are designed to reduce information asymmetry in capital markets.', example_ko_3 = '투명성 요건은 자본 시장에서 정보 비대칭을 줄이기 위해 설계됐어요.', example_en_4 = 'Information asymmetry is a key reason why financial markets require regulation.', example_ko_4 = '정보 비대칭은 금융 시장에 규제가 필요한 핵심 이유예요.', example_en_5 = 'Credit ratings help reduce information asymmetry between bond issuers and investors.', example_ko_5 = '신용 등급은 채권 발행자와 투자자 사이의 정보 비대칭을 줄이는 데 도움이 돼요.' WHERE id = 'w_economy_C2_34';

UPDATE words SET example_en_2 = 'The theory of general equilibrium shows how prices in all markets adjust simultaneously.', example_ko_2 = '일반 균형 이론은 모든 시장의 가격이 어떻게 동시에 조정되는지 보여줘요.', example_en_3 = 'Computational methods are needed to solve real-world general equilibrium models.', example_ko_3 = '실제 세계의 일반 균형 모델을 풀기 위해 컴퓨팅 방법이 필요해요.', example_en_4 = 'General equilibrium models are used to evaluate the economy-wide effects of tax reform.', example_ko_4 = '일반 균형 모델은 세제 개혁의 경제 전반적 효과를 평가하기 위해 사용돼요.', example_en_5 = 'Arrow and Debreu proved the existence of general equilibrium under certain conditions.', example_ko_5 = '애로와 드브루는 특정 조건 하에서 일반 균형의 존재를 증명했어요.' WHERE id = 'w_economy_C2_35';


